#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply d_cry effect from previous children who left
            children[j].p -= total_d_cry_effect;

            // Apply v_cry effect from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        if (diff == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = 0;
        count += diff / 5;
        diff %= 5;

        if (diff == 1 || diff == 2) {
            count += 1;
        } else if (diff == 3 || diff == 4) {
            count += 2;
        }
        // If diff is 0, nothing is added.

        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s2s1. We need s2s1 to be a palindrome and s2s1 != s.
    for (int i = 1; i < n; ++i) { // Cut after i characters
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_new = s2 + s1;
        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 is not possible, we check k=2.
    // With k=2, we can always make a new palindrome if not all characters are the same.
    // For example, cut s into s[0], s[1...n-2], s[n-1].
    // Rearrange to s[n-1], s[1...n-2], s[0].
    // Since s is a palindrome, s[0] == s[n-1].
    // The new string is s[n-1] + s[1...n-2] + s[0].
    // This is a palindrome because s[n-1] == s[0] and s[1...n-2] is a palindrome
    // (as it's the inner part of the original palindrome s).
    // The new string is s[n-1] + s.substr(1, n-2) + s[0].
    // The original string is s[0] + s.substr(1, n-2) + s[n-1].
    // These two strings are identical. This specific rearrangement doesn't work.

    // Consider cutting s into s[0...i-1], s[i...j-1], s[j...n-1].
    // We can rearrange them.
    // A simpler approach for k=2:
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement
    // of pieces will result in the same string "aaaa". In this case, it's impossible.
    // We can check this by counting distinct characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 must be possible.
    // Why? Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Example: "nolon". k=1 doesn't work.
    // "nolon" -> "no" | "l" | "on"
    // Rearrange to "on" | "l" | "no" -> "onlno". This is a palindrome and != "nolon".
    // This uses 2 cuts.
    //
    // Consider any palindrome s that is not all same characters.
    // If n is odd, s = c_0 c_1 ... c_{n/2-1} c_{n/2} c_{n/2-1} ... c_1 c_0
    // If n is even, s = c_0 c_1 ... c_{n/2-1} c_{n/2-1} ... c_1 c_0
    //
    // If k=1 doesn't work, it means for any split s = s1s2, s2s1 is either not a palindrome or s2s1 == s.
    //
    // If s is not all same characters, then there exists at least one character s[i] != s[0].
    // Since s is a palindrome, s[i] == s[n-1-i].
    //
    // Consider the string s. If we remove the first character s[0] and the last character s[n-1],
    // we get s.substr(1, n-2). This substring is also a palindrome.
    // If s.substr(1, n-2) is not all same characters, then we can apply the k=1 logic to it.
    // Let s' = s.substr(1, n-2). If s' is not all same characters, then we can find a cut in s'
    // such that s'_new != s' and is a palindrome.
    // Then we can form s[0] + s'_new + s[n-1]. This will be a palindrome and different from s.
    // This would require 2 cuts: one to separate s[0], one to separate s[n-1], and then cuts within s'.
    // This is getting complicated.

    // The problem statement guarantees that s is a palindrome.
    // If all characters are the same, "Impossible".
    // Otherwise, if k=1 doesn't work, then k=2 must be the answer.
    // This is because we can always find a way to make 2 cuts to form a new palindrome.
    // Example: s = "abacaba". k=1 doesn't work.
    // Cut into "a" | "bacab" | "a". Rearrange to "a" | "bacab" | "a". This is the same.
    //
    // Consider "nolon". n=5.
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'.
    // s.substr(0,1) = "n", s.substr(1,3) = "olo", s.substr(4,1) = "n".
    // Pieces: "n", "olo", "n".
    // Rearrange: "n" + "olo" + "n" -> "nolon" (original)
    //
    // The example "nolon" -> 2.
    // Cuts: no|l|on. Pieces: "no", "l", "on".
    // Rearrange: "on" + "l" + "no" -> "onlno". This is a palindrome and != "nolon".
    // This uses 2 cuts.
    //
    // The logic is:
    // 1. If all characters are the same, it's impossible.
    // 2. Otherwise, try k=1. If successful, print 1.
    // 3. If k=1 is not successful, but not all characters are the same, then k=2 must be possible.
    //    The only case where k=1 fails is if for every split s1|s2, s2s1 is either not a palindrome
    //    or s2s1 == s.
    //    If s is a palindrome and not all characters are the same, then s.substr(0, n/2) is not a palindrome.
    //    Consider s = "abacaba". n=7.
    //    s.substr(0,1) = "a", s.substr(1,6) = "bacaba". s_new = "bacabaa". Not palindrome.
    //    s.substr(0,2) = "ab", s.substr(2,5) = "acaba". s_new = "acabaab". Not palindrome.
    //    s.substr(0,3) = "aba", s.substr(3,4) = "caba". s_new = "cabaaba". Palindrome, but == "abacaba".
    //    This is the middle cut.
    //    For "abacaba", k=1 fails.
    //    But "abacaba" is not all same characters. So k=2 should be the answer.
    //    Example: "a" | "b" | "acaba". Rearrange "b" | "a" | "acaba" -> "baacaba". Not palindrome.
    //    Example: "a" | "baca" | "ba". Rearrange "ba" | "a" | "baca" -> "baabaca". Not palindrome.
    //
    // The problem statement for k=2: "nolon" -> 2.
    // "no" | "l" | "on". Pieces: "no", "l", "on". Rearrange: "on" + "l" + "no" = "onlno".
    // This is a palindrome and different from "nolon".
    // This is a specific type of cut: s[0...i-1] | s[i...j-1] | s[j...n-1].
    // The pieces are P1, P2, P3.
    // We can rearrange them to P3 P2 P1.
    // For this to be a palindrome, P3 P2 P1 must be a palindrome.
    // And P3 P2 P1 != P1 P2 P3 (original s).
    //
    // If s is a palindrome, and not all characters are the same, then it's always possible to achieve k=2.
    // The only case where k=1 fails is if s is of the form X Y X, where X is a palindrome, Y is a palindrome,
    // and X Y X is a palindrome, and swapping X and X gives X Y X.
    // This means X Y X is symmetric around the middle.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // The "Impossible" case is only when all characters are the same.
    // So, if k=1 fails and not all characters are the same, output 2.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Option 1: All elements in one subsequence (e.g., subsequence 1)
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Option 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a_1 + a_2.
    // The maximum possible f value is max(a_{n-1} + a_n, a_1 + a_n + h).
    // This is because a_1 and a_n must be in different subsequences to achieve a_1 + a_n + h.
    // If a_1 and a_n are in different subsequences, then a_1 + a_n + h is a possible f value.
    // The other values are a_i + a_j or a_i + a_j + h.
    // The smallest possible sum is a_1 + a_2.
    // The largest possible sum is a_{n-1} + a_n (if a_{n-1}, a_n are in same group)
    // or a_1 + a_n + h (if a_1, a_n are in different groups).
    //
    // Consider the partition where a_1 is in group 1, and all other elements are in group 2.
    // min_f = a_1 + a_2 + h (a_1 in group 1, a_2 in group 2)
    // max_f = a_{n-1} + a_n (a_{n-1}, a_n in group 2)
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2 + h)
    //
    // This is not quite right. The minimum f value could be a_2 + a_3 if a_2, a_3 are in group 2.
    // The minimum f value could be a_1 + a_k + h for some k.
    //
    // Let's consider the specific partition strategy:
    // Put a_1 into group 1.
    // Put a_2, ..., a_n into group 2.
    //
    // Values of f:
    // 1. a_i + a_j for i, j in {2, ..., n}: min is a_2 + a_3, max is a_{n-1} + a_n.
    // 2. a_1 + a_j + h for j in {2, ..., n}: min is a_1 + a_2 + h, max is a_1 + a_n + h.
    //
    // Overall min_f = min(a_2 + a_3, a_1 + a_2 + h)
    // Overall max_f = max(a_{n-1} + a_n, a_1 + a_n + h)
    //
    // This strategy is only optimal if h is large enough to separate the ranges.
    //
    // The key insight is that the minimum possible value of f is always a_1 + a_2.
    // This is because if a_1 and a_2 are in the same group, f(a_1, a_2) = a_1 + a_2.
    // If a_1 and a_2 are in different groups, f(a_1, a_2) = a_1 + a_2 + h.
    // So, if we want to minimize min_f, we must put a_1 and a_2 in the same group.
    //
    // If a_1 and a_2 are in the same group, then min_f = a_1 + a_2.
    //
    // Now we need to minimize max_f.
    // The possible values for max_f are:
    // 1. a_{n-1} + a_n (if a_{n-1} and a_n are in the same group)
    // 2. a_i + a_j + h (if a_i and a_j are in different groups). The maximum of these is a_1 + a_n + h.
    //
    // So, if a_1 and a_2 are in the same group, min_f = a_1 + a_2.
    // We need to choose a partition such that max_f is minimized.
    // The candidates for max_f are a_{n-1} + a_n and a_1 + a_n + h.
    //
    // Consider two main strategies for partitioning:
    // Strategy A: All elements in one group.
    //   min_f = a_1 + a_2
    //   max_f = a_{n-1} + a_n
    //   goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    //
    // Strategy B: a_1 in group 1, a_2, ..., a_n in group 2.
    //   min_f = a_1 + a_2 + h (from a_1 and a_2)
    //   max_f = a_{n-1} + a_n (from a_{n-1} and a_n)
    //   goodness = (a_{n-1} + a_n) - (a_1 + a_2 + h)
    // This is only valid if n >= 3. If n=2, this partition is not possible.
    // If n=2, a_1 in group 1, a_2 in group 2. f(a_1, a_2) = a_1 + a_2 + h. min_f = max_f = a_1 + a_2 + h. Goodness = 0.
    //
    // Let's re-evaluate the minimum and maximum f values for a general partition.
    // Let S1 be the set of elements in subsequence 1, S2 in subsequence 2.
    // min_f = min( min_{x,y in S1, x!=y} (x+y), min_{x,y in S2, x!=y} (x+y), min_{x in S1, y in S2} (x+y+h) )
    // max_f = max( max_{x,y in S1, x!=y} (x+y), max_{x,y in S2, x!=y} (x+y), max_{x in S1, y in S2} (x+y+h) )
    //
    // The smallest possible sum of two elements is elements[0].value + elements[1].value.
    // The largest possible sum of two elements is elements[n-1].value + elements[n-2].value.
    //
    // The smallest possible sum of two elements from different groups is elements[0].value + elements[1].value + h.
    // The largest possible sum of two elements from different groups is elements[0].value + elements[n-1].value + h.
    //
    // Case 1: All elements in one group (e.g., group 1).
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    // This is `goodness1`.

    // Case 2: At least one element in each group.
    // To minimize goodness, we want to make min_f as large as possible and max_f as small as possible.
    //
    // Consider the partition where elements[0] is in group 1, and all other elements are in group 2.
    // (This is the partition used in the example for large h).
    // If n=2: elements[0] in group 1, elements[1] in group 2.
    //   min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // If n >= 3:
    //   Elements in group 1: {elements[0]}
    //   Elements in group 2: {elements[1], ..., elements[n-1]}
    //   Possible f values:
    //     - From group 2: elements[i].value + elements[j].value for i,j in [1, n-1].
    //       Min: elements[1].value + elements[2].value. Max: elements[n-1].value + elements[n-2].value.
    //     - From different groups: elements[0].value + elements[j].value + h for j in [1, n-1].
    //       Min: elements[0].value + elements[1].value + h. Max: elements[0].value + elements[n-1].value + h.
    //   Overall min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //   Overall max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //   goodness = max_f - min_f.
    //
    // This partition strategy (elements[0] in group 1, rest in group 2) is a strong candidate.
    // Let's call this `goodness2`.
    long long goodness2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (n == 2) {
        goodness2 = 0; // Only one pair (a_0, a_1), they must be in different groups. f = a_0 + a_1 + h. min_f = max_f.
    } else {
        long long min_f_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long max_f_val = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
        goodness2 = max_f_val - min_f_val;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as many times as possible without exceeding k.
        // The number of times is (k - a[i]) / min_val.
        // Integer division automatically handles the floor.
        operations += (k - a[i]) / min_val;
    }

    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

