#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // For any permutation p, its reverse p_rev has the same set of adjacent sums.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // F(p_rev) = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // These two sets of sums are identical, just in reverse order, so their sorted versions are the same.
    // The reverse permutation p_rev is different from p unless p is a palindrome.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For n=2, p=[1,2], p_rev=[2,1]. They are different.
    // For n > 2, it's possible for p to be a palindrome, e.g., [1,2,1] is not a permutation.
    // A permutation cannot be a palindrome if n > 1.
    // If p_i = p_{n-1-i} for all i, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements in a permutation must be distinct, this implies that if p_1 = p_n, then n must be 1.
    // But n >= 2. So p_1 != p_n.
    // Therefore, p is never equal to its reverse p_rev for n >= 2.
    // So, reversing the given permutation always yields a different permutation with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

