}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long first_p_to_cover = p[p_idx];

        // If the current head cannot reach the first uncovered track, it cannot cover it.
        // This head must be used for tracks to its right or stay.
        // If current_h is too far right, it can't cover first_p_to_cover.
        // If current_h is too far left, it can't cover first_p_to_cover.
        // The condition is abs(current_h - first_p_to_cover) <= T.
        // If current_h + T < first_p_to_cover, this head cannot reach first_p_to_cover.
        // In this case, we need another head for first_p_to_cover.
        // So, this head must cover tracks starting from first_p_to_cover.
        // The range this head can cover is [current_h - T, current_h + T].
        // If first_p_to_cover is outside this range, this head cannot cover it.
        // Specifically, if first_p_to_cover > current_h + T, this head cannot cover it.
        // If first_p_to_cover < current_h - T, this head cannot cover it.
        // The problem states h_i and p_i are sorted.
        // We are trying to cover p[p_idx] with h[h_idx].
        // If h[h_idx] is too far to the right of p[p_idx], i.e., h[h_idx] - T > p[p_idx],
        // then h[h_idx] cannot cover p[p_idx]. We need to use a previous head or this head is useless for p[p_idx].
        // But we process heads from left to right, so previous heads are already assigned.
        // So if h[h_idx] - T > p[p_idx], this h[h_idx] cannot cover p[p_idx].
        // This means we must use h[h_idx] to cover tracks to its right, or it's not useful for p[p_idx].
        // This is not quite right. The greedy strategy is:
        // For the current head h[h_idx], find the rightmost track it can cover.
        // If h[h_idx] can cover p[p_idx], then it can cover a range of tracks.
        // We want to maximize the rightmost track covered by h[h_idx] to minimize the number of heads.

        // Option 1: Head moves left to cover p[p_idx] and then covers tracks to its right.
        // The leftmost point it can reach is current_h - T.
        // If p[p_idx] is to the left of current_h - T, this head cannot cover p[p_idx] by moving left.
        // So, if p[p_idx] < current_h - T, this head cannot cover p[p_idx].
        // In this case, we must use a head to the left of current_h, which is not possible as we iterate h_idx.
        // So, if p[p_idx] < current_h - T, this head cannot cover p[p_idx], and no subsequent head can either.
        // This means it's impossible.
        // However, this is not true. A head can cover a range.
        // If p[p_idx] is to the left of current_h - T, then this head cannot cover p[p_idx].
        // But this head might be able to cover some p_k where p_k > p[p_idx].
        // This is why the greedy strategy is tricky.

        // Let's re-evaluate the greedy strategy for `check(T)`:
        // We iterate through heads `h_idx` from left to right.
        // For each head `h[h_idx]`, we try to cover the current `p[p_idx]`.
        // If `h[h_idx]` cannot cover `p[p_idx]` (i.e., `p[p_idx] > h[h_idx] + T`), then this head is too far left.
        // We need to use a head to the right of `h[h_idx]` to cover `p[p_idx]`.
        // This means `h[h_idx]` is useless for `p[p_idx]` and any `p_k` to its right.
        // This is incorrect. `h[h_idx]` can move right.

        // Correct greedy strategy for `check(T)`:
        // We have `n` heads and `m` target tracks.
        // We want to cover all `p_j` using `n` heads, each moving at most `T` distance.
        // Iterate through heads `h_idx` from `0` to `n-1`.
        // For each head `h[h_idx]`:
        //   Find the first track `p[p_idx]` that is not yet covered.
        //   If `p[p_idx]` is too far to the left for `h[h_idx]` to reach (i.e., `p[p_idx] < h[h_idx] - T`),
        //   then `h[h_idx]` cannot cover `p[p_idx]`.
        //   Since `p` is sorted, `p[p_idx]` is the leftmost uncovered track.
        //   If `h[h_idx]` cannot cover `p[p_idx]` by moving left, it cannot cover it by moving right either.
        //   This means `h[h_idx]` cannot cover `p[p_idx]`.
        //   This also means `h[h_idx]` cannot cover any `p_k` where `p_k < p[p_idx]`.
        //   So, if `p[p_idx] < h[h_idx] - T`, then `h[h_idx]` is too far right to cover `p[p_idx]`.
        //   This implies that `p[p_idx]` must have been covered by a previous head.
        //   But we are at `p[p_idx]`, meaning it's not covered.
        //   So, if `p[p_idx] < h[h_idx] - T`, it's impossible to cover `p[p_idx]` with `h[h_idx]` or any subsequent head.
        //   Thus, `check(T)` should return `false`.

        //   If `h[h_idx]` *can* cover `p[p_idx]` (i.e., `p[p_idx] >= h[h_idx] - T` and `p[p_idx] <= h[h_idx] + T`):
        //     Then `h[h_idx]` can cover `p[p_idx]`.
        //     We want to maximize the rightmost track covered by `h[h_idx]` to cover as many tracks as possible.
        //     The head `h[h_idx]` can cover any track `x` such that `abs(h[h_idx] - x) <= T`.
        //     This means `x` is in `[h[h_idx] - T, h[h_idx] + T]`.
        //     However, if `h[h_idx]` moves to `x`, it can cover the range `[min(h[h_idx], x), max(h[h_idx], x)]`.
        //     The total range covered by `h[h_idx]` is `[h[h_idx] - T, h[h_idx] + T]`.
        //     So, `h[h_idx]` can cover all `p_k` such that `p_k` is in `[h[h_idx] - T, h[h_idx] + T]`.
        //     We need to find the rightmost `p_k` that `h[h_idx]` can cover.
        //     This is `p_k` such that `p_k <= h[h_idx] + T`.
        //     We advance `p_idx` as long as `p[p_idx] <= h[h_idx] + T`.

        // Let's refine the greedy strategy:
        // `p_idx` points to the first *uncovered* track.
        // For each head `h[h_idx]`:
        //   If `p_idx == m`, all tracks are covered, return true.
        //   Calculate the effective range this head can cover: `[h[h_idx] - T, h[h_idx] + T]`.
        //   If `p[p_idx]` (the current leftmost uncovered track) is to the left of this head's range,
        //   i.e., `p[p_idx] < h[h_idx] - T`, then this head cannot cover `p[p_idx]`.
        //   Since `p` is sorted, no subsequent head `h[h_idx+k]` (which is even further right) can cover `p[p_idx]` either.
        //   This means `p[p_idx]` cannot be covered. So, return `false`.

        //   If `p[p_idx]` is within or to the right of `h[h_idx] - T`, then `h[h_idx]` can potentially cover `p[p_idx]`.
        //   The head `h[h_idx]` can cover all tracks `p_k` such that `p_k` is in `[p[p_idx], h[h_idx] + T]`.
        //   We advance `p_idx` to the first track that is *not* covered by `h[h_idx]`.
        //   This means we advance `p_idx` as long as `p[p_idx] <= h[h_idx] + T`.
        //   After this loop, `p_idx` will point to the first track that `h[h_idx]` cannot cover.
        //   This is the new `p[p_idx]` for the next head.

        // Example: h = [2, 5, 6], p = [1, 3, 6, 8], T = 2
        // h_idx = 0, h[0] = 2. p_idx = 0, p[0] = 1.
        // Range for h[0]: [2-2, 2+2] = [0, 4].
        // p[0]=1 is in [0, 4].
        // Advance p_idx:
        // p[0]=1 <= 4. p_idx becomes 1.
        // p[1]=3 <= 4. p_idx becomes 2.
        // p[2]=6 > 4. Stop.
        // Now p_idx = 2. (Tracks 1, 3 covered by h[0])

        // h_idx = 1, h[1] = 5. p_idx = 2, p[2] = 6.
        // Range for h[1]: [5-2, 5+2] = [3, 7].
        // p[2]=6 is in [3, 7].
        // Advance p_idx:
        // p[2]=6 <= 7. p_idx becomes 3.
        // p[3]=8 > 7. Stop.
        // Now p_idx = 3. (Track 6 covered by h[1])

        // h_idx = 2, h[2] = 6. p_idx = 3, p[3] = 8.
        // Range for h[2]: [6-2, 6+2] = [4, 8].
        // p[3]=8 is in [4, 8].
        // Advance p_idx:
        // p[3]=8 <= 8. p_idx becomes 4.
        // Now p_idx = 4. (Track 8 covered by h[2])

        // p_idx = 4 == m. All tracks covered. Return true.

        // This greedy strategy seems correct.
        // For each head, we find the leftmost uncovered track `p[p_idx]`.
        // If `p[p_idx]` is to the left of `h[h_idx] - T`, then `h[h_idx]` cannot cover `p[p_idx]`.
        // Since `h` is sorted, `h[h_idx]` is the leftmost available head that could potentially cover `p[p_idx]`.
        // If `h[h_idx]` cannot cover `p[p_idx]` by moving left, no `h[h_idx+k]` can either.
        // So, `p[p_idx]` cannot be covered. Return `false`.
        // Otherwise, `h[h_idx]` can cover `p[p_idx]`.
        // We then greedily cover as many tracks to the right as possible with `h[h_idx]`.
        // This means `h[h_idx]` covers all `p_k` such that `p_k <= h[h_idx] + T`.
        // We advance `p_idx` past all such `p_k`.

        long long head_left_reach = current_h - T;
        long long head_right_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx] by moving left,
        // i.e., p[p_idx] is to the left of head_left_reach, then it's impossible.
        // This is because p[p_idx] is the leftmost uncovered track.
        // If h[h_idx] cannot cover it, no h[h_idx+k] (which are further right) can cover it either.
        // This condition is `p[p_idx] < head_left_reach`.
        // However, this is not quite right. The head can move to any point in [h_i-T, h_i+T].
        // If it moves to `x`, it covers `x`.
        // The problem is that if `p[p_idx]` is far to the left of `h[h_idx]`, say `h[h_idx] - T > p[p_idx]`,
        // then `h[h_idx]` cannot cover `p[p_idx]`.
        // This means `p[p_idx]` must have been covered by a previous head.
        // But `p[p_idx]` is the first *uncovered* track.
        // So, if `h[h_idx] - T > p[p_idx]`, it's impossible.
        // This is the correct condition for returning false.

        if (current_h - T > p[p_idx]) {
            return false;
        }

        // If we reach here, it means `current_h - T <= p[p_idx]`.
        // So, `h[h_idx]` can reach `p[p_idx]` by moving left or staying.
        // Now, we want to cover as many tracks as possible to the right.
        // The rightmost track `h[h_idx]` can cover is `current_h + T`.
        // So, we advance `p_idx` as long as `p[p_idx]` is within this range.
        while (p_idx < m && p[p_idx] <= current_h + T) {
            p_idx++;
        }
    }
    return p_idx == m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2*10^10.
                               // Or simply max(p_m - h_1, h_n - p_1)
                               // Max p_i is 10^10, min p_i is 1. Max h_i is 10^10, min h_i is 1.
                               // Max diff is 10^10 - 1. So 10^10 is a safe upper bound.
                               // 2e10 + 7 is a very safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

