    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] = k < n, then there is some p[j] = n.
        // In that case, a[i][j] = min(p[i], p[j]) = min(k, n) = k.
        // So max_val_in_row will be k.
        // If p[i] = n, then for all j != i, a[i][j] = min(n, p[j]) = p[j].
        // The maximum of these p[j] values (for j != i) will be n-1.
        // So if max_val_in_row is n-1, p[i] must be n.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

