int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate differences up to k

    // Generate k distinct differences: 1, 2, ..., k
    // We use numbers from 1 to k+1 to achieve this.
    // The pattern is: 1, k+1, 2, k, 3, k-1, ...
    // This generates differences: k, k-1, k-2, ..., 1
    // For example, if k=4, numbers are 1,2,3,4,5.
    // Sequence: 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This generates all differences from 1 to k.

    int current_idx = 0;
    bool use_left = true;
    while (left <= right) {
        if (use_left) {
            p[current_idx++] = left++;
        } else {
            p[current_idx++] = right--;
        }
        use_left = !use_left;
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // We append them in increasing order to ensure the differences are 1.
    // This does not introduce new distinct differences if k >= 1.
    // If k=1, the first part is 1, 2. Differences: |1-2|=1.
    // Then append 3, 4, ..., n. Differences: |2-3|=1, |3-4|=1, etc.
    // The set of differences remains {1}.
    for (int i = k + 2; i <= n; ++i) {
        p[current_idx++] = i;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the suffix that is already sorted.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[i...j] is non-increasing.
    // This is the suffix that is non-increasing, after the non-decreasing part.
    // The elements a[j...n-1] are non-decreasing.
    // The elements a[i...j] are non-increasing.
    // The elements a[0...i-1] are the prefix to be removed.
    // We need to find the smallest `i` such that a[i...n-1] can be made good.
    // The current `i` is the start of the non-decreasing suffix.
    // We need to find the start of the non-increasing part that precedes it.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing, and a[i...n-1] is non-decreasing.
    // The elements a[j...n-1] form the candidate "good" suffix.
    // The length of the prefix to remove is `j`.

    std::cout << j << std::endl;
}

