int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i times the area of one piece.
        // Total area = (1/2) * base * h = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n.
        // Area from apex to x_i = i * (h/2) / n = (i * h) / (2 * n).
        //
        // For a triangle with height x_i, its base b_i is related by similar triangles:
        // b_i / 1 = x_i / h  =>  b_i = x_i / h.
        // Area from apex to x_i = (1/2) * b_i * x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2 * h).
        //
        // Equating the two expressions for the area from apex to x_i:
        // x_i^2 / (2 * h) = (i * h) / (2 * n)
        // x_i^2 = (i * h^2) / n
        // x_i = sqrt((i * h^2) / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

