int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for the elements we are trying to "beat" (from sorted original array)
    int right_ptr = 0; // Pointer for the elements we are using to "beat" (from sorted available elements)

    while (right_ptr < n) {
        // If the current element a[right_ptr] is greater than a[left_ptr],
        // we can use a[right_ptr] to "beat" a[left_ptr].
        // This contributes to our count.
        // Then we move both pointers forward.
        if (a[right_ptr] > a[left_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[right_ptr] is not greater than a[left_ptr],
            // we cannot use a[right_ptr] to beat a[left_ptr].
            // We must try a larger element for a[left_ptr], so we advance right_ptr.
            right_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
