int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Step 1: Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Step 2: Ensure elements to the left of median are <= s
    // If a[median_idx] was originally > s, then elements to its left might also be > s.
    // We need to decrease them to s if they are > s.
    // If a[median_idx] was originally < s, then elements to its left are already <= a[median_idx] < s.
    // No operations needed for them to be <= s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Step 3: Ensure elements to the right of median are >= s
    // If a[median_idx] was originally < s, then elements to its right might also be < s.
    // We need to increase them to s if they are < s.
    // If a[median_idx] was originally > s, then elements to its right are already >= a[median_idx] > s.
    // No operations needed for them to be >= s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

