int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // next_bad[i] stores the smallest index j >= i such that s[j], s[j+1], s[j+2]
    // or s[j], s[j+2], s[j+4] form a pattern.
    // If no such j exists, it's n.
    std::vector<int> next_bad(n + 1, n);

    for (int i = n - 1; i >= 0; --i) {
        next_bad[i] = next_bad[i + 1]; // Inherit from right

        // Check for s[i] == s[i+1] == s[i+2]
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            next_bad[i] = std::min(next_bad[i], i);
        }
        // Check for s[i] == s[i+2] == s[i+4]
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            next_bad[i] = std::min(next_bad[i], i);
        }
    }

    // Iterate through all possible starting positions l (0-indexed)
    for (int l = 0; l < n; ++l) {
        // If next_bad[l] is n, it means no pattern starts at or after l.
        // All substrings starting at l are "bad".
        if (next_bad[l] == n) {
            bad_pairs += (n - l);
        } else {
            // If a pattern starts at next_bad[l], then any substring s[l...r]
            // where r >= next_bad[l] + 2k (for the smallest k) is "good".
            // The "bad" substrings starting at l are those where r < next_bad[l] + 2k.
            // The smallest possible end index for a pattern starting at next_bad[l]
            // is next_bad[l] + 2 (for k=1) or next_bad[l] + 4 (for k=2).
            // So, any r such that r < next_bad[l] + 2 will not contain the pattern.
            // The number of such r's is (next_bad[l] + 2) - 1 - l + 1 = next_bad[l] + 2 - l.
            // However, r must be <= n-1.
            // So, the number of bad r's for a fixed l is min(n-1, next_bad[l] + 1) - l + 1.
            // This simplifies to (next_bad[l] + 2) - l.
            // But we need to be careful. The pattern is s[x] == s[x+k] == s[x+2k].
            // The rightmost index involved is x+2k.
            // For k=1, x+2k = x+2. For k=2, x+2k = x+4.
            // So, the minimum rightmost index for a pattern starting at x is x+2.
            // If next_bad[l] is the first x that starts a pattern, then any substring
            // s[l...r] where r < next_bad[l] + 2 is a bad substring.
            // The number of such r's is (next_bad[l] + 2) - 1 - l + 1 = next_bad[l] + 2 - l.
            // This is the number of r's from l to next_bad[l] + 1.
            // The actual number of bad r's for a fixed l is (next_bad[l] + 2) - l.
            // But r must be <= n-1. So, the number of bad r's is min(n, next_bad[l] + 2) - l.
            // Example: s = "010101", n=6.
            // next_bad = [0, 0, 0, 0, 0, 0, 6] (for 0-indexed string)
            // l=0: next_bad[0]=0. Bad r's: min(6, 0+2)-0 = min(6,2)-0 = 2.
            //      r=0,1. Substrings s[0...0], s[0...1].
            //      s[0...0]="0", s[0...1]="01". These are bad.
            //      s[0...2]="010". This is good because s[0]=s[2]=s[4] (010101).
            //      The pattern is at x=0, k=2. The rightmost index is 0+2*2=4.
            //      So, r must be at least 4.
            //      The condition is l <= x and x+2k <= r.
            //      For a fixed l, we find the smallest x_0 >= l that starts a pattern.
            //      Let this be x_0 = next_bad[l].
            //      If x_0 = n, all substrings starting at l are bad.
            //      Otherwise, x_0 is the start of the first pattern.
            //      The pattern involves indices x_0, x_0+k, x_0+2k.
            //      The smallest possible x_0+2k is x_0+2 (for k=1).
            //      So, any r such that r < x_0+2 will not contain this pattern.
            //      The number of such r's is (x_0+2) - 1 - l + 1 = x_0+2-l.
            //      This is the number of r's from l to x_0+1.
            //      So, bad_pairs += (x_0 + 2 - l).
            //      This is correct.
            bad_pairs += (next_bad[l] + 2 - l);
        }
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

