    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d >= 4.0, so d^2 - 4d >= 0
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d + sqrt_discriminant is positive.
            // So a1 is positive.
            // For b1, we need d - sqrt_discriminant >= 0.
            // This is equivalent to d >= sqrt_discriminant,
            // which is d^2 >= discriminant (since both sides are non-negative),
            // d^2 >= d^2 - 4d, which simplifies to 0 >= -4d, or 4d >= 0.
            // Since d >= 4, 4d is definitely >= 0.
            // So both a1 and b1 are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');
    int min_idx = pos[1];
    int max_idx = pos[1];

    // For m=1, the segment is just [1]. It's always beautiful.
    ans[0] = '1';

    for (int m = 2; m <= n; ++m) {
        // Expand the current window [min_idx, max_idx] to include 'm'.
        // The value 'm' is at pos[m].
        // We need to update min_idx and max_idx to cover the range [1, ..., m].
        // This means the new min_idx will be min(current min_idx, pos[m])
        // and new max_idx will be max(current max_idx, pos[m]).
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the segment p[min_idx ... max_idx] is a permutation of 1...m.
        // The length of this segment is max_idx - min_idx + 1.
        // If this length is equal to m, then it contains all numbers from 1 to m
        // (because it contains 1 and m, and all numbers in between, and its length is m,
        // and all elements are distinct in a permutation).
        if (max_idx - min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }
    std::cout << ans << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

