long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1; // Opponent takes 1, game ends.
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                // If Chanek takes N/2, opponent faces odd N/2.
                // Opponent will take 1, then Chanek faces N/2-1 (even).
                // If Chanek takes 1, opponent faces N-1 (odd).
                // In this specific scenario, taking 1 is better for Chanek.
                // Example: N=6.
                // Chanek takes 1: N=5. Opponent takes 1: N=4. Chanek takes 1: N=3. Opponent takes 1: N=2. Chanek takes 1: N=1. Opponent takes 1: N=0.
                // Chanek: 1+1+1 = 3. Opponent: 1+1+1 = 3.
                // Chanek takes N/2 (3): N=3. Opponent takes 1: N=2. Chanek takes 1: N=1. Opponent takes 1: N=0.
                // Chanek: 3+1 = 4. Opponent: 1+1 = 2.
                // So, taking N/2 is better.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even
                // If Chanek takes N/2, opponent faces even N/2.
                // If Chanek takes 1, opponent faces odd N-1.
                // Taking 1 is always better for Chanek here.
                // Example: N=4.
                // Chanek takes 1: N=3. Opponent takes 1: N=2. Chanek takes 1: N=1. Opponent takes 1: N=0.
                // Chanek: 1+1 = 2. Opponent: 1+1 = 2.
                // Chanek takes N/2 (2): N=2. Opponent takes 1: N=1. Chanek takes 1: N=0.
                // Chanek: 2+1 = 3. Opponent: 1 = 1.
                // So, taking N/2 is better.
                // This logic is flawed. Let's re-evaluate.
                // The optimal strategy for the current player is to leave the opponent in the worst possible state.
                // If N is even:
                // Option 1: Take 1. Remaining N-1 (odd). Opponent gets 1.
                // Option 2: Take N/2. Remaining N/2. Opponent gets N/2.
                // If N/2 is odd: Taking N/2 is better for Chanek. Chanek gets N/2, opponent faces odd N/2.
                // If N/2 is even: Taking N/2 is better for Chanek. Chanek gets N/2, opponent faces even N/2.
                // The only time taking 1 is better is when N/2 is odd AND N/2 is not 1.
                // This means N is even, N/2 is odd, and N/2 > 1.
                // This is equivalent to N is even, N/2 is odd, and N > 2.
                // In this case, if Chanek takes N/2, opponent faces N/2 (odd, >1). Opponent takes 1.
                // If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1.
                // The key is that if N/2 is odd, the opponent will take 1 from N/2.
                // If N/2 is even, the opponent will take N/4 from N/2 (if N/4 is odd) or N/4 (if N/4 is even).
                // The logic should be: if N is even, and N/2 is odd, and N/2 > 1, then taking 1 is better.
                // This is because if Chanek takes N/2, he gets N/2. Opponent faces N/2 (odd). Opponent takes 1.
                // If Chanek takes 1, he gets 1. Opponent faces N-1 (odd). Opponent takes 1.
                // The opponent will always take 1 if they face an odd number.
                // So if N is even, and N/2 is odd (and N/2 > 1), Chanek takes 1.
                // Otherwise (N is even, and N/2 is even, or N=2), Chanek takes N/2.

                // Corrected logic:
                // If N is even:
                //   If N/2 is odd AND N/2 > 1 (i.e., N is even, N/2 is odd, N > 2):
                //     Chanek takes 1.
                //     chanek_coins += 1;
                //     n -= 1;
                //   Else (N=2, or N/2 is even):
                //     Chanek takes N/2.
                //     chanek_coins += n / 2;
                //     n /= 2;
                if ((n / 2) % 2 != 0 && n / 2 > 1) { // N/2 is odd and N/2 > 1
                    chanek_coins += 1;
                    n -= 1;
                } else { // N=2 or N/2 is even
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }
        // Opponent's turn (if n > 0)
        if (n > 0) {
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n / 2) % 2 != 0 && n / 2 > 1) { // N/2 is odd and N/2 > 1
                    n -= 1;
                } else { // N=2 or N/2 is even
                    n /= 2;
                }
            }
        }
    }
    return chanek_coins;
}

