int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long current_a_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'a') {
            // If we encounter an 'a', it will eventually need to jump over
            // all 'b's to its right. Each 'b' it jumps over costs 1 step
            // and doubles the number of 'b's it needs to jump over for
            // subsequent 'a's.
            // The number of 'b's it needs to jump over is `current_a_count`.
            // So, this 'a' contributes `current_a_count` steps.
            total_steps = (total_steps + current_a_count) % MOD;

            // After this 'a' has jumped over all 'b's to its right,
            // it effectively becomes a 'b' for the 'a's further to its left.
            // More precisely, it generates a 'b' for each 'b' it jumps over.
            // So, the number of 'b's that 'a's to the left will see
            // effectively doubles for each 'a' encountered.
            current_a_count = (current_a_count * 2) % MOD;
        } else { // s[i] == 'b'
            // If we encounter a 'b', it means there's one more 'b' for
            // any 'a's to its left to jump over.
            // This 'b' itself doesn't initiate any operations, but it
            // increases the count of 'b's that an 'a' to its left would
            // need to jump over.
            current_a_count = (current_a_count + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

