void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor_sum ^= a[i];
    }

    // Check if already good
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Append 2 elements
    // Let the two elements be X_0 and S_0 + X_0.
    // New sum: S_0 + X_0 + (S_0 + X_0) = 2*S_0 + 2*X_0
    // New XOR sum: X_0 ^ X_0 ^ (S_0 + X_0) = S_0 + X_0
    // We need: 2*S_0 + 2*X_0 = 2 * (S_0 + X_0)
    // This is always true.
    // The problem states that appended elements don't have to be different.
    // So, we can append X_0 and S_0 + X_0.
    // Note: S_0 + X_0 can be up to 10^5 * 10^9 + 10^9 which is approx 10^14.
    // This fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

