// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we need to remove some prime factors from p such that the resulting number
        // is no longer divisible by q, but is as large as possible.

        // Get prime factors of q.
        // For each prime factor f of q, we need to reduce the power of f in p
        // until p is no longer divisible by q.
        // To maximize x, we should only reduce the power of f in p just enough.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : q_prime_factors) {
            // For each prime factor f of q, we want to find the largest divisor of p
            // that is not divisible by q, by reducing the power of f in p.

            // Calculate current p_copy, which is p divided by f until it's no longer divisible by q.
            // This is done by dividing p by f until the exponent of f in p is less than
            // the exponent of f in q.
            // More precisely, we want to find the largest x = p / (f^k) such that x % q != 0.
            // This means p / (f^k) should not be divisible by q.
            // This is equivalent to saying that the exponent of f in p / (f^k) is less than
            // the exponent of f in q.

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

