void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    if (total_toys == 1) {
        if (a == 1) std::cout << "Ya Tidak Tidak Tidak\n";
        else if (b == 1) std::cout << "Tidak Ya Tidak Tidak\n";
        else if (c == 1) std::cout << "Tidak Tidak Ya Tidak\n";
        else if (d == 1) std::cout << "Tidak Tidak Tidak Ya\n";
        return;
    }

    // Determine if the final product can be negative.
    // The final product is negative if and only if the total number of negative factors is odd.
    // Negative factors come from Box 1 and Box 2.
    // So, if (a + b) is odd, the final product can be negative.
    // If (a + b) is even, the final product must be positive.
    bool can_be_negative = ((a + b) % 2 == 1);
    bool can_be_positive = true; // Always possible to make positive, unless all toys are negative and (a+b) is odd.
                                 // But even if (a+b) is odd, we can still make positive intermediate products.
                                 // The final product's sign is determined by the parity of negative factors.
                                 // If (a+b) is even, final product is positive.
                                 // If (a+b) is odd, final product is negative.
                                 // So, if (a+b) is odd, can_be_positive is false for the final product.
                                 // If (a+b) is even, can_be_negative is false for the final product.
                                 // This logic is for the *final* product.
                                 // However, the problem asks "which boxes *can* be the special box".
                                 // This implies we can choose the order of operations.
                                 // If (a+b) is odd, the final product *must* be negative.
                                 // If (a+b) is even, the final product *must* be positive.
                                 // So, if (a+b) is odd, Box 3 and Box 4 are impossible.
                                 // If (a+b) is even, Box 1 and Box 2 are impossible.

    bool final_sign_negative = ((a + b) % 2 == 1);

    // Determine if the final product can have magnitude < 1.
    // This is possible if there is at least one toy in Box 2 or Box 3.
    // If all toys are from Box 1 and Box 4, then all magnitudes are >= 1.
    // In this case, the product of magnitudes will be >= 1.
    bool can_be_mag_lt_1 = (b > 0 || c > 0);

    // Determine if the final product can have magnitude >= 1.
    // This is possible if there is at least one toy in Box 1 or Box 4.
    // If all toys are from Box 2 and Box 3, then all magnitudes are < 1.
    // In this case, the product of magnitudes will be < 1.
    bool can_be_mag_ge_1 = (a > 0 || d > 0);

    // Special case: If all toys are from Box 2 and Box 3, then the final product's magnitude must be < 1.
    if (a == 0 && d == 0) {
        can_be_mag_ge_1 = false;
    }
    // Special case: If all toys are from Box 1 and Box 4, then the final product's magnitude must be >= 1.
    if (b == 0 && c == 0) {
        can_be_mag_lt_1 = false;
    }

    // Box 1: Negative, magnitude >= 1
    bool box1_possible = final_sign_negative && can_be_mag_ge_1;

    // Box 2: Negative, magnitude < 1
    bool box2_possible = final_sign_negative && can_be_mag_lt_1;

    // Box 3: Positive, magnitude < 1
    bool box3_possible = !final_sign_negative && can_be_mag_lt_1;

    // Box 4: Positive, magnitude >= 1
    bool box4_possible = !final_sign_negative && can_be_mag_ge_1;

    // Edge case: If there are no toys with magnitude < 1 (b=0, c=0),
    // but there are toys with magnitude >= 1 (a>0 or d>0),
    // then the final product's magnitude must be >= 1.
    // In this scenario, if we have only a and d toys, can_be_mag_lt_1 would be false.
    // This is correctly handled by the `can_be_mag_lt_1` and `can_be_mag_ge_1` logic.

    // Another edge case: What if we have only one toy with magnitude < 1 (e.g., b=1, a=c=d=0)?
    // Then can_be_mag_lt_1 is true, can_be_mag_ge_1 is false.
    // final_sign_negative is true.
    // Box 1: F && F = F
    // Box 2: T && T = T
    // Box 3: F && T = F
    // Box 4: F && F = F
    // This is correct for total_toys=1.

    // What if we have only one toy with magnitude >= 1 (e.g., a=1, b=c=d=0)?
    // Then can_be_mag_lt_1 is false, can_be_mag_ge_1 is true.
    // final_sign_negative is true.
    // Box 1: T && T = T
    // Box 2: T && F = F
    // Box 3: F && F = F
    // Box 4: F && T = F
    // This is correct for total_toys=1.

    // The logic seems robust for total_toys > 1.
    // The key insight is that the final sign is fixed by the parity of (a+b).
    // The final magnitude range depends on whether there were any factors < 1 or > 1.
    // If there are factors < 1 (b>0 or c>0), we can always arrange operations to make the final magnitude < 1.
    // For example, multiply all factors with magnitude >= 1 first, then multiply by a factor < 1.
    // If there are factors >= 1 (a>0 or d>0), we can always arrange operations to make the final magnitude >= 1.
    // For example, multiply all factors with magnitude < 1 first, then multiply by a factor >= 1.
    // This is true unless one of the magnitude categories is completely empty.
    // E.g., if a=0, d=0, then all initial toys have magnitude < 1. The final product must have magnitude < 1.
    // E.g., if b=0, c=0, then all initial toys have magnitude >= 1. The final product must have magnitude >= 1.

    std::cout << (box1_possible ? "Ya" : "Tidak");
    std::cout << " " << (box2_possible ? "Ya" : "Tidak");
    std::cout << " " << (box3_possible ? "Ya" : "Tidak");
    std::cout << " " << (box4_possible ? "Ya" : "Tidak") << "\n";
}

