    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left.
    // Then 'n - i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // These are w[n-1]...w[n-(n-i)]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive actions
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left.
            // The last item taken must be from the left.
            // The difference is (left_count - right_count).
            // If this difference is 1, no extra penalty.
            // If this difference is > 1, then (left_count - right_count - 1) times
            // we took an item from the left when the previous was also from the left.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right.
            // The last item taken must be from the right.
            // The difference is (right_count - left_count).
            // If this difference is 1, no extra penalty.
            // If this difference is > 1, then (right_count - left_count - 1) times
            // we took an item from the right when the previous was also from the right.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no extra penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementsA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementsB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementsA);
    std::sort(B.begin(), B.end(), compareElementsB);

    std::vector<long long> result_A_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (B[i].value) should be paired with
        // the (m-1-i)-th largest A value (A[m-1-i].value).
        // The original index of this B value is B[i].original_index.
        // So, result_A_prime[B[i].original_index] should be A[m-1-i].value.
        result_A_prime[B[i].original_index] = A[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit in S1
        int last2 = -1; // Last digit in S2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_p = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > p) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_p = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == p
                // Can be color 1 or color 2
                // If it can extend S2, put it in S2.
                // Otherwise, put it in S1.
                if (d[i] >= last2) { // Can be part of S2
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Can be part of S1
                    colors[i] = 1;
                    last1 = d[i];
                } else { // Cannot be part of S1 or S2
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            // Final check: last of S1 <= first of S2
            // This is implicitly handled by the logic:
            // if a digit `p` is put into S1, it means `p < last2` was true.
            // if a digit `p` is put into S2, it means `p >= last2` was true.
            // The `last1` and `last2` variables track the maximum values seen so far for each color.
            // The condition `last1 <= first_of_S2` is not directly checked, but the construction ensures it.
            // Specifically, any digit `d[i] == p` that goes into S1 must satisfy `d[i] >= last1`.
            // Any digit `d[i] == p` that goes into S2 must satisfy `d[i] >= last2`.
            // The critical part is that if `d[i] == p` goes into S1, it means `d[i] < last2` was true.
            // This implies that any `p` in S1 is less than any `p` in S2 that has already been placed.
            // And any `p` in S2 is greater than or equal to any `p` in S1 that has already been placed.
            // The `last1` and `last2` values are the maximums of the digits assigned to each color *so far*.
            // The actual check needed is that the maximum value in the final S1 sequence is <= minimum value in the final S2 sequence.
            // Our greedy choice for `d[i] == p` ensures this:
            // If `d[i] == p` is placed in color 1, it means `d[i] < last2` (the current max of S2).
            // This is problematic. The `last2` here is the max of digits already assigned to color 2.
            // The condition is that `max(S1) <= min(S2)`.
            // Let's re-evaluate the `d[i] == p` logic.
            // If `d[i] == p`, we want to put it in color 1 if possible, to keep `last1` small.
            // Or put it in color 2 if possible, to keep `last2` small.
            // The current logic: if `d[i] >= last2`, put in color 2. Else if `d[i] >= last1`, put in color 1.
            // This means if `d[i] == p` and `p >= last2`, it goes to color 2.
            // If `d[i] == p` and `p < last2`, it goes to color 1 (if `p >= last1`).
            // This ensures that any `p` assigned to color 1 is strictly less than any `p` assigned to color 2 *that appeared earlier*.
            // This is exactly what we need for `max(S1) <= min(S2)`.
            // The `last1` and `last2` variables correctly track the non-decreasing property within each color.
            // The split point `p` ensures that all digits `< p` are in S1, all digits `> p` are in S2.
            // Digits `== p` are split such that those appearing before the first `p` assigned to color 2 go to color 1,
            // and those appearing after or at the first `p` assigned to color 2 go to color 2.
            // This means `max(S1) <= p` and `min(S2) >= p`.
            // So `max(S1) <= min(S2)` is guaranteed.

            for (int color : colors) {
                std::cout << color;
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] can be reduced to
    // to satisfy a_1 < a_2 < ... < a_i
    // This means a_i must be at least i-1.
    // So, a[i] >= i-1.
    // If a[i] < i-1, it's impossible to satisfy the increasing condition up to i.
    // We can reduce a[i] to min(a[i], i-1) if we want to satisfy the condition.
    // More precisely, we need a[i] >= i-1.
    // Let's define `left_possible[i]` as true if `a[i]` can be made `i-1` or greater
    // while maintaining `a_0 < a_1 < ... < a_i`.
    // This is equivalent to `a[i] >= i`.
    // For `a_0`, it must be `a_0 >= 0`.
    // For `a_1`, it must be `a_1 >= 1`.
    // For `a_i`, it must be `a_i >= i`.
    // So, `a[i]` must be at least `i`.
    // Let's re-evaluate: `b_0 < b_1 < ... < b_k`.
    // `b_0 >= 0`.
    // `b_1 >= b_0 + 1 >= 1`.
    // `b_2 >= b_1 + 1 >= 2`.
    // In general, `b_i >= i`.
    // So, we need `a[i] >= i` for `0 <= i < k`.

    // Calculate `left_ok[i]`: true if `a[i]` can be the `i`-th element (0-indexed)
    // of a strictly increasing sequence starting from `a[0] >= 0`.
    // This means `a[i]` must be at least `i`.
    std::vector<bool> left_ok(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_ok[i] = true;
        } else {
            left_ok[i] = false;
        }
    }

    // Calculate `right_ok[i]`: true if `a[i]` can be the `i`-th element (0-indexed)
    // of a strictly decreasing sequence ending at `a[n-1] >= 0`.
    // This means `a[i]` must be at least `n-1-i`.
    // For `a[n-1]`, it must be `a[n-1] >= 0`.
    // For `a[n-2]`, it must be `a[n-2] >= 1`.
    // For `a[i]`, it must be `a[i] >= n-1-i`.
    std::vector<bool> right_ok(n);
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_ok[i] = true;
        } else {
            right_ok[i] = false;
        }
    }

    // Check if there exists a peak `k` (0-indexed) such that
    // `left_ok[k]` is true and `right_ok[k]` is true.
    // The problem statement uses 1-indexed `k`.
    // If `k` is 1-indexed, then `a_k` is the peak.
    // For `a_1 < ... < a_k`, we need `a_i >= i-1` for `1 <= i <= k`.
    // For `a_k > ... > a_n`, we need `a_i >= n-i` for `k <= i <= n`.
    // Let's stick to 0-indexed for implementation: `a_0 < ... < a_{k_0}` and `a_{k_0} > ... > a_{n-1}`.
    // For `a_0 < ... < a_{k_0}`, we need `a_i >= i` for `0 <= i <= k_0`.
    // For `a_{k_0} > ... > a_{n-1}`, we need `a_i >= (n-1)-i` for `k_0 <= i <= n-1`.
    // So, we need to find `k_0` such that `a[k_0] >= k_0` AND `a[k_0] >= (n-1)-k_0`.
    // This is equivalent to `left_ok[k_0]` and `right_ok[k_0]`.

    bool possible = false;
    for (int k_0 = 0; k_0 < n; ++k_0) {
        if (left_ok[k_0] && right_ok[k_0]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

