int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -1000000000LL; // Effectively negative infinity
        long long max_x = 1000000000LL;  // Effectively positive infinity
        long long min_y = -1000000000LL; // Effectively negative infinity
        long long max_y = 1000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1). So target X must be >= current x.
            // This means x is a lower bound for X.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 0 means cannot move right (x+1). So target X must be <= current x.
            // This means x is an upper bound for X.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So target Y must be >= current y.
            // This means y is a lower bound for Y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 0 means cannot move up (y+1). So target Y must be <= current y.
            // This means y is an upper bound for Y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists with |X|, |Y| <= 10^5.
            // Our calculated min_x, max_x, min_y, max_y can be outside this range,
            // but any point within [min_x, max_x] x [min_y, max_y] is a valid target.
            // We can just pick min_x and min_y as the target.
            // The problem statement implies that the coordinates of the chosen point
            // should not exceed 10^5 by absolute value.
            // However, the bounds for x_i, y_i are -10^5 to 10^5.
            // If a robot is at (10^5, 10^5) and cannot move right, max_x becomes 10^5.
            // If a robot is at (-10^5, -10^5) and cannot move left, min_x becomes -10^5.
            // So min_x and max_x will always be within [-10^5, 10^5] if they are derived from robot positions.
            // The initial -10^9 and 10^9 are just to represent "infinity".
            // The actual bounds will be constrained by robot positions.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

