#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    long long total_sum = 0;

    // Sum of k from 1 to a: a * (a + 1) / 2
    long long sum_k_mod = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_mod = (sum_k_mod * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r_mod = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r_mod = (sum_r_mod * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The sum is sum(r * (k*b + 1)) for k in [1, a], r in [1, b-1]
    // This can be rewritten as sum(r * k * b + r)
    // = sum(r * k * b) + sum(r)
    // = b * sum(r * k) + sum(r)
    // = b * (sum(r) * sum(k)) + sum(r)
    // = (b * sum(r) * sum(k)) + sum(r)

    long long term1 = (b % MOD * sum_r_mod) % MOD;
    term1 = (term1 * sum_k_mod) % MOD;

    long long term2 = sum_r_mod;

    total_sum = (term1 + term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
