#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char c0 = s[k_actual];

        std::vector<int> possible_k_values;
        for (int idx : char_indices[c0 - 'a']) {
            possible_k_values.push_back(idx);
        }

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < n; ++p) {
            char cp = s[(k_actual + p) % n];

            int count_unique_k = 0;
            for (int k_cand : possible_k_values) {
                if (s[(k_cand + p) % n] == cp) {
                    count_unique_k++;
                }
            }

            if (count_unique_k == 1) {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            } else {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 0.0);
            }
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long N = std::abs(n);
        long long M = std::abs(m);

        // Ensure N >= M for simpler logic
        if (N < M) {
            std::swap(N, M);
        }

        // Case 1: k < N (or k < M, since N >= M)
        // It's impossible to reach (N, M) in k moves if k is less than the
        // maximum coordinate distance.
        if (k < N) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= N
        // We can always reach (N, M) in N moves by making M diagonal moves
        // and N-M non-diagonal moves along the x-axis.
        // The remaining k - N moves must be "wasted" by moving back and forth.
        // Each wasted move must be paired with another move to return to the
        // same parity or position.
        // A pair of moves like (x,y) -> (x+1,y) -> (x,y) takes 2 moves and
        // changes parity of x by 0.
        // A pair of moves like (x,y) -> (x+1,y+1) -> (x,y) takes 2 moves and
        // changes parity of x by 0, y by 0.
        //
        // The parity of the final coordinates (N, M) must match the parity of k.
        // Each move changes the sum of coordinates (x+y) by an odd amount
        // if it's a non-diagonal move (e.g., (x+1,y) -> x+y+1)
        // or by an even amount if it's a diagonal move (e.g., (x+1,y+1) -> x+y+2).
        // This is incorrect. Each move changes the parity of x+y by 1.
        // (x,y) -> (x',y'). (x'+y') - (x+y) has the same parity as (x'-x) + (y'-y).
        // For any of the 8 moves, (x'-x) and (y'-y) are -1, 0, or 1.
        // The sum (x'-x) + (y'-y) can be -2, -1, 0, 1, 2.
        // The parity of (x'+y') - (x+y) is the parity of (x'-x) + (y'-y).
        // This means (x'+y') and (x+y) must have different parities if (x'-x)+(y'-y) is odd.
        // (x'-x)+(y'-y) is odd for non-diagonal moves (e.g., (1,0) sum 1)
        // (x'-x)+(y'-y) is even for diagonal moves (e.g., (1,1) sum 2)
        //
        // This is also not the simplest way to think about parity.
        // A simpler way: each move changes the parity of (x+y) by 1.
        // (x_new + y_new) % 2 != (x_old + y_old) % 2.
        // So, after k moves, the parity of (N+M) must be different from the parity of (0+0)
        // if k is odd, and the same if k is even.
        // In other words, (N+M) % 2 must be equal to k % 2.

        if ((N + M) % 2 != k % 2) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible to reach (N, M) in k moves.
        // We want to maximize diagonal moves.
        // The maximum number of diagonal moves is k.
        // However, we must ensure that the final position is (N, M).
        //
        // We can make M diagonal moves to reach (M, M). This uses M moves.
        // We then need to reach (N, M) from (M, M). This requires N-M more moves
        // along the x-axis. These N-M moves must be non-diagonal.
        // Total moves so far: M (diagonal) + (N-M) (non-diagonal) = N moves.
        // Current diagonal moves: M.
        //
        // We have k - N moves remaining. These moves must be "wasted" without
        // changing the final position (N, M).
        // Each pair of moves like (x,y) -> (x+1,y+1) -> (x,y) uses 2 moves and 2 diagonal moves.
        // Each pair of moves like (x,y) -> (x+1,y) -> (x,y) uses 2 moves and 0 diagonal moves.
        //
        // To maximize diagonal moves, we should use the (x+1,y+1) -> (x,y) type of pair.
        // Each such pair adds 2 to the total moves and 2 to the diagonal moves count.
        // The number of such pairs we can make is (k - N) / 2.
        // So, the additional diagonal moves are 2 * ((k - N) / 2) = k - N.
        //
        // Total diagonal moves = M (from initial path) + (k - N) (from wasted moves).
        // This is the maximum possible.

        long long ans = M + (k - N);
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current_val_0 and current_val_1 for each bit.
    // current_val_0[b] stores the final state of bit b if initial bit b was 0.
    // current_val_1[b] stores the final state of bit b if initial bit b was 1.
    // Initially, if bit b was 0, it's 0. If bit b was 1, it's 1.
    std::vector<int> current_val_0(10); // All zeros
    std::vector<int> current_val_1(10); // All ones
    for (int i = 0; i < 10; ++i) {
        current_val_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int b = 0; b < 10; ++b) {
            int bit_val = (val >> b) & 1;
            if (op_char == '&') {
                current_val_0[b] &= bit_val;
                current_val_1[b] &= bit_val;
            } else if (op_char == '|') {
                current_val_0[b] |= bit_val;
                current_val_1[b] |= bit_val;
            } else { // '^'
                current_val_0[b] ^= bit_val;
                current_val_1[b] ^= bit_val;
            }
        }
    }

    // Now, for each bit b, we know the mapping:
    // 0 -> current_val_0[b]
    // 1 -> current_val_1[b]

    // We need to find A_AND, A_OR, A_XOR such that:
    // (x & A_AND | A_OR) ^ A_XOR
    // For each bit b:
    // (x_b & (A_AND)_b | (A_OR)_b) ^ (A_XOR)_b = current_val_x_b[b]

    // Let's determine A_AND, A_OR, A_XOR bit by bit.
    int A_AND = 1023; // Initialize to all ones (no effect for AND)
    int A_OR = 0;     // Initialize to all zeros (no effect for OR)
    int A_XOR = 0;    // Initialize to all zeros (no effect for XOR)

    for (int b = 0; b < 10; ++b) {
        int f0 = current_val_0[b]; // Result for input bit 0
        int f1 = current_val_1[b]; // Result for input bit 1

        // We are looking for (x_b & and_b | or_b) ^ xor_b
        // Case 1: x_b = 0
        // (0 & and_b | or_b) ^ xor_b = (0 | or_b) ^ xor_b = or_b ^ xor_b = f0
        // Case 2: x_b = 1
        // (1 & and_b | or_b) ^ xor_b = (and_b | or_b) ^ xor_b = f1

        // From these two equations, we can deduce and_b, or_b, xor_b.
        // There are 4 possible (f0, f1) pairs: (0,0), (0,1), (1,0), (1,1)

        if (f0 == 0 && f1 == 0) { // Both 0 -> 0
            // or_b ^ xor_b = 0  => or_b = xor_b
            // (and_b | or_b) ^ xor_b = 0 => and_b | or_b = xor_b
            // If or_b = xor_b, then and_b | or_b = or_b. This implies and_b must be 0.
            // So, and_b = 0, or_b = 0, xor_b = 0.
            // (x_b & 0 | 0) ^ 0 = 0. This works.
            A_AND &= ~(1 << b); // Set and_b to 0
            // A_OR remains 0 for this bit
            // A_XOR remains 0 for this bit
        } else if (f0 == 0 && f1 == 1) { // 0 -> 0, 1 -> 1 (identity)
            // or_b ^ xor_b = 0  => or_b = xor_b
            // (and_b | or_b) ^ xor_b = 1 => and_b | or_b = 1 ^ xor_b
            // If or_b = xor_b, then and_b | or_b = 1 ^ or_b.
            // This implies and_b must be 1 and or_b must be 0.
            // So, and_b = 1, or_b = 0, xor_b = 0.
            // (x_b & 1 | 0) ^ 0 = x_b. This works.
            // A_AND remains 1 for this bit
            // A_OR remains 0 for this bit
            // A_XOR remains 0 for this bit
        } else if (f0 == 1 && f1 == 0) { // 0 -> 1, 1 -> 0 (NOT)
            // or_b ^ xor_b = 1  => or_b != xor_b
            // (and_b | or_b) ^ xor_b = 0 => and_b | or_b = xor_b
            // If or_b != xor_b, and and_b | or_b = xor_b, then:
            // If or_b = 0, xor_b = 1. Then and_b | 0 = 1 => and_b = 1.
            // So, and_b = 1, or_b = 0, xor_b = 1.
            // (x_b & 1 | 0) ^ 1 = x_b ^ 1. This works.
            // A_AND remains 1 for this bit
            // A_OR remains 0 for this bit
            A_XOR |= (1 << b); // Set xor_b to 1
        } else { // f0 == 1 && f1 == 1 (Both 1 -> 1)
            // or_b ^ xor_b = 1  => or_b != xor_b
            // (and_b | or_b) ^ xor_b = 1 => and_b | or_b = 1 ^ xor_b
            // If or_b != xor_b, and and_b | or_b = 1 ^ xor_b, then:
            // If or_b = 1, xor_b = 0. Then and_b | 1 = 1 ^ 0 = 1. This is always true for any and_b.
            // So, and_b = 0 (to be minimal), or_b = 1, xor_b = 0.
            // (x_b & 0 | 1) ^ 0 = 1. This works.
            A_AND &= ~(1 << b); // Set and_b to 0
            A_OR |= (1 << b);   // Set or_b to 1
            // A_XOR remains 0 for this bit
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_AND != 1023) { // If A_AND is not all ones, we need an AND operation
        result_ops.push_back({'&', A_AND});
    }
    if (A_OR != 0) { // If A_OR is not all zeros, we need an OR operation
        result_ops.push_back({'|', A_OR});
    }
    if (A_XOR != 0) { // If A_XOR is not all zeros, we need an XOR operation
        result_ops.push_back({'^', A_XOR});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> seen_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        seen_in_s[s[i] - 'a'] = true;
        if (i > 0) {
            adj[s[i] - 'a'].insert(s[i - 1]);
            adj[s[i - 1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths
    // A starting point is a character that has only one required neighbor
    // or a character that is in 's' but has no required neighbors (s.length() == 1 case)
    // or any character if s is empty (not possible by constraints)

    for (int i = 0; i < 26; ++i) {
        if (seen_in_s[i] && adj[i].size() <= 1 && !visited[i]) {
            char current_char = (char)('a' + i);

            // If this character has no neighbors, it means it's a single character password
            // or an isolated character in a longer password.
            // We should only start a path from it if it's not already part of a longer path.
            // The condition adj[i].size() <= 1 handles this.

            std::string current_path = "";
            char prev_char = 0; // Sentinel for no previous char

            while (current_char != 0 && !visited[current_char - 'a']) {
                visited[current_char - 'a'] = true;
                current_path += current_char;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (neighbor != prev_char) {
                        next_char = neighbor;
                        break;
                    }
                }
                prev_char = current_char;
                current_char = next_char;
            }
            layout += current_path;
        }
    }

    // Check if all characters from 's' have been included in the layout
    for (int i = 0; i < 26; ++i) {
        if (seen_in_s[i] && !visited[i]) {
            // This means there's a cycle or a path segment not starting with a degree-1 node
            // which implies a degree-2 node was not visited.
            // This should not happen if adj.size() <= 2 for all nodes.
            // If it happens, it means our path construction logic missed something,
            // or there's a cycle.
            // A cycle would mean a character has two neighbors, and following them leads back.
            // But a keyboard is a single row, so no cycles are allowed.
            // If all nodes have degree <= 2, the graph is a collection of paths and isolated vertices.
            // Our logic should find all paths.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in 's'
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    if (layout.length() != 26) {
        // This should ideally not happen if the logic is correct and constraints are met.
        // It would imply some character was missed or duplicated.
        std::cout << "NO\n"; // Fallback
    } else {
        std::cout << "YES\n";
        std::cout << layout << "\n";
    }
}

