int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to n+1.
        // If no 'R' was found, last_R_pos is -1, and the gap is (n+1) - (-1) = n+2.
        // If 'R's were found, last_R_pos is the index of the last 'R'.
        // The length of the string is s.length(), so the cells are 1 to s.length().
        // The target is cell s.length() + 1.
        // The distance from last_R_pos to s.length() + 1 is (s.length() + 1) - last_R_pos.
        max_gap = std::max(max_gap, (int)s.length() + 1 - last_R_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] is set per query
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop/terminates outside
    std::vector<int> dp_x(n + 1, 0); // 0: uncomputed, -1: infinite loop/terminates outside

    for (int start_a1 = 1; start_a1 < n; ++start_a1) {
        a[1] = start_a1;

        long long current_y = 0;
        int current_x = 1;

        // Simulate the first two steps (x+a_x, y+a_x) and (x-a_x, y+a_x)
        // This is the first pair of operations.
        // After this, x will be 1 + a[1] - a[1+a[1]].
        // y will be a[1] + a[1+a[1]].
        // The next state will be (x, y) where x is 1 + a[1] - a[1+a[1]] and y is a[1] + a[1+a[1]].
        // The next operation will be x+a_x, y+a_x.

        // First operation: x = x + a[x], y = y + a[x]
        long long val1 = a[current_x];
        current_x += val1;
        current_y += val1;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Second operation: x = x - a[x], y = y + a[x]
        long long val2 = a[current_x];
        current_x -= val2;
        current_y += val2;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now, current_x is the starting point for the next pair of operations.
        // The next operation will be x = x + a[x], y = y + a[x].
        // We need to find the result for starting from current_x with an "add" operation.
        // This is equivalent to finding dp_y[current_x] and dp_x[current_x]
        // but considering the first operation is x+a_x, y+a_x.

        // If dp_y[current_x] is -2, it means we haven't computed it yet.
        // We need to compute it.
        if (dp_y[current_x] == -2) {
            std::vector<int> path;
            int temp_x = current_x;

            while (temp_x > 0 && temp_x <= n && dp_y[temp_x] == -2) {
                path.push_back(temp_x);
                dp_y[temp_x] = -1; // Mark as visited (potential cycle)
                dp_x[temp_x] = -1;

                long long next_val1 = a[temp_x];
                int next_x_after_add = temp_x + next_val1;

                if (next_x_after_add <= 0 || next_x_after_add > n) {
                    dp_y[temp_x] = next_val1;
                    dp_x[temp_x] = next_x_after_add;
                    break;
                }

                long long next_val2 = a[next_x_after_add];
                int next_x_after_sub = next_x_after_add - next_val2;

                if (next_x_after_sub <= 0 || next_x_after_sub > n) {
                    dp_y[temp_x] = next_val1 + next_val2;
                    dp_x[temp_x] = next_x_after_sub;
                    break;
                }
                temp_x = next_x_after_sub;
            }

            long long final_y_val;
            int final_x_val;

            if (temp_x <= 0 || temp_x > n) { // Terminated outside
                final_y_val = 0; // Base case for termination
                final_x_val = temp_x;
            } else { // Hit a computed state or a cycle
                final_y_val = dp_y[temp_x];
                final_x_val = dp_x[temp_x];
            }

            // Backtrack and fill DP table
            for (int j = path.size() - 1; j >= 0; --j) {
                int p_x = path[j];
                if (dp_y[p_x] != -1) continue; // Already computed by another path

                long long next_val1 = a[p_x];
                int next_x_after_add = p_x + next_val1;
                long long current_step_y = next_val1;
                int current_step_x = next_x_after_add;

                if (current_step_x <= 0 || current_step_x > n) {
                    dp_y[p_x] = current_step_y;
                    dp_x[p_x] = current_step_x;
                } else {
                    long long next_val2 = a[current_step_x];
                    current_step_y += next_val2;
                    current_step_x -= next_val2;

                    if (current_step_x <= 0 || current_step_x > n) {
                        dp_y[p_x] = current_step_y;
                        dp_x[p_x] = current_step_x;
                    } else {
                        if (final_y_val == -1) { // Cycle detected
                            dp_y[p_x] = -1;
                            dp_x[p_x] = -1;
                        } else {
                            dp_y[p_x] = current_step_y + final_y_val;
                            dp_x[p_x] = final_x_val;
                        }
                    }
                }
                final_y_val = dp_y[p_x];
                final_x_val = dp_x[p_x];
            }
        }

        if (dp_y[current_x] == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + dp_y[current_x] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    // If k*k < n, we need to increase k to ensure all elements are covered.
    // This is equivalent to ceil(sqrt(n)).
    if (k * k < n) {
        k++;
    }

    // The permutation will be constructed in blocks of size k.
    // Each block will be printed in decreasing order.
    // The blocks themselves are arranged such that smaller numbers appear later.
    // Example for n=4, k=2:
    // Block 1: (2, 1)
    // Block 2: (4, 3)
    // Output: 2 1 4 3 (This is not the example output, but also valid)
    // Example for n=4, k=ceil(sqrt(4))=2.
    // Block 1: (2, 1)
    // Block 2: (4, 3)
    // Output: 2 1 4 3. LIS: [2,4] or [1,3] (len 2). LDS: [2,1] or [4,3] (len 2). Sum = 4.
    //
    // The example output for n=4 is 3 4 1 2.
    // This is constructed by blocks of size k, but the blocks are printed in reverse order.
    // For n=4, k=2.
    // Block 1: (1, 2)
    // Block 2: (3, 4)
    // Print Block 2 in reverse: 4 3
    // Print Block 1 in reverse: 2 1
    // Output: 4 3 2 1. LIS: [1] (len 1). LDS: [4,3,2,1] (len 4). Sum = 5.
    // This is not optimal.

    // Let's re-evaluate the construction from the problem statement's example.
    // For n=4, output 3 4 1 2.
    // LIS: [3,4] or [1,2] (len 2). LDS: [3,1], [3,2], [4,1], [4,2] (len 2). Sum = 4.
    // This permutation is formed by:
    // Block 1: (1, 2)
    // Block 2: (3, 4)
    // Output: (Block 2, reversed) (Block 1, reversed) -> (4, 3) (2, 1) -> 4 3 2 1. This is not 3 4 1 2.
    //
    // The example output 3 4 1 2 for n=4:
    // It seems to be constructed by taking elements in groups of k, and reversing each group.
    // k = ceil(sqrt(n)).
    // For n=4, k=2.
    // Group 1: (1, 2) -> reversed (2, 1)
    // Group 2: (3, 4) -> reversed (4, 3)
    // If we print them in order: 2 1 4 3.
    //
    // The example output 3 4 1 2 is different.
    // It looks like:
    // (k-1) elements from the end of the first block, then (k-1) elements from the end of the second block, etc.
    // No, it's simpler.
    // The construction that achieves LIS + LDS = 2*ceil(sqrt(n)) is:
    // Divide numbers 1 to n into blocks of size k.
    // Block 1: 1, ..., k
    // Block 2: k+1, ..., 2k
    // ...
    // Block m: (m-1)k+1, ..., n
    // Then print each block in reverse order.
    // For n=4, k=2:
    // Block 1: (1, 2) -> reversed (2, 1)
    // Block 2: (3, 4) -> reversed (4, 3)
    // Output: 2 1 4 3.
    // This is a valid answer, and it achieves the minimum sum.
    // The problem states "If there are multiple answers, print any."
    // So 2 1 4 3 for n=4 is fine.

    // Let's implement this strategy:
    // Iterate from n down to 1.
    // For each number `i`, if it's the start of a new block (i.e., `i % k == 0` or `i == n`),
    // print the block `i-k+1, ..., i` in reverse.
    // More simply: iterate `i` from `0` to `n-1`.
    // The numbers are `1, ..., n`.
    // We want to print `k, k-1, ..., 1, 2k, 2k-1, ..., k+1, ...`
    // Or, `(j*k+k), (j*k+k-1), ..., (j*k+1)` for `j=0, 1, ...`
    // The last block might be smaller.

    // Iterate through blocks.
    // `current_val` will be the largest value in the current block.
    // `current_val` starts at `n`.
    // `start_of_block` will be the smallest value in the current block.
    // `start_of_block = max(1, current_val - k + 1)`.
    // Print from `current_val` down to `start_of_block`.
    // Then set `current_val = start_of_block - 1`.

    int current_val = n;
    while (current_val >= 1) {
        int start_of_block = std::max(1, current_val - k + 1);
        for (int i = current_val; i >= start_of_block; --i) {
            std::cout << i << (i == 1 ? "" : " ");
        }
        current_val = start_of_block - 1;
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Should not happen based on constraints (n >= 3), but good for robustness
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones_dist(n, 0);
    std::vector<int> right_ones_dist(n, 0);

    // Calculate left_ones_dist
    if (a[0] == 0) {
        left_ones_dist[0] = 0;
    } else { // a[0] == 1
        left_ones_dist[0] = -1; // Sentinel for '1' at current position
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_ones_dist[i] = left_ones_dist[i - 1] + 1;
        } else { // a[i] == 1
            left_ones_dist[i] = -1; // Sentinel for '1' at current position
        }
    }

    // Calculate right_ones_dist
    if (a[n - 1] == 0) {
        right_ones_dist[n - 1] = 0;
    } else { // a[n-1] == 1
        right_ones_dist[n - 1] = -1; // Sentinel for '1' at current position
    }
