void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance (strawberry - blueberry) for all 2n jars
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // balance_left[k] = balance of jars 1 to k
    // We are interested in balance_left[k] for k from 0 to n.
    // balance_left[0] = 0 (empty prefix)
    // balance_left[k] = balance of jars a[0]...a[k-1]
    std::vector<int> balance_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_left[i + 1] = balance_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // balance_right[k] = balance of jars 2n-k+1 to 2n
    // We are interested in balance_right[k] for k from 0 to n.
    // balance_right[0] = 0 (empty suffix)
    // balance_right[k] = balance of jars a[2n-k]...a[2n-1]
    std::vector<int> balance_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_right[i + 1] = balance_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain balance
    // map: balance_value -> jars_removed_from_left
    std::map<int, int> left_balance_to_removed_count;
    for (int k = 0; k <= n; ++k) { // k is number of jars kept from left (0 to n)
        // balance_left[k] is the balance of the first k jars (a[0]...a[k-1])
        // Number of jars removed from left is n - k
        if (left_balance_to_removed_count.find(balance_left[k]) == left_balance_to_removed_count.end()) {
            left_balance_to_removed_count[balance_left[k]] = n - k;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible removed jars

    // Iterate through possible number of jars kept from the right side
    for (int k = 0; k <= n; ++k) { // k is number of jars kept from right (0 to n)
        // balance_right[k] is the balance of the last k jars (a[2n-k]...a[2n-1])
        // Number of jars removed from right is n - k

        // The total balance of remaining jars should be 0.
        // balance_left[kept_left] + balance_right[kept_right] = 0
        // So, balance_left[kept_left] = -balance_right[kept_right]
        int target_left_balance = -balance_right[k];

        if (left_balance_to_removed_count.count(target_left_balance)) {
            int removed_from_left = left_balance_to_removed_count[target_left_balance];
            int removed_from_right = n - k;
            min_removed_jars = std::min(min_removed_jars, removed_from_left + removed_from_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

