    // by all type 1 operations *in the entire sequence*.
    std::vector<long long> add_val(n, 0);
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                add_val[j] += op.val;
            }
        }
    }

