    // a_0[i] <= m_k - (add_val[i] - current_delta_at_op_k[i]) for all type 2 ops k
    // where i is in range [l_k, r_k].
    // current_delta_at_op_k[i] is the sum of d values from type 1 ops *before* op k.

    // Let's define `initial_a[i]` as the value we are trying to find.
    // For each type 2 operation (2, l, r, m_k), we know that for all j in [l, r]:
    // initial_a[j] + (sum of d's from type 1 ops affecting j *before* op k) <= m_k.
    // This implies initial_a[j] <= m_k - (sum of d's from type 1 ops affecting j *before* op k).
    // To maximize the chance of finding a solution, we want to make initial_a[j] as large as possible.
    // So, initial_a[j] = min_over_all_relevant_type2_ops_k (m_k - (sum of d's affecting j before op k)).

    std::vector<long long> initial_a(n, LLONG_MAX); // Initialize with a very large value

    // To calculate "sum of d's affecting j before op k" efficiently:
    // We can iterate through operations. Maintain a current_delta array.
    // current_delta[i] stores the sum of d values applied to a[i] by type 1 ops processed so far.
    std::vector<long long> current_delta(n, 0);
    std::vector<long long> diff_current_delta(n + 1, 0); // Difference array for current_delta

    for (const auto& op : ops) {
        // Apply changes from diff_current_delta to current_delta
        // This is equivalent to current_delta[j] += diff_current_delta[j] for all j
        // and then current_delta[j] += current_delta[j-1] for j > 0.
        // But we only need current_delta values for the range [op.l, op.r].
        // Let's reconstruct current_delta from diff_current_delta for the relevant range.
        // Or, more simply, just update current_delta directly.
        // No, the problem is that current_delta needs to be the *actual* sum of d's.
        // A difference array is better for applying range updates.
        // Let's use a temporary array to reconstruct current_delta for type 2 checks.

        if (op.type == 1) {
