#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::vector<char> w_chars(n, '1'); // Initialize w with all 1s

    // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
    // This is a necessary condition. We use it to set bits in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w_chars[i - x] = '0';
            }
            if (i + x < n) {
                w_chars[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it matches the rule based on our w_chars.
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w_chars[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w_chars[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch: s[i] is '1' but our w implies '0', OR s[i] is '0' but our w implies '1'.
            // The second case (s[i] is '0' but w implies '1') should not happen
            // if our logic for setting w_chars to '0' is correct and complete.
            // Specifically, if s[i] is '0', we set w[i-x] and w[i+x] to '0'.
            // So s_i_should_be_1 would be false.
            // Thus, the only mismatch possible is s[i] == '1' and !s_i_should_be_1.
            // This means s[i] is '1', but both w[i-x] and w[i+x] (if they exist) are '0'.
            // This implies no valid w exists.
            std::cout << -1 << std::endl;
            return;
        }
    }

    // If no mismatch, then w_chars is a valid reconstruction.
    for (int i = 0; i < n; ++i) {
        std::cout << w_chars[i];
    }
    std::cout << std::endl;
}

