int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    if (n < 3) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // min_r[i] stores the minimum r (0-indexed) such that s[i...r] contains a 3-AP starting at or after i.
    // If no such 3-AP exists starting at or after i, min_r[i] will be n.
    std::vector<int> min_r(n, n);

    // Iterate through all possible starting positions x for a 3-AP
    for (int x = 0; x < n; ++x) {
        // Iterate through possible values of k.
        // The maximum k is such that x + 2k < n. So 2k < n - x, k < (n - x) / 2.
        // We only need to check small k values because larger k values would mean
        // a very sparse 3-AP, which is less likely to be the "first" one.
        // The problem constraints on n (300,000) suggest that k cannot be large.
        // If k is large, say k >= 9, then x+2k is at least x+18.
        // If s[x] == s[x+k] == s[x+2k], then the substring s[x...x+2k] contains this 3-AP.
        // The rightmost index is x+2k.
        // If we find such a 3-AP, we update min_r[x] to min(min_r[x], x+2k).
        // However, the problem asks for the smallest r such that s[l...r] contains a 3-AP.
        // This means we need to find the smallest r for *any* x' >= l.
        // Let's re-evaluate the definition of min_r.
        // Let min_r_val[i] be the smallest r (0-indexed) such that s[i] = s[i+k] = s[i+2k] for some k.
        // If no such k exists for s[i], then min_r_val[i] = n.
        int current_min_r_val_for_x = n;
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                current_min_r_val_for_x = x + 2 * k;
                // Since we are looking for the smallest r for a given x,
                // and k is increasing, the first k we find gives the smallest x+2k.
                break;
            }
            // Optimization: If k becomes too large, say k > 8, then x+2k > x+16.
            // Any 3-AP with k > 8 would be "sparse".
            // If there's a 3-AP with k > 8, there must also be one with k <= 8
            // that starts at an earlier or same position and ends at an earlier or same position.
            // This is a common observation in problems involving arithmetic progressions.
            // For example, if s[i] = s[i+k] = s[i+2k], and k > 8, then the substring s[i...i+2k]
            // contains this 3-AP.
            // If we consider all possible 3-APs, the "densest" ones (small k) are more restrictive.
            // The maximum k we need to check is small.
            // For example, if k=1, s[x]s[x+1]s[x+2].
            // If k=2, s[x]s[x+2]s[x+4].
            // If k=3, s[x]s[x+3]s[x+6].
            // If k=4, s[x]s[x+4]s[x+8].
            // If k=5, s[x]s[x+5]s[x+10].
            // If k=6, s[x]s[x+6]s[x+12].
            // If k=7, s[x]s[x+7]s[x+14].
            // If k=8, s[x]s[x+8]s[x+16].
            // If k > 8, then x+2k > x+16.
            // Any 3-AP s[x]s[x+k]s[x+2k] with k > 8 implies that the substring s[x...x+2k]
            // contains this 3-AP.
            // It has been proven that if a binary string contains a 3-AP, it must contain one
            // with k <= 8. This is a known result from combinatorics on words (e.g., related to
            // avoiding arithmetic progressions).
            // So, we only need to check k from 1 to 8.
            if (k > 8) break;
        }
        min_r[x] = current_min_r_val_for_x;
    }

    // Now, min_r[i] stores the smallest r (0-indexed) such that s[i] = s[i+k] = s[i+2k] for some k.
    // We need to find the smallest r' such that s[l...r'] contains *any* 3-AP.
    // Let min_valid_r[l] be the minimum r' (0-indexed) such that the substring s[l...r']
    // contains at least one 3-AP.
    // This means there exists some x, k such that l <= x < x+2k <= r' and s[x]=s[x+k]=s[x+2k].
    // So, min_valid_r[l] = min_{x=l to n-1} (min_r[x]).
    // This can be computed efficiently by iterating backwards.
    std::vector<int> min_valid_r(n + 1, n); // min_valid_r[l] for 0-indexed l
    min_valid_r[n] = n; // Base case: no 3-AP in an empty string

    for (int l = n - 1; l >= 0; --l) {
        min_valid_r[l] = std::min(min_r[l], min_valid_r[l + 1]);
    }

    long long total_pairs = 0;
    for (int l = 0; l < n; ++l) {
        // For a given starting position l, we need to count r such that l <= r < n
        // and s[l...r] contains a 3-AP.
        // This means r must be at least min_valid_r[l].
        // If min_valid_r[l] == n, it means no 3-AP exists starting at or after l.
        // In this case, no r will satisfy the condition for this l.
        if (min_valid_r[l] < n) {
            // The valid r values are from min_valid_r[l] to n-1.
            // Number of such r values is (n - 1) - min_valid_r[l] + 1.
            total_pairs += (n - min_valid_r[l]);
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

