    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    long long total_successful_a = 0;
    long long total_sent_a = 0;
    long long total_successful_b = 0;
    long long total_sent_b = 0;

    for (int i = 0; i < n; ++i) {
        int t, x, y;
        std::cin >> t >> x >> y;
        if (t == 1) {
            total_successful_a += x;
            total_sent_a += 10;
        } else { // t == 2
            total_successful_b += x;
            total_sent_b += 10;
        }
    }

    if (2 * total_successful_a >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    if (2 * total_successful_b >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0;
}

