    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The presence of +1 or -1 doesn't matter for this specific position,
        // but it might matter for subsequent positions.
        // The has_pos_one and has_neg_one flags are updated based on a[i]
        // for future elements a[j] where j > i.
        // This is implicitly handled by the loop structure:
        // has_pos_one and has_neg_one track if a 1 or -1 has appeared
        // *before or at* the current index i.
        // So, when checking a[i], has_pos_one means there's an a[k]=1 with k < i.
        // This is correct because a[i] can only be modified by a[k] where k < i.
    }

    std::cout << "YES\n";
}

