#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell index, or -1 for cell 0.
                             // The distance from last_R_pos to the current 'R' cell
                             // must be covered by d.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // The distance from the previous 'R' cell (or 0) to this 'R' cell
                // is (i+1) - (last_R_pos + 1) + 1 = i - last_R_pos.
                // If last_R_pos was -1 (meaning we are coming from cell 0),
                // the distance is (i+1) - 0 = i+1.
                // This is equivalent to (i+1) - (last_R_pos + 1) + 1 if last_R_pos is -1,
                // then last_R_pos + 1 = 0. So (i+1) - 0 = i+1.
                // The distance is (current_cell_idx) - (previous_cell_idx).
                // current_cell_idx is i+1.
                // previous_cell_idx is last_R_pos + 1 (if last_R_pos is not -1).
                // If last_R_pos is -1, previous_cell_idx is 0.
                // So, the distance is (i+1) - (last_R_pos == -1 ? 0 : last_R_pos + 1).
                // This simplifies to (i+1) - (last_R_pos + 1) if we consider last_R_pos as -1 for cell 0.
                // The actual distance is (i+1) - (last_R_pos + 1) + 1.
                // Let's use 0-indexed positions for calculation:
                // The previous "safe" position was `last_R_pos`.
                // The current "safe" position is `i`.
                // The distance between them is `i - last_R_pos`.
                // We need to be able to jump from `last_R_pos` to `i`.
                // The required `d` must be at least `i - last_R_pos`.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // to the target cell n+1.
        // The last 'R' cell was at index `last_R_pos`.
        // The target cell is `n+1`.
        // The distance from `last_R_pos` to `n+1` is `(n+1) - (last_R_pos + 1)`.
        // This is `n - last_R_pos`.
        max_dist = std::max(max_dist, n - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1)
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // Goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value will be min(a_0 + a_1, a_0 + a_1 + h).
    // If h is large, it's likely that a_0 + a_1 is the minimum.
    // The maximum possible f value will be max(a_{n-2} + a_{n-1}, a_{n-1} + a_0 + h).
    //
    // Consider the minimum possible f value:
    // It must involve a_0.
    // If a_0 is paired with a_1 in the same group: a_0 + a_1
    // If a_0 is paired with a_1 in different groups: a_0 + a_1 + h
    // So, min_f = a_0 + a_1.
    //
    // Consider the maximum possible f value:
    // It must involve a_{n-1}.
    // If a_{n-1} is paired with a_{n-2} in the same group: a_{n-1} + a_{n-2}
    // If a_{n-1} is paired with a_0 in different groups: a_{n-1} + a_0 + h
    // So, max_f = max(a_{n-1} + a_{n-2}, a_{n-1} + a_0 + h).
    //
    // Goodness = max(a_{n-1} + a_{n-2}, a_{n-1} + a_0 + h) - (a_0 + a_1).
    //
    // This strategy works if we can always achieve a_0+a_1 as min_f and
    // max(a_{n-1}+a_{n-2}, a_{n-1}+a_0+h) as max_f.
    //
    // To achieve a_0+a_1 as min_f, a_0 and a_1 must be in the same group.
    // To achieve a_{n-1}+a_{n-2} as max_f (if it's the max), a_{n-1} and a_{n-2} must be in the same group.
    // To achieve a_{n-1}+a_0+h as max_f (if it's the max), a_{n-1} and a_0 must be in different groups.
    //
    // Let's try a specific partition:
    // Put a_0 in group 1.
    // Put a_1, ..., a_{n-1} in group 2.
    //
    // Min f:
    //   - a_0 with any other element a_j (j > 0): a_0 + a_j + h. Smallest is a_0 + a_1 + h.
    //   - a_i with a_j (i,j > 0): a_i + a_j. Smallest is a_1 + a_2.
    //   So, min_f = min(a_0 + a_1 + h, a_1 + a_2).
    //
    // Max f:
    //   - a_0 with any other element a_j (j > 0): a_0 + a_j + h. Largest is a_0 + a_{n-1} + h.
    //   - a_i with a_j (i,j > 0): a_i + a_j. Largest is a_{n-2} + a_{n-1}.
    //   So, max_f = max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1}).
    //
    // Goodness = max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1}) - min(a_0 + a_1 + h, a_1 + a_2).
    //
    // This is the "optimal" partition for the case where h is large enough to make cross-group pairs expensive.
    // The minimum value of f will be a_0 + a_1. This can be achieved if a_0 and a_1 are in the same group.
    // The maximum value of f will be max(a_{n-1} + a_{n-2}, a_{n-1} + a_0 + h).
    //
    // Let's consider two main strategies:
    // Strategy A: All elements in one group. Goodness = (a_{n-1} + a_{n-2}) - (a_0 + a_1).
    // Strategy B: Split into two groups.
    //   To minimize goodness, we want to make min_f as large as possible and max_f as small as possible.
    //   The smallest possible sum of two elements is a_0 + a_1.
    //   The largest possible sum of two elements is a_{n-1} + a_{n-2}.
    //   The smallest possible sum of two elements from different groups is a_0 + a_1 + h.
    //   The largest possible sum of two elements from different groups is a_{n-1} + a_{n-2} + h.
    //
    //   If we put a_0 in group 1 and all others in group 2:
    //   Min f: min(a_0 + a_1 + h, a_1 + a_2)
    //   Max f: max(a_0 + a_{n-1} + h, a_{n-1} + a_{n-2})
    //   Goodness = max(a_0 + a_{n-1} + h, a_{n-1} + a_{n-2}) - min(a_0 + a_1 + h, a_1 + a_2)
    //
    //   This is the partition where a_0 is in one group, and a_1...a_{n-1} are in another.
    //   Let's call this partition P_A.
    //   min_f_PA = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    //   max_f_PA = max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value);
    //   goodness_PA = max_f_PA - min_f_PA;
    //
    //   What if we put a_0, a_1 in group 1 and a_2, ..., a_{n-1} in group 2?
    //   This is not necessarily better.
    //
    //   The key observation is that the minimum possible value of f is always a_0 + a_1.
    //   This is because if a_0 and a_1 are in the same group, we get a_0 + a_1.
    //   If they are in different groups, we get a_0 + a_1 + h.
    //   So, the absolute minimum f value is a_0 + a_1.
    //
    //   The maximum possible value of f is always a_{n-1} + a_{n-2} + h.
    //   This is because if a_{n-1} and a_{n-2} are in different groups, we get a_{n-1} + a_{n-2} + h.
    //   If they are in the same group, we get a_{n-1} + a_{n-2}.
    //   The largest possible sum of two elements is a_{n-1} + a_{n-2}.
    //   The largest possible sum of two elements from different groups is a_{n-1} + a_0 + h.
    //   So, the absolute maximum f value is max(a_{n-1} + a_{n-2}, a_{n-1} + a_0 + h).
    //
    //   Let's re-evaluate the goodness for a general partition.
    //   min_f = min(min_same, min_diff)
    //   max_f = max(max_same, max_diff)
    //
    //   min_same = a_0 + a_1 (if a_0, a_1 are in the same group)
    //   min_diff = a_0 + a_1 + h (if a_0, a_1 are in different groups)
    //   So, min_f is at least a_0 + a_1.
    //
    //   max_same = a_{n-1} + a_{n-2} (if a_{n-1}, a_{n-2} are in the same group)
    //   max_diff = a_{n-1} + a_0 + h (if a_{n-1}, a_0 are in different groups)
    //   So, max_f is at least a_{n-1} + a_{n-2} or a_{n-1} + a_0 + h.
    //
    //   Consider two candidate partitions:
    //   1. All elements in group 1.
    //      min_f = elements[0].value + elements[1].value
    //      max_f = elements[n-1].value + elements[n-2].value
    //      Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //      Partition: all 1s.
    //
    //   2. elements[0] in group 1, elements[1...n-1] in group 2.
    //      min_f:
    //          - From group 2: elements[1].value + elements[2].value
    //          - From different groups: elements[0].value + elements[1].value + h
    //          So, min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //      max_f:
    //          - From group 2: elements[n-1].value + elements[n-2].value
    //          - From different groups: elements[0].value + elements[n-1].value + h
    //          So, max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //      Goodness = max_f - min_f
    //      Partition: 1 for elements[0], 2 for others.
    //
    // Let's calculate these two goodness values and pick the minimum.

    long long current_min_goodness = goodness1;
    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }

    // Calculate goodness for partition 2
    long long min_f2_val;
    if (n == 2) { // Special case for n=2, group 2 would only have one element
        // elements[0] in group 1, elements[1] in group 2
        // Only one pair: (elements[0], elements[1]) in different groups
        min_f2_val = elements[0].value + elements[1].value + h;
    } else {
        min_f2_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    }

    long long max_f2_val = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
    long long goodness2 = max_f2_val - min_f2_val;

    if (goodness2 < current_min_goodness) {
        current_min_goodness = goodness2;
        best_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    // There is one more case to consider:
    // What if elements[0] and elements[1] are in different groups, and elements[n-1] and elements[n-2] are in different groups?
    // This would mean min_f = elements[0].value + elements[1].value + h
    // and max_f = elements[n-1].value + elements[n-2].value + h
    // This is not necessarily optimal.
    //
    // The crucial insight is that the minimum possible value of f is `elements[0].value + elements[1].value`.
    // This can be achieved by putting `elements[0]` and `elements[1]` in the same group.
    // The maximum possible value of f is `elements[n-1].value + elements[n-2].value + h`.
    // This can be achieved by putting `elements[n-1]` and `elements[n-2]` in different groups.
    //
    // Let's consider the minimum possible value of f. It is `elements[0].value + elements[1].value`.
    // This is achieved if `elements[0]` and `elements[1]` are in the same group.
    //
    // Let's consider the maximum possible value of f. It is `elements[n-1].value + elements[0].value + h`.
    // This is achieved if `elements[n-1]` and `elements[0]` are in different groups.
    //
    // If we want to achieve `elements[0].value + elements[1].value` as min_f, we must put `elements[0]` and `elements[1]` in the same group.
    // If we want to achieve `elements[n-1].value + elements[0].value + h` as max_f, we must put `elements[n-1]` and `elements[0]` in different groups.
    //
    // This implies `elements[0]` is in one group, and `elements[1]` and `elements[n-1]` are in the other.
    //
    // Let's try a partition where `elements[0]` is in group 1, and all other elements `elements[1]...elements[n-1]` are in group 2.
    // This is exactly partition 2 we already calculated.
    //
    // What if `elements[0]` and `elements[1]` are in group 1, and `elements[2]...elements[n-1]` are in group 2?
    // Min f:
    //   - From group 1: elements[0].value + elements[1].value
    //   - From group 2: elements[2].value + elements[3].value (if n >= 4)
    //   - From different groups: elements[0].value + elements[2].value + h
    //   So, min_f = elements[0].value + elements[1].value (always the smallest possible)
    // Max f:
    //   - From group 1: elements[0].value + elements[1].value
    //   - From group 2: elements[n-1].value + elements[n-2].value (if n >= 4)
    //   - From different groups: elements[1].value + elements[n-1].value + h
    //   So, max_f = max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h)
    //   Goodness = max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h) - (elements[0].value + elements[1].value)
    //
    // Let's call this partition P_C.
    // This partition puts elements[0] and elements[1] in group 1, and the rest in group 2.
    // This ensures elements[0]+elements[1] is the minimum.
    // The maximum will be max(elements[n-1]+elements[n-2], elements[1]+elements[n-1]+h).
    //
    // This is the third candidate.
    // min_f_PC = elements[0].value + elements[1].value;
    // long long max_f_PC;
    // if (n == 2) { // elements[0], elements[1] in group 1. Group 2 is empty.
    //     max_f_PC = elements[0].value + elements[1].value;
    // } else {
    //     max_f_PC = std::max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h);
    // }
    //
    // The logic for max_f_PC needs to be careful.
    // If n=2, elements[0], elements[1] are in group 1. No elements in group 2. No cross-group pairs.
    // max_f_PC = elements[0].value + elements[1].value.
    // This is the same as goodness1 for n=2.
    //
    // If n=3, elements[0], elements[1] in group 1. elements[2] in group 2.
    // Pairs:
    //   Same group: (elements[0], elements[1]) -> elements[0]+elements[1]
    //   Diff group: (elements[0], elements[2]) -> elements[0]+elements[2]+h
    //               (elements[1], elements[2]) -> elements[1]+elements[2]+h
    // min_f_PC = elements[0].value + elements[1].value
    // max_f_PC = elements[1].value + elements[2].value + h
    // Goodness = (elements[1].value + elements[2].value + h) - (elements[0].value + elements[1].value)
    //
    // If n >= 3:
    // min_f_PC = elements[0].value + elements[1].value;
    // max_f_PC = std::max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h);
    // long long goodness_PC = max_f_PC - min_f_PC;
    //
    // This is the third candidate.
    //
    // Let's re-evaluate the three candidates:
    // Candidate 1: All in group 1.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-1].value + elements[n-2].value
    //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //   Partition: all 1s.
    //
    // Candidate 2: elements[0] in group 1, elements[1...n-1] in group 2.
    //   min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) (if n >= 3)
    //           elements[0].value + elements[1].value + h (if n == 2)
    //   max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h) (if n >= 3)
    //           elements[0].value + elements[1].value + h (if n == 2)
    //   Goodness = max_f - min_f
    //   Partition: elements[0] is 1, others are 2.
    //
    // Candidate 3: elements[0], elements[1] in group 1, elements[2...n-1] in group 2.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = std::max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h) (if n >= 3)
    //           elements[0].value + elements[1].value (if n == 2, group 2 is empty)
    //   Goodness = max_f - min_f
    //   Partition: elements[0], elements[1] are 1, others are 2.

    // Re-calculate goodness1 (all 1s)
    current_min_goodness = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }

    // Calculate goodness for Candidate 2
    if (n >= 2) { // This partition is valid for n >= 2
        long long min_f_cand2;
        if (n == 2) {
            min_f_cand2 = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            min_f_cand2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        }
        long long max_f_cand2 = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
        long long goodness_cand2 = max_f_cand2 - min_f_cand2;

        if (goodness_cand2 < current_min_goodness) {
            current_min_goodness = goodness_cand2;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Calculate goodness for Candidate 3
    if (n >= 3) { // This partition is valid for n >= 3
        long long min_f_cand3 = elements[0].value + elements[1].value;
        long long max_f_cand3 = std::max(elements[n - 1].value + elements[n - 2].value, elements[1].value + elements[n - 1].value + h);
        long long goodness_cand3 = max_f_cand3 - min_f_cand3;

        if (goodness_cand3 < current_min_goodness) {
            current_min_goodness = goodness_cand3;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << current_min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_price_from_right = a[n - 1]; // Initialize with the last price

    // Iterate from the second to last element to the first
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_price_from_right) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_price_from_right,
            // it means a[i] is a new minimum or equal to the current minimum.
            // Update min_price_from_right to be the minimum of itself and a[i].
            // This is equivalent to min_price_from_right = std::min(min_price_from_right, a[i]);
            // but we only need to update if a[i] is smaller.
            min_price_from_right = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

