int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If n is the maximum possible value in the permutation,
        // then for p_i = n, max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j = n-1.
        // If p_i < n, then max_{j!=i} min(p_i, p_j) could be p_i or some other p_j.
        // Specifically, if p_i is not n, then there must be some p_k = n.
        // Then min(p_i, p_k) = p_i.
        // So max_{j!=i} min(p_i, p_j) >= p_i.
        // If p_i is not n, then max_{j!=i} min(p_i, p_j) can be p_i or some other value.
        // The key insight is that if p_i is not n, then there is some p_k = n.
        // Then a[i][k] = min(p_i, p_k) = min(p_i, n) = p_i.
        // So max_{j!=i} a[i][j] must be at least p_i.
        // If max_{j!=i} a[i][j] is exactly p_i, it means p_i is the largest value
        // among all min(p_i, p_j) for j!=i.
        // This implies that for all j!=i, p_j >= p_i.
        // This can only happen if p_i is the smallest value in the permutation, which is 1.
        // But if p_i = 1, then max_{j!=i} min(1, p_j) = 1.
        // So if max_val_in_row == p_i, then p_i must be 1.
        //
        // The logic for determining p_i:
        // If p_i = n, then max_{j!=i} a[i][j] = n-1.
        // If p_i < n, then max_{j!=i} a[i][j] >= p_i.
        //
        // The problem states that p is a permutation of 1 to n.
        // The maximum possible value for any p_i is n.
        // The maximum value in any row `i` (excluding `a[i][i]`) is `max_{j!=i} min(p_i, p_j)`.
        // This value can be at most `n-1` (if `p_i = n`) or `p_i` (if `p_i < n` and `p_i` is the largest among `min(p_i, p_j)`).
        //
        // If `max_val_in_row` is `n-1`, it means `p_i` must be `n`.
        // Why? If `p_i < n`, then `max_{j!=i} min(p_i, p_j)` would be at most `p_i`, which is less than `n-1`.
        // So, if `max_val_in_row == n-1`, then `p_i = n`.
        // Otherwise, `p_i` must be `max_val_in_row`.
        // This is because if `p_i < n`, then there exists some `p_k = n`.
        // Then `a[i][k] = min(p_i, p_k) = min(p_i, n) = p_i`.
        // So `max_val_in_row` must be at least `p_i`.
        // If `max_val_in_row > p_i`, it means there is some `p_j` such that `min(p_i, p_j) > p_i`, which is impossible.
        // Therefore, if `p_i < n`, then `max_val_in_row` must be exactly `p_i`.
        //
        // Combining these:
        // If `max_val_in_row == n-1`, then `p_i = n`.
        // Else (`max_val_in_row < n-1`), then `p_i = max_val_in_row`.
        // This covers all cases.
        // Example: n=2.
        // Row 0: max_val_in_row = a[0][1]. If a[0][1] = 1 (which is n-1), then p[0]=2.
        // Row 1: max_val_in_row = a[1][0]. If a[1][0] = 1 (which is n-1), then p[1]=2.
        // This means if a[0][1]=1, p[0]=2. If a[1][0]=1, p[1]=2.
        // But only one can be 2.
        //
        // The logic should be:
        // For each i, calculate M_i = max_{j!=i} a[i][j].
        // If M_i = n-1, then p_i = n.
        // Otherwise, p_i = M_i.
        // This works because if p_i < n, then there is some p_k = n.
        // Then a[i][k] = min(p_i, n) = p_i.
        // So M_i = max_{j!=i} min(p_i, p_j) >= p_i.
        // Also, min(p_i, p_j) <= p_i for all j.
        // So M_i <= p_i.
        // Thus, if p_i < n, then M_i = p_i.
        // If p_i = n, then M_i = max_{j!=i} min(n, p_j) = max_{j!=i} p_j = n-1.
        //
        // So, the rule is:
        // if max_val_in_row == n-1, then p[i] = n.
        // else, p[i] = max_val_in_row.

        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

