void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::vector<std::string> result(4);

    long long total_toys = a + b + c + d;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Box 1: (-inf, -1]
    // Final toy in Box 1 means its value is <= -1.
    // This requires an odd number of negative factors and magnitude >= 1.
    // The number of negative factors is (A + B).
    // If (A+B) is odd, the final sign is negative.
    // If (A+B) is even, the final sign is positive.

    // Case 1: Final toy in Box 1 (value <= -1)
    // Requires odd number of negative factors (A+B is odd).
    // Requires magnitude >= 1.
    // Magnitude >= 1 is possible if:
    //   - There's at least one toy from Box 1 or Box 4 (A+D > 0).
    //   - Or, if A+D=0, then B+C must be > 0. If B+C > 0, we can make magnitude >= 1 if we have enough factors.
    //     Specifically, if A+D=0, all initial toys are in Box 2 or Box 3.
    //     Multiplying values in (-1,0) and (0,1) always results in a value in (-1,1).
    //     So, if A+D=0, the magnitude will always be < 1.
    //     Therefore, for magnitude >= 1, we must have A+D > 0.

    bool can_be_box1 = false;
    if ((a + b) % 2 != 0) { // Odd number of negative factors
        if (a + d > 0) { // At least one toy with magnitude >= 1
            can_be_box1 = true;
        } else if (a + b + c + d == 1 && a == 1) { // Single toy in Box 1
            can_be_box1 = true;
        }
    } else if (total_toys == 1 && a == 1) { // Single toy in Box 1
        can_be_box1 = true;
    }
    result[0] = can_be_box1 ? "Ya" : "Tidak";

    // Case 2: Final toy in Box 2 (-1, 0)
    // Requires odd number of negative factors (A+B is odd).
    // Requires magnitude < 1.
    // Magnitude < 1 is always possible if there's at least one toy from Box 2 or Box 3 (B+C > 0).
    // If B+C=0, then all toys are in Box 1 or Box 4.
    // Multiplying values from Box 1 and Box 4 always results in magnitude >= 1.
    // So, if B+C=0, magnitude will always be >= 1.
    // Therefore, for magnitude < 1, we must have B+C > 0.

    bool can_be_box2 = false;
    if ((a + b) % 2 != 0) { // Odd number of negative factors
        if (b + c > 0) { // At least one toy with magnitude < 1
            can_be_box2 = true;
        } else if (total_toys == 1 && b == 1) { // Single toy in Box 2
            can_be_box2 = true;
        }
    } else if (total_toys == 1 && b == 1) { // Single toy in Box 2
        can_be_box2 = true;
    }
    result[1] = can_be_box2 ? "Ya" : "Tidak";

    // Case 3: Final toy in Box 3 (0, 1)
    // Requires even number of negative factors (A+B is even).
    // Requires magnitude < 1.
    // For magnitude < 1, we must have B+C > 0 (same logic as Box 2).

    bool can_be_box3 = false;
    if ((a + b) % 2 == 0) { // Even number of negative factors
        if (b + c > 0) { // At least one toy with magnitude < 1
            can_be_box3 = true;
        } else if (total_toys == 1 && c == 1) { // Single toy in Box 3
            can_be_box3 = true;
        }
    } else if (total_toys == 1 && c == 1) { // Single toy in Box 3
        can_be_box3 = true;
    }
    result[2] = can_be_box3 ? "Ya" : "Tidak";

    // Case 4: Final toy in Box 4 [1, inf)
    // Requires even number of negative factors (A+B is even).
    // Requires magnitude >= 1.
    // For magnitude >= 1, we must have A+D > 0 (same logic as Box 1).

    bool can_be_box4 = false;
    if ((a + b) % 2 == 0) { // Even number of negative factors
        if (a + d > 0) { // At least one toy with magnitude >= 1
            can_be_box4 = true;
        } else if (total_toys == 1 && d == 1) { // Single toy in Box 4
            can_be_box4 = true;
        }
    } else if (total_toys == 1 && d == 1) { // Single toy in Box 4
        can_be_box4 = true;
    }
    result[3] = can_be_box4 ? "Ya" : "Tidak";

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
}

