#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate max_left_len
    // max_left_len is the maximum length L such that a[0], ..., a[L-1] can be made into 0, 1, ..., L-1
    int max_left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_left_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate max_right_len
    // max_right_len is the maximum length R such that a[n-R], ..., a[n-1] can be made into R-1, ..., 1, 0
    int max_right_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[n - 1 - i] >= i) {
            max_right_len = i + 1;
        } else {
            break;
        }
    }

    // A sharpened array requires a peak k.
    // The left part a_1, ..., a_k must be strictly increasing.
    // The right part a_k, ..., a_n must be strictly decreasing.
    // The peak k must be part of both the increasing prefix and decreasing suffix.
    // This means the increasing prefix must reach at least index k-1 (0-indexed).
    // And the decreasing suffix must start at index k-1 (0-indexed).
    // The length of the increasing prefix is k.
    // The length of the decreasing suffix is n - k + 1.
    // The total length covered by the increasing prefix and decreasing suffix must be at least n.
    // The peak element is counted in both.
    // So, max_left_len + max_right_len - 1 >= n is the condition.
    // If max_left_len + max_right_len > n, it means there's an overlap of at least one element.
    // This overlap element can be the peak.
    // For example, if n=3, max_left_len=2, max_right_len=2.
    // Left can be 0,1. Right can be 1,0.
    // Possible peaks:
    // k=1 (0-indexed): a[0] is peak. Left part is a[0]. Right part is a[0], a[1], a[2].
    //   Requires a[0] >= 0. a[0] > a[1] > a[2].
    //   This means max_left_len >= 1 and max_right_len >= n.
    // k=n-1 (0-indexed): a[n-1] is peak. Left part is a[0], ..., a[n-1]. Right part is a[n-1].
    //   Requires a[n-1] >= 0. a[0] < ... < a[n-1].
    //   This means max_left_len >= n and max_right_len >= 1.
    // For any k, we need max_left_len >= k and max_right_len >= n - k + 1.
    // Summing these: max_left_len + max_right_len >= n + 1.
    // This is the condition for existence of such a k.

    if (max_left_len + max_right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

