void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Expand the window to include 'm'
        // The current window [current_min_idx, current_max_idx] contains 1, ..., m-1
        // We need to include 'm'
        // The position of 'm' is pos[m]

        // Update the window boundaries to cover all numbers from 1 to m
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current window [current_min_idx, current_max_idx]
        // forms a permutation of 1, ..., m
        // This means its length must be exactly m
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

