// Function to convert a long long integer to its 18-digit parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to ensure length 18
    while (pattern.length() < 18) {
        pattern += '0';
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get correct order (most significant first)
    return pattern;
}

