int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, a_i up to 100. n*a_i can be 100*100 = 10000.
                     // d is days, not total haybales.
                     // The problem states d <= 100. So long long for d is not strictly necessary, but harmless.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long remaining_days = d;

        for (int i = 1; i < n; ++i) { // Iterate from pile 2 (index 1) to pile n
            if (remaining_days <= 0) {
                break; // No more days left to move haybales
            }

            long long pile_index = i; // 0-indexed pile_index
            long long cost_per_haybale = pile_index; // Days to move one haybale from pile i+1 to pile 1

            if (cost_per_haybale == 0) { // This should only happen for pile 1 itself, which is skipped
                continue;
            }

            long long haybales_in_pile = a[i];

            // Calculate how many haybales can be moved from this pile
            // based on remaining days and cost per haybale
            long long max_haybales_to_move_from_this_pile = remaining_days / cost_per_haybale;

            // The actual number of haybales moved is limited by what's available in the pile
            long long haybales_moved = std::min(haybales_in_pile, max_haybales_to_move_from_this_pile);

            current_a1 += haybales_moved;
            remaining_days -= haybales_moved * cost_per_haybale;
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

