#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: if N=2, taking 1 is better than taking N/2=1
                    chanek_score += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // Taking 1 leaves an odd number for opponent.
                    // This is the tricky part.
                    // If N/2 is odd, then N must be 2 * (odd number).
                    // Example: N=6, N/2=3 (odd).
                    // Option 1: Take 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Total Chanek: 1+2+1=4.
                    // Option 2: Take N/2=3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Total Chanek: 3+1=4.
                    // In this specific case, taking N/2 is optimal if N/2 is odd and N > 2.
                    // The logic is that if N/2 is odd, the opponent will be forced to take 1, leaving an even number for Chanek.
                    // If Chanek takes 1, N-1 is odd, opponent takes 1, N-2 is even.
                    // The key is that if N/2 is odd, then N is of the form 2 * (2k+1).
                    // If Chanek takes N/2, he gets N/2. Remaining N/2 (odd). Opponent takes 1. Remaining N/2-1 (even).
                    // If Chanek takes 1, he gets 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                    // Comparing N/2 vs 1. N/2 is always better for N > 2.
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leaves an even number for opponent.
                    // Opponent can then take N/4. This is bad for Chanek.
                    // So Chanek should take 1.
                    chanek_score += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if (n == 2) {
                    n -= 1; // Opponent takes 1
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    n /= 2; // Opponent takes N/2
                } else { // N/2 is even
                    n -= 1; // Opponent takes 1
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

