// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // This means we need to remove some prime factors from p such that the resulting number
        // is no longer divisible by q, but is as large as possible.

        // Get prime factors of q.
        // For each prime factor pf of q, we will try to remove enough pf's from p
        // such that p / (pf^k) is no longer divisible by q.
        // The largest such p / (pf^k) will be our answer.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        for (long long pf : q_prime_factors) {
            long long current_p = p;
            // Count how many times pf divides q
            long long q_pf_count = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % pf == 0) {
                q_pf_count++;
                temp_q /= pf;
            }

            // Count how many times pf divides p
            long long p_pf_count = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % pf == 0) {
                p_pf_count++;
                temp_p /= pf;
            }

            // We need to remove enough factors of pf from p such that the count of pf in p
            // becomes less than the count of pf in q.
            // Specifically, we need to reduce p_pf_count to q_pf_count - 1.
            // This means we need to divide p by pf^(p_pf_count - (q_pf_count - 1))
            // which simplifies to p / pf^(p_pf_count - q_pf_count + 1)

            long long num_to_divide = p_pf_count - q_pf_count + 1;

            for (int i = 0; i < num_to_divide; ++i) {
                current_p /= pf;
            }

            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

