void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w_cand(n, '1'); // Initialize w_cand with all '1's

    // If s[i] is '0', then both w[i-x] and w[i+x] must be '0' (if they exist).
    // This is a definitive constraint.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w_cand[i - x] = '0';
            }
            if (i + x < n) {
                w_cand[i + x] = '0';
            }
        }
    }

    // Now, verify if this w_cand can produce the given s.
    // Construct a new string s_prime based on w_cand and x.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w_cand[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w_cand[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the original s.
    if (s_prime == s) {
        std::cout << w_cand << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

