int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is total_sum - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for extra items from left or right
        if (i > j) { // More items taken from left
            int diff = i - j;
            // If diff is 1, it means i = j+1. The last item taken was from left.
            // No extra penalty if diff is 1.
            // If diff is 2, it means i = j+2. The last two items taken were from left.
            // One extra penalty Ql.
            // In general, if diff = k, then k-1 extra penalties Ql.
            current_energy += (diff - 1) * Ql;
        } else if (j > i) { // More items taken from right
            int diff = j - i;
            // Similar logic for Qr
            current_energy += (diff - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
