struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[i] = a[i].value;
            y[i] = b[n - 1 - i].value;
        }

        // The problem statement's example output for the second test case
        // suggests that sorting one ascending and the other descending is a valid strategy.
        // Let's re-check the example:
        // a = [1, 7, 5] -> sorted a = [1, 5, 7]
        // b = [6, 1, 2] -> sorted b = [1, 2, 6]
        //
        // If a is sorted ascending and b is sorted descending:
        // a_sorted = [1, 5, 7]
        // b_sorted_desc = [6, 2, 1]
        //
        // Pairs:
        // (1, 6) sum = 7
        // (5, 2) sum = 7
        // (7, 1) sum = 8
        // This results in duplicate sums (7, 7, 8), which is invalid.
        //
        // The example output for the second test case is:
        // x = [5, 1, 7]
        // y = [6, 2, 1]
        // Sums: 5+6=11, 1+2=3, 7+1=8. These are distinct.
        //
        // Let's analyze the example output:
        // Original a: [1, 7, 5]
        // Original b: [6, 1, 2]
        //
        // x = [5, 1, 7] -> This is a permutation of a.
        // y = [6, 2, 1] -> This is a permutation of b.
        //
        // How can we get this?
        // If we sort both a and b in ascending order:
        // a_sorted = [1, 5, 7]
        // b_sorted = [1, 2, 6]
        //
        // If we pair a_sorted[i] with b_sorted[i]:
        // (1, 1) sum = 2
        // (5, 2) sum = 7
        // (7, 6) sum = 13
        // These sums are distinct. This is a valid solution.
        //
        // The problem states "If there are multiple possible answers, you may print any of them."
        // So, sorting both in ascending order and pairing a_i with b_i should work.

        for (int i = 0; i < n; ++i) {
            x[i] = a[i].value;
            y[i] = b[i].value;
        }

