#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation always has the same fingerprint.
    // If the original permutation is not a palindrome, its reverse will be different.
    // The problem statement guarantees a solution exists, and for n >= 2,
    // a permutation is a palindrome only if p_i = p_{n-i+1}.
    // For n=2, p=[1,2], p_rev=[2,1]. They are different.
    // For n > 2, it's highly unlikely for a random permutation to be a palindrome.
    // Even if it were a palindrome, the problem guarantees a solution exists.
    // The simplest approach is to just output the reverse.
    // The problem statement implies that p_rev will always be different from p
    // for the test cases where a solution is required.
    // For example, if p = [1,2,3,4,5], p_rev = [5,4,3,2,1].
    // If p = [1,2,1] (not a permutation), then p_rev = [1,2,1].
    // But p is guaranteed to be a permutation of distinct integers from 1 to n.
    // A permutation p is a palindrome if p_i = p_{n-i+1} for all i.
    // For n=2, p=[1,2], p_rev=[2,1]. Different.
    // For n=3, p=[1,2,3], p_rev=[3,2,1]. Different.
    // For n=4, p=[1,2,3,4], p_rev=[4,3,2,1]. Different.
    // In general, for a permutation of distinct elements, p_i = p_{n-i+1} for all i
    // implies that the sequence is symmetric.
    // For example, if n=5, p=[1,2,3,2,1] is a palindrome, but not a permutation
    // because 2 and 1 appear twice.
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
    // If n is odd, say n=2k+1, then p_k+1 must be unique.
    // If n is even, say n=2k, then p_i = p_{n-i+1} means elements come in pairs.
    // For example, p_1=p_n, p_2=p_{n-1}, etc.
    // But all elements must be distinct. So p_1 cannot be equal to p_n unless n=1.
    // Therefore, for n >= 2, p_i != p_{n-i+1} for at least one i (specifically i=1).
    // This means p_rev will always be different from p.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

