    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        p[i] = s[i] - '0';
    }

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::vector<int> colors(n);
        int last1 = -1;
        int last2 = -1;
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            if (p[i] < pivot_digit) {
                // Must be color 1
                if (p[i] < last1) {
                    possible = false;
                    break;
                }
                colors[i] = 1;
                last1 = p[i];
            } else if (p[i] > pivot_digit) {
                // Must be color 2
                if (p[i] < last2) {
                    possible = false;
                    break;
                }
                colors[i] = 2;
                last2 = p[i];
            } else { // p[i] == pivot_digit
                // Can be color 1 or color 2
                // Prefer color 2 if possible, to keep color 1 sequence shorter
                // and allow more digits for color 1 later.
                // This is equivalent to assigning to color 2 if last2 <= p[i]
                // and assigning to color 1 if last1 <= p[i]
                // If both are possible, assign to color 2.
                // If only color 1 is possible, assign to color 1.
                // If only color 2 is possible, assign to color 2.
                // If neither is possible, then impossible.

                bool can_be_1 = (p[i] >= last1);
                bool can_be_2 = (p[i] >= last2);

                if (can_be_2) {
                    colors[i] = 2;
                    last2 = p[i];
                } else if (can_be_1) {
                    colors[i] = 1;
                    last1 = p[i];
                } else {
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

