int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, a_i up to 100.
                     // (i-1) can be up to 99.
                     // d / (i-1) can be 100 / 1 = 100.
                     // a_1 can increase by sum of these, max 100 * 100 = 10000.
                     // Initial a_1 is 100. So a_1 can be 10100.
                     // long long for d is not strictly necessary based on constraints,
                     // but good practice for day counts if they were larger.
                     // int is fine for d.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];

        for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
            int pile_idx = i + 1; // Convert 0-indexed i to 1-indexed pile number
            long long cost_per_haybale = i; // Days to move from pile (i+1) to pile 1 is i
                                            // (e.g., pile 2 (idx 1) costs 1 day, pile 3 (idx 2) costs 2 days)

            if (cost_per_haybale > d) {
                // If even one haybale from this pile costs more days than available,
                // we can't move any haybales from this pile or any further piles.
                break;
            }

            long long haybales_in_pile = a[i];
            long long max_haybales_to_move = d / cost_per_haybale;

            long long actual_haybales_moved = std::min(haybales_in_pile, max_haybales_to_move);

            current_a1 += actual_haybales_moved;
            d -= actual_haybales_moved * cost_per_haybale;
        }
        std::cout << current_a1 << "\n";
    }
    return 0;
}

