int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char t0_char = s[k_actual];

        const std::vector<int>& possible_k_for_t0 = char_indices[t0_char - 'a'];

        if (possible_k_for_t0.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        int max_unique_count = 0;

        // Iterate over all possible positions p (1 to N-1) for the second character
        for (int p = 1; p < n; ++p) {
            std::map<std::pair<char, char>, int> counts;
            for (int k_cand : possible_k_for_t0) {
                char t0_cand = s[k_cand];
                char tp_cand = s[(k_cand + p) % n];
                counts[{t0_cand, tp_cand}]++;
            }

            int current_unique_count = 0;
            for (auto const& [pair_val, count] : counts) {
                if (count == 1) {
                    current_unique_count++;
                }
            }
            max_unique_count = std::max(max_unique_count, current_unique_count);
        }
        total_win_prob += static_cast<double>(max_unique_count) / possible_k_for_t0.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
