    }

    // Check if any p[i] is equal to n. If not, it means n is not present in any min(p_i, p_j)
    // which implies n must be the value of some p_k where p_k is greater than all other p_j
    // it's compared with. In this case, max_val_in_row for that p_k would be n-1.
    // If n is not found in p, then one of the p[i] values must be n.
    // The one that should be n is the one whose current value is n-1, and all other p[j] are less than n-1.
    // Or more simply, if n is not present in the current p, then the largest value in p must be n-1,
    // and that element should be n.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        int max_p_val = 0;
        int max_p_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (p[i] > max_p_val) {
                max_p_val = p[i];
                max_p_idx = i;
            }
        }
        // If n is not found, it means the largest value in p is n-1.
        // This largest value must correspond to the element that should be n.
        // So, we increment it.
        p[max_p_idx] = n;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

