int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - last_r_pos
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or 0 if no 'R's)
        // to the target cell n+1.
        // The distance is (n+1) - last_r_pos
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: SumR = (b-1) * b / 2
    // Since b-1 or b might be even, one of them is divisible by 2.
    // We need to perform division by 2 carefully under modulo.
    // (b-1) * b / 2 mod MOD
    long long sum_r_term = (b - 1);
    long long sum_r_term_mult = b;

    long long sum_r_val;
    if (sum_r_term_mult % 2 == 0) {
        sum_r_val = (sum_r_term % MOD * (sum_r_term_mult / 2 % MOD)) % MOD;
    } else {
        sum_r_val = (sum_r_term / 2 % MOD * (sum_r_term_mult % MOD)) % MOD;
    }

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} (1)
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_kb_plus_1_val;
    long long sum_k_term = a;
    long long sum_k_term_mult = (a + 1);

    long long sum_k_val;
    if (sum_k_term_mult % 2 == 0) {
        sum_k_val = (sum_k_term % MOD * (sum_k_term_mult / 2 % MOD)) % MOD;
    } else {
        sum_k_val = (sum_k_term / 2 % MOD * (sum_k_term_mult % MOD)) % MOD;
    }

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = a % MOD;
    sum_kb_plus_1_val = (term1 + term2) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

