#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we'll use to generate k distinct differences

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left++;
        } else {
            p[i] = right--;
        }
    }

    // The remaining numbers are just appended in increasing order
    // starting from the last number used (either left or right, whichever is greater)
    // or simply continuing the sequence from the last number used.
    // The differences generated by these appended numbers will be 1,
    // which is already among the k distinct differences (unless k=0, but k>=1).
    // The last number used in the alternating sequence is either left-1 or right+1.
    // The next number to append is left (if right was used last) or right (if left was used last).
    // In either case, the numbers from left to right (inclusive) are the ones not yet used.
    // Since we used numbers from 1 to k+1, and left and right pointers crossed or met,
    // the remaining numbers are those that were not picked by the alternating strategy.
    // The alternating strategy uses numbers from 1 up to k+1.
    // So, the remaining numbers are k+2, k+3, ..., n.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

