        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant >= 0, so sqrt is real.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a and b must be non-negative.
            // Since d >= 4, d + sqrt_discriminant is positive.
            // For b1, d - sqrt_discriminant:
            // We know d^2 - 4d >= 0 => d^2 >= 4d.
            // Since d >= 4, d is positive, so we can take sqrt:
            // sqrt(d^2) >= sqrt(4d) => d >= 2*sqrt(d).
            // This means d - 2*sqrt(d) >= 0.
            // The term d - sqrt(d^2 - 4d) is always non-negative for d >= 4.
            // Proof: We need to show d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, both a1 and b1 are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <algorithm>
