void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::vector<std::string> result(4, "Tidak");

    long long total_toys = a + b + c + d;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Final toy in Box 1 (value <= -1)
    // This requires an odd number of negative factors and magnitude >= 1.
    // The number of negative factors is (A + B) initially.
    // Each multiplication of two negatives results in a positive.
    // Each multiplication of a negative and a positive results in a negative.
    // So, the parity of negative factors (A+B) determines the sign of the final product.
    // If (A+B) is odd, the final product is negative.
    // If (A+B) is even, the final product is positive.

    // For Box 1 (negative, magnitude >= 1):
    // Need (A+B) to be odd.
    // Need to be able to achieve magnitude >= 1.
    // If A > 0, we have at least one toy with value <= -1.
    // If D > 0, we have at least one toy with value >= 1.
    // If C > 0, we have at least one toy with value in (0,1).
    // If B > 0, we have at least one toy with value in (-1,0).

    // Can Box 1 be the special box?
    // Condition 1: Final product must be negative. This means (A+B) must be odd.
    // Condition 2: Final product must have magnitude >= 1.
    // To achieve magnitude >= 1, we need at least one toy from Box 1 or Box 4,
    // OR we need to multiply enough toys from Box 2/3 to get magnitude >= 1.
    // However, if we have only toys from Box 2 and Box 3, the magnitude will always be < 1.
    // So, to get magnitude >= 1, we must have at least one toy from Box 1 or Box 4 initially.
    // Exception: If total_toys = 1 and that toy is in Box 1, then it's possible.
    // If total_toys = 1, and A=1, B=C=D=0, then Box 1 is the special box.
    // If total_toys = 1, and D=1, B=C=A=0, then Box 4 is the special box.
    // If total_toys = 1, and B=1, A=C=D=0, then Box 2 is the special box.
    // If total_toys = 1, and C=1, A=B=D=0, then Box 3 is the special box.

    // Let's handle total_toys = 1 first.
    if (total_toys == 1) {
        if (a == 1) result[0] = "Ya";
        if (b == 1) result[1] = "Ya";
        if (c == 1) result[2] = "Ya";
        if (d == 1) result[3] = "Ya";
    } else {
        // General case for total_toys > 1
        // Box 1: Negative, magnitude >= 1
        // Requires (A+B) to be odd.
        // Requires (A+D > 0) OR (A+B+C+D >= 2 and (A+B+C+D - (B+C)) >= 1)
        // More simply, to get magnitude >= 1, we need at least one initial toy from Box 1 or Box 4.
        // If A+D > 0, we have at least one "large" magnitude toy.
        // If A+D == 0, all initial toys are from Box 2 or Box 3. Their product will always have magnitude < 1.
        if ((a + b) % 2 != 0 && (a + d > 0)) {
            result[0] = "Ya";
        }

        // Box 2: Negative, magnitude < 1
        // Requires (A+B) to be odd.
        // Requires magnitude < 1.
        // This is possible if:
        // 1. All initial toys are from Box 2 or Box 3 (A+D == 0). In this case, magnitude is always < 1.
        // 2. We have some "large" magnitude toys (A+D > 0), but we can arrange multiplications
        //    such that the final magnitude is < 1. This is always possible if we have at least one toy from Box 2 or Box 3.
        //    E.g., multiply a large value by a small value.
        //    If A+D > 0, and B+C > 0, we can always make magnitude < 1.
        //    If A+D > 0, and B+C == 0, then all toys are from Box 1 or Box 4. Their product will always have magnitude >= 1.
        // So, for Box 2: (A+B) is odd AND (A+D == 0 OR B+C > 0).
        if ((a + b) % 2 != 0 && (a + d == 0 || b + c > 0)) {
            result[1] = "Ya";
        }

        // Box 3: Positive, magnitude < 1
        // Requires (A+B) to be even.
        // Requires magnitude < 1.
        // Similar logic to Box 2 for magnitude: (A+D == 0 OR B+C > 0).
        if ((a + b) % 2 == 0 && (a + d == 0 || b + c > 0)) {
            result[2] = "Ya";
        }

        // Box 4: Positive, magnitude >= 1
        // Requires (A+B) to be even.
        // Requires magnitude >= 1.
        // Similar logic to Box 1 for magnitude: (A+D > 0).
        if ((a + b) % 2 == 0 && (a + d > 0)) {
            result[3] = "Ya";
        }
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
}

