void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, such that a_j >= j for j <= i.
    // This is equivalent to a_j >= j-1 for 0-indexed j.
    // Or, a_j >= j for 0-indexed j, if we consider the values relative to their index.
    // Let's define `left_reach[i]` as the maximum `k` such that `a_i` can be the `k`-th element
    // in a strictly increasing sequence starting from 0.
    // i.e., `0 < 1 < ... < k-1 < k`
    // So, `a_j` must be at least `j` for `0 <= j < k`.
    // `a_0` must be at least `0`.
    // `a_1` must be at least `1`.
    // `a_i` must be at least `i`.
    // This is `a_i >= i`.
    // If `a_i < i`, then it's impossible to form a prefix of length `i+1` (0 to i)
    // where `a_j` is at least `j`.
    // `left_possible[i]` is true if `a_i` can be made `i` (or more) and `a_0` can be made `0`, ..., `a_{i-1}` can be made `i-1`.
    // This means `a_j >= j` for all `0 <= j <= i`.
    std::vector<bool> left_possible(n);
    left_possible[0] = (a[0] >= 0);
    for (int i = 1; i < n; ++i) {
        left_possible[i] = (a[i] >= i) && left_possible[i-1];
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, such that a_j >= n-1-j for j >= i.
    // This is equivalent to a_j >= (n-1)-j for 0-indexed j.
    // `a_{n-1}` must be at least `0`.
    // `a_{n-2}` must be at least `1`.
    // `a_i` must be at least `n-1-i`.
    // `right_possible[i]` is true if `a_i` can be made `n-1-i` (or more) and `a_{n-1}` can be made `0`, ..., `a_{i+1}` can be made `n-1-(i+1)`.
    // This means `a_j >= n-1-j` for all `i <= j <= n-1`.
    std::vector<bool> right_possible(n);
    right_possible[n-1] = (a[n-1] >= 0);
    for (int i = n - 2; i >= 0; --i) {
        right_possible[i] = (a[i] >= (n - 1 - i)) && right_possible[i+1];
    }

    // Check if there exists a peak `k` (0-indexed) such that
    // the prefix `0...k` can be made strictly increasing (0, 1, ..., k)
    // AND the suffix `k...n-1` can be made strictly decreasing (k, k-1, ..., 0)
    // The condition for `a_k` is that it must be able to be made `k` AND `n-1-k`.
    // This means `a_k >= k` AND `a_k >= n-1-k`.
    // The `left_possible[k]` already checks `a_j >= j` for `j <= k`.
    // The `right_possible[k]` already checks `a_j >= n-1-j` for `j >= k`.
    // So we just need to find if there's any `k` where both are true.
    bool found = false;
    for (int k = 0; k < n; ++k) {
        if (left_possible[k] && right_possible[k]) {
            found = true;
            break;
        }
    }

    if (found) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

