    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        result_a[b_elements[i].original_idx] = a_elements[m - 1 - i].val;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

