#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return true; // Empty permutation is technically valid, but problem states non-zero length
    if (arr.size() < len) return false;

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> counts(n + 1, 0);
    int current_max = 0;
    int distinct_count = 0;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (val > l1) { // Value exceeds current length, cannot be a permutation
            break;
        }
        if (counts[val] == 0) {
            distinct_count++;
        }
        counts[val]++;
        current_max = std::max(current_max, val);

        if (current_max == l1 && distinct_count == l1) {
            is_prefix_perm[l1] = true;
        }
    }

    std::fill(counts.begin(), counts.end(), 0);
    current_max = 0;
    distinct_count = 0;
    std::vector<bool> is_suffix_perm(n + 1, false);
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (val > l2) { // Value exceeds current length, cannot be a permutation
            break;
        }
        if (counts[val] == 0) {
            distinct_count++;
        }
        counts[val]++;
        current_max = std::max(current_max, val);

        if (current_max == l2 && distinct_count == l2) {
            is_suffix_perm[l2] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

