// Function to convert a long long integer to its 18-digit parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The problem statement implies padding from the left for shorter numbers
    // when comparing with a pattern.
    // For example, 92 (01) with pattern 010. 92 becomes 00...001.
    // The pattern is effectively 00...0010.
    // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should normalize both to the maximum length (18) by padding with '0's.
    // Since we build the pattern from right to left, we need to reverse it and then pad.
    std::reverse(pattern.begin(), pattern.end());
    while (pattern.length() < 18) {
        pattern = '0' + pattern;
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 characters long
            while (s.length() < 18) {
                s = '0' + s;
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

