#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n-i' items are taken from the right side
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // These are w[n-(n-i)]...w[n-1]
        // Which is w[i]...w[n-1] if we consider original indices
        // But we are taking n-i items from the right end.
        // The sum of weights for these items is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalties
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left. The last item taken must be from left.
            // The difference in counts is left_count - right_count.
            // If left_count = right_count + 1, no extra penalty.
            // If left_count = right_count + k (k > 1), then k-1 times we took left item
            // when the previous item was also left.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right. The last item taken must be from right.
            // The difference in counts is right_count - left_count.
            // If right_count = left_count + 1, no extra penalty.
            // If right_count = left_count + k (k > 1), then k-1 times we took right item
            // when the previous item was also right.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no penalty from this rule.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

