void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int k = 0; k <= 9; ++k) { // k is the split digit
        std::vector<int> colors(n);
        int last1 = -1; // last digit colored 1
        int last2 = -1; // last digit colored 2
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                colors[i] = 1;
                if (d[i] < last1) {
                    possible_k = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > k) {
                colors[i] = 2;
                if (d[i] < last2) {
                    possible_k = false;
                    break;
                }
                last2 = d[i];
            } else { // d[i] == k
                // Try to assign to color 1 if it maintains non-decreasing order
                // and if it's not forced to be color 2 by a previous k
                if (d[i] >= last2) { // Can be color 2
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Must be color 1
                    colors[i] = 1;
                    last1 = d[i];
                } else { // Cannot be color 1 or 2
                    possible_k = false;
                    break;
                }
            }
        }

        if (possible_k) {
            // Final check: last digit of color 1 <= first digit of color 2
            // This is implicitly handled by the logic:
            // last1 is the max digit in color 1.
            // last2 is the min digit in color 2.
            // If last1 > last2, it means some d[i] was assigned to color 1
            // that should have been color 2, or vice versa.
            // The current assignment strategy ensures that all digits assigned to color 1
            // are <= k, and all digits assigned to color 2 are >= k.
            // If last1 is the largest digit assigned to color 1, and first2 is the smallest
            // digit assigned to color 2, then we need last1 <= first2.
            // Our strategy ensures that any digit assigned to color 1 is <= k,
            // and any digit assigned to color 2 is >= k.
            // So, if last1 <= k and first2 >= k, then last1 <= first2 is guaranteed.
            // The only edge case is if k itself is split.
            // The current logic assigns k's greedily to 2 if possible, else to 1.
            // This means all k's assigned to 1 appear before all k's assigned to 2.
            // And all digits < k are 1, all digits > k are 2.
            // So the sequence will be: (digits < k) (k's as 1) (k's as 2) (digits > k).
            // This is sorted.

            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

