        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor_q : q_prime_factors) {
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= factor_q;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

