#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = {};
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited;

    // Find starting points for paths (nodes with degree 1 or isolated nodes)
    std::vector<char> path_starts;
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() <= 1) {
            path_starts.push_back(c);
        }
    }

    for (char start_node : path_starts) {
        if (visited.count(start_node)) {
            continue;
        }

        char current_node = start_node;
        char prev_node = '\0'; // Sentinel for the first node in a path

        while (current_node != '\0' && !visited.count(current_node)) {
            layout += current_node;
            visited.insert(current_node);

            char next_node = '\0';
            for (char neighbor : adj[current_node]) {
                if (neighbor != prev_node) {
                    next_node = neighbor;
                    break;
                }
            }
            prev_node = current_node;
            current_node = next_node;
        }
    }

    if (layout.length() != 26) {
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

