int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> pos_diff_counts(L, std::vector<int>(L, 0));
    for (int i = 0; i < L; ++i) {
        for (int j = 0; j < L; ++j) {
            if (i == j) continue;
            int diff = (j - i + L) % L;
            pos_diff_counts[diff][s[i] - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c1 = s[k_actual];
        int char_code_c1 = c1 - 'a';

        std::vector<int> possible_k_values;
        for (int k_cand : char_indices[char_code_c1]) {
            possible_k_values.push_back(k_cand);
        }

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < L; ++p) {
            int current_p_win_count = 0;
            for (int k_cand : possible_k_values) {
                char c2 = s[(p + k_cand) % L];
                int char_code_c2 = c2 - 'a';

                int count_matches = 0;
                for (int k_check : possible_k_values) {
                    if (s[(p + k_check) % L] == c2) {
                        count_matches++;
                    }
                }
                if (count_matches == 1) {
                    current_p_win_count++;
                }
            }
            max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, (double)current_p_win_count / possible_k_values.size());
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

