        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_val = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && (i + j) < n; ++j) {
            p[i + j] = block_start_val + (k - 1 - j);
        }
        current_val = block_start_val - 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

