void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    // Calculate prefix sums for the left part (jars 1 to n)
    // Suffix sums for the left part, from right to left
    // S_L[k] = sum(a[n-k]...a[n-1])
    // S_L[0] = 0 (empty prefix)
    // S_L[1] = a[n-1]
    // S_L[k] = a[n-k] + ... + a[n-1]
    std::map<int, int> left_balance_to_k; // balance -> k (number of jars kept from left)
    left_balance_to_k[0] = 0; // Keeping 0 jars from left gives balance 0

    int current_balance = 0;
    for (int k = 1; k <= n; ++k) {
        current_balance += a[n - k];
        if (left_balance_to_k.find(current_balance) == left_balance_to_k.end()) {
            left_balance_to_k[current_balance] = k;
        }
    }

    // Calculate prefix sums for the right part (jars n+1 to 2n)
    // S_R[k] = sum(a[n]...a[n+k-1])
    // S_R[0] = 0 (empty prefix)
    // S_R[1] = a[n]
    // S_R[k] = a[n] + ... + a[n+k-1]
    int min_removed = 2 * n; // Initialize with max possible removed jars

    // Case 1: Keep 0 jars from the right part
    // This means we only keep jars from the left part.
    // The balance of the remaining jars must be 0.
    // We need to find if balance 0 exists in left_balance_to_k.
    // If it does, we keep left_balance_to_k[0] jars from left, and 0 from right.
    // Jars removed = (n - left_balance_to_k[0]) + n
    if (left_balance_to_k.count(0)) {
        min_removed = std::min(min_removed, (n - left_balance_to_k[0]) + n);
    }

    current_balance = 0;
    for (int k = 1; k <= n; ++k) {
        current_balance += a[n + k - 1];
        // We keep k jars from the right part, with balance `current_balance`.
        // We need to find a number of jars `k_L` from the left part such that
        // balance(k_L) + current_balance = 0.
        // This means balance(k_L) = -current_balance.
        if (left_balance_to_k.count(-current_balance)) {
            int k_L = left_balance_to_k[-current_balance];
            // Total jars kept = k_L + k
            // Jars removed = (n - k_L) + (n - k)
            min_removed = std::min(min_removed, (n - k_L) + (n - k));
        } else {
            // If no matching left part, consider only keeping jars from right.
            // This means k_L = 0, so balance(k_L) = 0.
            // If current_balance is 0, then we keep k jars from right and 0 from left.
            // Jars removed = n + (n - k)
            if (current_balance == 0) {
                min_removed = std::min(min_removed, n + (n - k));
            }
        }
    }

    std::cout << min_removed << std::endl;
}

