void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Handle substrings starting with '0'
        if (s[l] == '0') {
            // Find the first '1' after l, or end of string
            int first_one_idx = -1;
            for (int k = l + 1; k < n; ++k) {
                if (s[k] == '1') {
                    first_one_idx = k;
                    break;
                }
            }

            if (first_one_idx == -1) { // All remaining characters are '0'
                // Substrings s[l...r] where all are '0's.
                // f(s[l...r]) = 0.
                // Condition: r - l + 1 = 0.
                // This is impossible since length must be at least 1.
                // So, no good substrings if all are '0's.
                continue;
            }

            // Now, we have s[l] = '0', and s[first_one_idx] = '1'.
            // Any substring s[l...r] where r < first_one_idx will have f(s[l...r]) = 0.
            // The length is r - l + 1.
            // Condition: r - l + 1 = 0. Impossible.
            // So, we only need to consider substrings s[l...r] where r >= first_one_idx.

            // For such substrings, the value f(s[l...r]) is determined by s[first_one_idx...r].
            // Let effective_l = first_one_idx.
            // The value is f(s[effective_l...r]).
            // The length is r - l + 1.
            // Condition: r - l + 1 = f(s[effective_l...r]).

            // We can iterate r from first_one_idx up to n-1.
            // The maximum possible value for f(s[effective_l...r]) is 2^k - 1 where k = r - effective_l + 1.
            // The maximum length we need to check is limited.
            // If r - l + 1 > 20 (approx), then f(s[effective_l...r]) will be much larger than r - l + 1.
            // Specifically, if r - effective_l + 1 >= 20, then f(s[effective_l...r]) >= 2^19.
            // And r - l + 1 <= n <= 2e5.
            // 2^19 is about 5e5.
            // So, if r - effective_l + 1 is large, f(s[effective_l...r]) will be much larger than r - l + 1.
            // The maximum length of the binary representation that can equal its decimal value is small.
            // For example, if length is 20, max value is 2^20-1.
            // If length is 1, value is 1.
            // If length is 2, max value is 3.
            // If length is 3, max value is 7.
            // If length is 18, max value is 2^18-1 = 262143.
            // If length is 19, max value is 2^19-1 = 524287.
            // If length is 20, max value is 2^20-1 = 1048575.
            // The maximum possible length of s is 2e5.
            // So, if r - l + 1 > 20, then f(s[effective_l...r]) will be at least 2^(r - effective_l + 1 - 1)
            // which is 2^(r - l + 1 - (first_one_idx - l) - 1).
            // This is getting complicated. Let's simplify.

            // The number of leading zeros is `first_one_idx - l`.
            // The actual binary string for value calculation starts at `first_one_idx`.
            // Let `num_leading_zeros = first_one_idx - l`.
            // For a substring s[l...r], its length is `len = r - l + 1`.
            // Its value is `val = f(s[first_one_idx...r])`.
            // We need `len = val`.

            // Iterate `r` from `first_one_idx` up to `n-1`.
            // Calculate `val` for `s[first_one_idx...r]`.
            // Calculate `len = r - l + 1`.
            // If `val == len`, increment count.
            // If `val > len + MAX_LEADING_ZEROS_TO_CHECK` (e.g., 20), we can break.
            // The maximum number of leading zeros we can have is `n`.
            // The maximum length of the string is `n`.
            // The maximum value of `val` we need to consider is `n`.
            // If `val` exceeds `n`, it can't be equal to `len` (since `len <= n`).
            // So, we can stop when `val` exceeds `n`.
            // Also, `val` can grow very fast. If `val` becomes too large, it will never equal `len`.
            // The maximum `len` is `n`.
            // The maximum `val` we need to check is `n`.
            // If `val` exceeds `n`, we can stop.
            // The maximum number of bits for `val` to be <= `n` is `log2(n)`.
            // For `n = 2e5`, `log2(2e5)` is about 17.6. So, about 18 bits.
            // This means `r - first_one_idx + 1` can be at most around 18.
            // So, `r` can be at most `first_one_idx + 17`.
            // This limits the inner loop for `r` to a small constant number of iterations.

            long long current_val = 0;
            for (int r = first_one_idx; r < n; ++r) {
                current_val = (current_val << 1) | (s[r] - '0');
                int len = r - l + 1;

                // Optimization: if current_val is already too large, it can't be equal to len.
                // Max possible len is n. If current_val > n, break.
                // Also, if current_val exceeds a certain threshold (e.g., 2 * n), it's very unlikely to match.
                // A tighter bound: if current_val > n, it can't be equal to len.
                // Also, if current_val > len + (r - first_one_idx + 1) + (first_one_idx - l)
                // The actual length of the binary number is r - first_one_idx + 1.
                // The total length of the substring is r - l + 1.
                // If current_val > n, we can break.
                if (current_val > n + 20) { // A slightly larger bound to be safe, e.g., n + max_leading_zeros_to_check
                                            // Max leading zeros to check is around 20.
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        } else { // s[l] == '1'
            long long current_val = 0;
            // Iterate r from l up to n-1
            // The maximum length of the binary representation that can equal its decimal value is small.
            // If r - l + 1 > 20 (approx), then f(s[l...r]) will be much larger than r - l + 1.
            // Max length of s is 2e5.
            // Max value of f(s[l...r]) we need to check is 2e5.
            // log2(2e5) is about 17.6. So, we only need to check about 18 bits.
            // This means r - l + 1 can be at most around 18.
            // So, the inner loop for r runs at most about 18 times.
            for (int r = l; r < n; ++r) {
                current_val = (current_val << 1) | (s[r] - '0');
                int len = r - l + 1;

                // Optimization: if current_val is already too large, it can't be equal to len.
                // Max possible len is n. If current_val > n, break.
                if (current_val > n + 20) { // A slightly larger bound to be safe
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

