// Since `len = r - l + 1 <= N = 2e5`, if `current_val > N`, it cannot be equal to `len`.
// So, `current_val > 2e5` is a good break condition.
// The `+ 20` in `current_val > n + 20` is a safety margin.
// The number of leading zeros `first_one_idx - l` can be up to `N`.
// The total length `len = r - l + 1`.
// The value `val = f(s[first_one_idx...r])`.
// We need `len = val`.
// `len = (r - first_one_idx + 1) + (first_one_idx - l)`.
// `len = len_val + num_leading_zeros`.
// So, `val = len_val + num_leading_zeros`.
// Since `val >= 2^(len_val-1)` (if `len_val >= 1`), we need `2^(len_val-1) <= len_val + num_leading_zeros`.
// If `len_val` is large, `2^(len_val-1)` grows much faster than `len_val + num_leading_zeros`.
// For `len_val = 1`, `1 <= 1 + num_leading_zeros`. True.
// For `len_val = 2`, `2 <= 2 + num_leading_zeros`. True.
// For `len_val = 3`, `4 <= 3 + num_leading_zeros`. True if `num_leading_zeros >= 1`.
// For `len_val = 4`, `8 <= 4 + num_leading_zeros`. True if `num_leading_zeros >= 4`.
// For `len_val = 5`, `16 <= 5 + num_leading_zeros`. True if `num_leading_zeros >= 11`.
// For `len_val = 6`, `32 <= 6 + num_leading_zeros`. True if `num_leading_zeros >= 26`.
// For `len_val = 7`, `64 <= 7 + num_leading_zeros`. True if `num_leading_zeros >= 57`.
// For `len_val = 8`, `128 <= 8 + num_leading_zeros`. True if `num_leading_zeros >= 120`.
// For `len_val = 9`, `256 <= 9 + num_leading_zeros`. True if `num_leading_zeros >= 247`.
// For `len_val = 10`, `512 <= 10 + num_leading_zeros`. True if `num_leading_zeros >= 502`.
// For `len_val = 11`, `1024 <= 11 + num_leading_zeros`. True if `num_leading_zeros >= 1013`.
// For `len_val = 12`, `2048 <= 12 + num_leading_zeros`. True if `num_leading_zeros >= 2036`.
// For `len_val = 13`, `4096 <= 13 + num_leading_zeros`. True if `num_leading_zeros >= 4083`.
// For `len_val = 14`, `8192 <= 14 + num_leading_zeros`. True if `num_leading_zeros >= 8178`.
// For `len_val = 15`, `16384 <= 15 + num_leading_zeros`. True if `num_leading_zeros >= 16369`.
// For `len_val = 16`, `32768 <= 16 + num_leading_zeros`. True if `num_leading_zeros >= 32752`.
// For `len_val = 17`, `65536 <= 17 + num_leading_zeros`. True if `num_leading_zeros >= 65519`.
// For `len_val = 18`, `131072 <= 18 + num_leading_zeros`. True if `num_leading_zeros >= 131054`.
// For `len_val = 19`, `262144 <= 19 + num_leading_zeros`.
// Max `num_leading_zeros` is `N-1` (if `s[N-1]` is '1' and all before are '0').
// Max `N` is `2e5`.
// So, `num_leading_zeros` can be up to `2e5 - 1`.
// If `len_val = 19`, `262144` is already greater than `2e5 - 1 + 19`.
// So, `len_val` can be at most 18.
// This means the inner loop for `r` (when `s[l] == '0'`) runs at most about 18 iterations after `first_one_idx`.
// The `current_val > n + 20` condition is robust enough.
// The total complexity is O(N * C) where C is a small constant (around 20).
// Sum of N over queries is 2e5. So total time complexity is O(Sum N * C). This is efficient enough.

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop
    std::vector<int> dp_x(n + 1, 0);

    for (int i = 1; i <= n; ++i) {
        if (dp_y[i] != -2) continue;

        std::vector<int> path;
        int current_x = i;
        long long current_y_offset = 0; // y offset from the start of the current path

        while (current_x >= 1 && current_x <= n) {
            if (dp_y[current_x] != -2) { // Hit a computed state
                if (dp_y[current_x] == -1) { // Hit an infinite loop
                    for (int node : path) {
                        dp_y[node] = -1;
                    }
                    break;
                } else { // Hit a terminating state
                    for (int node : path) {
                        dp_y[node] = current_y_offset + dp_y[current_x];
                        dp_x[node] = dp_x[current_x];
                    }
                    break;
                }
            }

            // Check for cycle in current path
            bool in_path = false;
            for (int node : path) {
                if (node == current_x) {
                    in_path = true;
                    break;
                }
            }
            if (in_path) { // Cycle detected
                for (int node : path) {
                    dp_y[node] = -1;
                }
                break;
            }

            path.push_back(current_x);

            long long val_a_x = a[current_x];

            // Step 2: x = x + a[x], y = y + a[x]
            int next_x_step2 = current_x + val_a_x;
            long long next_y_offset_step2 = current_y_offset + val_a_x;

            if (next_x_step2 <= 0 || next_x_step2 > n) { // Terminates after step 2
                for (int node : path) {
                    dp_y[node] = next_y_offset_step2;
                    dp_x[node] = next_x_step2;
                }
                break;
            }

            // Step 3: y = y + a[x_new], x = x_new - a[x_new]
            long long val_a_next_x_step2 = a[next_x_step2];
            int next_x_step3 = next_x_step2 - val_a_next_x_step2;
            long long next_y_offset_step3 = next_y_offset_step2 + val_a_next_x_step2;

            if (next_x_step3 <= 0 || next_x_step3 > n) { // Terminates after step 3
                for (int node : path) {
                    dp_y[node] = next_y_offset_step3;
                    dp_x[node] = next_x_step3;
                }
                break;
            }

            // Continue to next iteration
            current_x = next_x_step3;
            current_y_offset = next_y_offset_step3;
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current run

        int current_x = 1;
        long long current_y = 0;

        long long val_a_x = a[current_x];

        // Step 2: x = x + a[x], y = y + a[x]
        int next_x_step2 = current_x + val_a_x;
        long long next_y_step2 = current_y + val_a_x;

        if (next_x_step2 <= 0 || next_x_step2 > n) { // Terminates after step 2
            std::cout << next_y_step2 << "\n";
            continue;
        }

        // Step 3: y = y + a[x_new], x = x_new - a[x_new]
        long long val_a_next_x_step2 = a[next_x_step2];
        int next_x_step3 = next_x_step2 - val_a_next_x_step2;
        long long next_y_step3 = next_y_step2 + val_a_next_x_step2;

        if (next_x_step3 <= 0 || next_x_step3 > n) { // Terminates after step 3
            std::cout << next_y_step3 << "\n";
            continue;
        }

        // If it doesn't terminate, it enters the precomputed states
        if (dp_y[next_x_step3] == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << next_y_step3 + dp_y[next_x_step3] << "\n";
        }
    }

    return 0;
}

#include <iostream>
