struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, 0); // Initial array values
    std::vector<long long> current_d_sum(n, 0); // Sum of d for type 1 operations applied so far

    // Process operations in reverse to determine upper bounds for b[j]
    // For each type 2 operation (2 l r m), we know that for all j in [l, r], a[j] <= m.
    // This means b[j] + current_d_sum[j] <= m, or b[j] <= m - current_d_sum[j].
    // We want to find the largest possible b[j] values that satisfy all constraints.
    // Initialize b[j] to a very large value (effectively infinity) and then take minimums.
    std::vector<long long> max_b_val(n, 2000000000000000000LL); // A value larger than 10^9 + 5*10^7 + 5000*10^4

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (1 l r d), it means this d was applied
            // to a[j] for j in [l, r]. When going backwards, this d is "removed"
            // from the current_d_sum for those indices.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_d_sum[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (2 l r m), it means max(a[j]) == m for j in [l, r].
            // At this point in reverse, current_d_sum[j] represents the sum of d's
            // that would be applied *after* this operation.
            // So, the initial value b[j] plus all d's applied *before and including* this operation
            // must be <= m.
            // The d's applied *before and including* this operation are (current_d_sum[j] + ops[i].val).
            // No, this is wrong. current_d_sum[j] already represents the sum of d's applied *after* this operation.
            // So, the value of a[j] at the time of this operation was b[j] + (total_d_sum_up_to_this_op).
            // The total_d_sum_up_to_this_op is (total_d_sum_for_all_ops - current_d_sum[j]).
            // Let's re-evaluate.
            // current_d_sum[j] stores the sum of d's for operations *after* the current one (in forward time).
            // So, if a[j] at time i is X, then X = b[j] + (sum of d's from ops 0 to i-1).
            // When we are at operation i (reverse order), current_d_sum[j] holds the sum of d's from ops i+1 to m-1.
            // So, the sum of d's from ops 0 to i-1 is (total_d_sum_at_end - current_d_sum[j]).
            // Let's use a different approach for current_d_sum.
            // Let `delta[j]` be the sum of `d` values applied to `a[j]` by operations `0` to `i-1`.
            // Then `a[j]` at operation `i` is `b[j] + delta[j]`.
            // For type 2 operation `i` (2 l r m): `b[j] + delta[j] <= m` for `j` in `[l, r]`.
            // This means `b[j] <= m - delta[j]`.
            // We need to calculate `delta[j]` for each `i`.

            // Let's restart the logic for `max_b_val`.
            // `max_b_val[j]` will store the maximum possible initial value for `a[j]`.
            // Initialize `max_b_val[j]` to a very large number.
            // `current_d_effect[j]` will store the sum of `d` values applied to `a[j]` by operations *before* the current one.
            // When processing operations in forward order:
            // If type 1 (1 l r d): `current_d_effect[j]` increases by `d` for `j` in `[l, r]`.
            // If type 2 (2 l r m): For all `j` in `[l, r]`, `b[j] + current_d_effect[j] <= m`.
            // So, `b[j] <= m - current_d_effect[j]`. We update `max_b_val[j] = min(max_b_val[j], m - current_d_effect[j])`.

            // This is the correct approach.
            // `max_b_val[j]` stores the upper bound for `b[j]`.
            // `current_d_sum[j]` stores the sum of `d` values from type 1 operations *up to the current point* in forward time.
            // Initialize `max_b_val` to a very large number.
            // Initialize `current_d_sum` to all zeros.

            // The loop below is for calculating `max_b_val`.
            // It should iterate forward.
            // Let's re-initialize `max_b_val` and `current_d_sum`.
            // `max_b_val` is already initialized.
            std::fill(current_d_sum.begin(), current_d_sum.end(), 0);

            for (int k = 0; k < m; ++k) {
                if (ops[k].type == 1) {
                    for (int j = ops[k].l; j <= ops[k].r; ++j) {
                        current_d_sum[j] += ops[k].val;
                    }
                } else { // ops[k].type == 2
                    for (int j = ops[k].l; j <= ops[k].r; ++j) {
                        max_b_val[j] = std::min(max_b_val[j], ops[k].val - current_d_sum[j]);
                    }
                }
            }
            // After this loop, `max_b_val[j]` holds the tightest upper bound for `b[j]`
            // derived from all type 2 operations.
            // We can choose `b[j] = max_b_val[j]` as a candidate solution.
            // If `max_b_val[j]` is still the initial large value, it means no type 2 operation
            // constrained `b[j]`. In this case, we can set `b[j] = 0` (or any value within bounds).
            // Let's set `b[j] = max_b_val[j]` for now. If it's still large, it means it's unconstrained
            // by type 2 ops, so we can pick 0.
            for(int j=0; j<n; ++j) {
                if (max_b_val[j] == 2000000000000000000LL) {
                    b[j] = 0; // Unconstrained, pick 0
                } else {
                    b[j] = max_b_val[j];
                }
            }

            // Now, we need to verify if this `b` array works.
            // For each type 2 operation (2 l r m), we must have `max(a[j]) == m`.
            // Our choice `b[j] = max_b_val[j]` ensures `a[j] <= m` for all `j` in `[l, r]`.
            // We still need to ensure that `max(a[j]) == m` (i.e., at least one `a[k] == m`).
            // If for any type 2 operation, `max(a[j]) < m`, then no solution exists.

            std::fill(current_d_sum.begin(), current_d_sum.end(), 0); // Reset for verification
            for (int k = 0; k < m; ++k) {
                if (ops[k].type == 1) {
                    for (int j = ops[k].l; j <= ops[k].r; ++j) {
                        current_d_sum[j] += ops[k].val;
                    }
                } else { // ops[k].type == 2
                    long long current_max = -3000000000000000000LL; // A very small number
                    for (int j = ops[k].l; j <= ops[k].r; ++j) {
                        current_max = std::max(current_max, b[j] + current_d_sum[j]);
                    }
                    if (current_max != ops[k].val) {
                        std::cout << "NO\n";
                        return 0;
                    }
                }
            }

            // Check absolute value constraints for b[j]
            for (int j = 0; j < n; ++j) {
                if (b[j] < -1000000000LL || b[j] > 1000000000LL) {
                    std::cout << "NO\n";
                    return 0;
                }
            }

            std::cout << "YES\n";
            for (int j = 0; j < n; ++j) {
                std::cout << b[j] << (j == n - 1 ? "" : " ");
            }
            std::cout << "\n";
            return 0;
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long office_cry_effect = children[i].v;
        long long cumulative_hall_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative hall cry effect from previous children who ran away
            children[j].p -= cumulative_hall_cry_effect;

            // Apply office cry effect from current child
            if (office_cry_effect > 0) {
                children[j].p -= office_cry_effect;
                office_cry_effect--;
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_hall_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

