        // The example "nolon" -> 2 confirms this. "nolon" is not all same chars, k=1 doesn't work, so k=2.
        // The example "otto" -> 1 confirms this. "otto" is not all same chars, k=1 works.
        // The example "qqqq" -> Impossible confirms this. "qqqq" is all same chars.

        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: SumR = (b-1) * b / 2
    // Since b-1 or b might be even, one of them is divisible by 2.
    // We need to perform division by 2 carefully under modulo.
    // (b-1) * b / 2 mod MOD
    long long sum_r_term = (b - 1);
    long long sum_r_term_mult = b;

    long long sum_r_val;
    if (sum_r_term_mult % 2 == 0) {
        sum_r_val = (sum_r_term % MOD * (sum_r_term_mult / 2 % MOD)) % MOD;
    } else {
        sum_r_val = (sum_r_term / 2 % MOD * (sum_r_term_mult % MOD)) % MOD;
    }

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} (1)
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_kb_plus_1_val;
    long long sum_k_term = a;
    long long sum_k_term_mult = (a + 1);

    long long sum_k_val;
    if (sum_k_term_mult % 2 == 0) {
        sum_k_val = (sum_k_term % MOD * (sum_k_term_mult / 2 % MOD)) % MOD;
    } else {
        sum_k_val = (sum_k_term / 2 % MOD * (sum_k_term_mult % MOD)) % MOD;
    }

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = a % MOD;
    sum_kb_plus_1_val = (term1 + term2) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<std::pair<long long, long long>> head_ranges(n);
    for (int i = 0; i < n; ++i) {
        head_ranges[i] = {h[i] - T, h[i] + T};
    }

    int p_idx = 0;
    for (int h_idx = 0; h_idx < n && p_idx < m; ++h_idx) {
        long long current_head_pos = h[h_idx];
        long long min_reach = current_head_pos - T;
        long long max_reach = current_head_pos + T;

        // If the current head cannot even reach the current target track p[p_idx]
        // (meaning p[p_idx] is to the left of min_reach), then this head cannot cover it.
        // We need to find a head that can cover p[p_idx].
        // The heads are sorted, so if h[h_idx] cannot reach p[p_idx], no h[k] for k < h_idx can.
        // We must use h[h_idx] or a later head.
        // If p[p_idx] is to the left of min_reach, this head cannot cover it.
        // We need to advance p_idx until p[p_idx] is within reach or we run out of p.
        // This is not quite right. We need to cover p[p_idx].
        // If p[p_idx] is to the left of min_reach, this head cannot cover it.
        // But we can't just skip this head. We must use heads to cover tracks.
        // The greedy strategy is: for the current p[p_idx], find the earliest head that can cover it.
        // And then use that head to cover as many subsequent p's as possible.

        // If p[p_idx] is already covered by a previous head's range, advance p_idx.
        // This is handled by the outer loop condition `p_idx < m`.
        // The current head h[h_idx] can cover tracks in [min_reach, max_reach].
        // If p[p_idx] is outside this range, this head cannot cover it.
        // Specifically, if p[p_idx] > max_reach, this head cannot cover it.
        // If p[p_idx] < min_reach, this head cannot cover it.
        // But since p and h are sorted, and we process p_idx sequentially,
        // p[p_idx] will generally be to the right of h[h_idx] or within its range.

        // The greedy approach:
        // For the current p[p_idx], we need to find a head that can cover it.
        // We iterate through heads. If h[h_idx] can cover p[p_idx] (i.e., p[p_idx] >= min_reach),
        // then we use this head. This head can cover all tracks up to max_reach.
        // We then advance p_idx past all tracks that are <= max_reach.
        // If h[h_idx] cannot cover p[p_idx] (i.e., p[p_idx] < min_reach),
        // this means p[p_idx] is too far to the left for h[h_idx].
        // This should not happen if we are processing p_idx sequentially and h_idx sequentially.
        // Because if p[p_idx] < min_reach, then h[h_idx] is too far right for p[p_idx].
        // This implies that p[p_idx] must have been covered by a previous head, or it's impossible.

        // Let's refine the greedy strategy:
        // We need to cover p[p_idx].
        // Find the first head h[h_idx] such that h[h_idx] + T >= p[p_idx].
        // If no such head exists, or if for this head, h[h_idx] - T > p[p_idx], then it's impossible.
        // Otherwise, this head h[h_idx] can cover p[p_idx].
        // It can cover all tracks up to h[h_idx] + T.
        // So, we advance p_idx past all tracks that are <= h[h_idx] + T.
        // Then we move to the next head (h_idx+1) and the next uncovered track (new p_idx).

        // Corrected greedy approach:
        // Iterate through heads. For each head h[h_idx]:
        // 1. If p_idx is already at m (all tracks covered), we are done.
        // 2. Calculate the range this head can cover: [h[h_idx] - T, h[h_idx] + T].
        // 3. If p[p_idx] is to the left of this head's minimum reach (p[p_idx] < h[h_idx] - T),
        //    then this head cannot cover p[p_idx]. Since heads are sorted,
        //    any subsequent head h[k] (k > h_idx) will be even further to the right,
        //    so it also cannot cover p[p_idx]. This means p[p_idx] cannot be covered. Return false.
        // 4. If p[p_idx] is within this head's reach (p[p_idx] <= h[h_idx] + T),
        //    then this head can cover p[p_idx]. It can also cover all tracks up to h[h_idx] + T.
        //    So, advance p_idx past all tracks that are <= h[h_idx] + T.
        // 5. If p[p_idx] is to the right of this head's maximum reach (p[p_idx] > h[h_idx] + T),
        //    then this head cannot cover p[p_idx]. We must use a later head for p[p_idx].
        //    So, we continue to the next head (h_idx+1) without advancing p_idx.

        // This greedy strategy is slightly flawed.
        // Consider p = [1, 10], h = [5], T = 2.
        // h[0]=5, range [3, 7]. p[0]=1 < 3. This strategy would return false.
        // But if h[0] moves to 1, it covers [1,5]. If it moves to 10, it covers [5,10].
        // The problem is that a head can move to *any* point in its T-range.
        // If a head h_i moves to x, it covers [min(h_i, x), max(h_i, x)].
        // The total set of tracks it can cover is [h_i - T, h_i + T].
        // So, if we need to cover p_j, and h_i is used, it must be that p_j is in [h_i - T, h_i + T].
        // And if h_i covers p_j, it can also cover other tracks.
        // The most efficient way to cover tracks is to move the head to one end of its range.
        // If h_i covers p_j, it can cover [p_j, h_i + T] if p_j >= h_i.
        // Or [h_i - T, p_j] if p_j <= h_i.
        // Or [h_i - T, h_i + T] if it moves to one of the ends.

        // Let's use the standard greedy approach for interval covering:
        // We need to cover all p_j.
        // For the current p[p_idx] that needs to be covered:
        // Find the head h[h_idx] (starting from the current h_idx) that can cover p[p_idx]
        // AND can reach furthest to the right.
        // If no head can cover p[p_idx], then it's impossible.
        // Otherwise, pick the best head, use it, and advance p_idx past its covered range.

        // This is the correct greedy approach:
        // `p_idx` points to the first target track not yet covered.
        // `h_idx` points to the first head not yet used.
        // While `p_idx < m`:
        //   Find the first head `h[current_h_idx]` (starting from `h_idx`) such that `h[current_h_idx] + T >= p[p_idx]`.
        //   If no such head exists (i.e., `current_h_idx == n`), then `p[p_idx]` cannot be covered. Return `false`.
        //   Let this head be `h_k = h[current_h_idx]`.
        //   Check if `h_k` can actually cover `p[p_idx]`: `p[p_idx] >= h_k - T`.
        //   If not, then `p[p_idx]` is too far left for `h_k`. Since `h` is sorted,
        //   any `h_j` with `j < current_h_idx` would be even further left, and might have covered `p[p_idx]`.
        //   But we are processing heads from left to right.
        //   This means `p[p_idx]` cannot be covered by any available head. Return `false`.
        //   If `h_k` can cover `p[p_idx]`, then it can cover all tracks up to `h_k + T`.
        //   Advance `p_idx` past all tracks `p_j` such that `p_j <= h_k + T`.
        //   Advance `h_idx` to `current_h_idx + 1` (this head is now used).

        // Let's try this:
        // `p_idx` is the index of the first target track that needs to be covered.
        // `h_idx` is the index of the first head available to cover `p[p_idx]`.
        // We iterate `h_idx` from 0 to `n-1`.
        // For each `h[h_idx]`:
        //   It can cover the range `[h[h_idx] - T, h[h_idx] + T]`.
        //   We need to cover `p[p_idx]`.
        //   If `p[p_idx]` is to the left of `h[h_idx] - T`, then `h[h_idx]` cannot cover `p[p_idx]`.
        //   Since `h` is sorted, any `h[k]` for `k > h_idx` will be even further right,
        //   so it also cannot cover `p[p_idx]`.
        //   This means `p[p_idx]` cannot be covered by any *remaining* head.
        //   So, if `p[p_idx] < h[h_idx] - T`, it's impossible. Return `false`.
        //   If `p[p_idx]` is within the range `[h[h_idx] - T, h[h_idx] + T]`:
        //     This head can cover `p[p_idx]`. It can cover all tracks up to `h[h_idx] + T`.
        //     So, we advance `p_idx` past all tracks `p_j` such that `p_j <= h[h_idx] + T`.
        //     Then we move to the next head (`h_idx + 1`) and the next uncovered track (`p_idx`).
        //   If `p[p_idx]` is to the right of `h[h_idx] + T`:
        //     This head cannot cover `p[p_idx]`. We must use a later head for `p[p_idx]`.
        //     So, we continue to the next head (`h_idx + 1`) without advancing `p_idx`.

        // This is the standard greedy approach for interval covering.
        // `p_idx` is the index of the first *uncovered* target track.
        // `h_idx` is the index of the current head we are considering.
        // We try to cover `p[p_idx]` using `h[h_idx]`.
        // If `h[h_idx]` can cover `p[p_idx]` (i.e., `p[p_idx]` is in `[h[h_idx]-T, h[h_idx]+T]`),
        // then we use `h[h_idx]` to cover `p[p_idx]` and as many subsequent tracks as possible.
        // The maximum reach of `h[h_idx]` is `h[h_idx] + T`.
        // So we advance `p_idx` past all tracks `p_k` such that `p_k <= h[h_idx] + T`.
        // Then we move to the next head `h_idx + 1`.
        // If `h[h_idx]` cannot cover `p[p_idx]` (i.e., `p[p_idx] > h[h_idx] + T`),
        // then `h[h_idx]` is too far left to cover `p[p_idx]`. We must use a later head.
        // So we move to `h_idx + 1` without advancing `p_idx`.
        // If `p[p_idx] < h[h_idx] - T`, then `h[h_idx]` is too far right for `p[p_idx]`.
        // Since `h` is sorted, any `h[k]` for `k > h_idx` will also be too far right.
        // This means `p[p_idx]` cannot be covered. Return `false`.

        // Let's trace the example:
        // n=3, m=4
        // h = [2, 5, 6]
        // p = [1, 3, 6, 8]
        // T = 2

        // h_idx = 0, p_idx = 0
        // h[0] = 2. Range [2-2, 2+2] = [0, 4].
        // p[0] = 1.
        // Is p[0] < h[0]-T? (1 < 0) No.
        // Is p[0] <= h[0]+T? (1 <= 4) Yes.
        //   Head h[0] covers p[0]. Max reach is 4.
        //   Advance p_idx: p[0]=1, p[1]=3. Both <= 4.
        //   New p_idx = 2 (p[2]=6 is > 4).
        //   h_idx becomes 1.

        // h_idx = 1, p_idx = 2
        // h[1] = 5. Range [5-2, 5+2] = [3, 7].
        // p[2] = 6.
        // Is p[2] < h[1]-T? (6 < 3) No.
        // Is p[2] <= h[1]+T? (6 <= 7) Yes.
        //   Head h[1] covers p[2]. Max reach is 7.
        //   Advance p_idx: p[2]=6. It is <= 7.
        //   New p_idx = 3 (p[3]=8 is > 7).
        //   h_idx becomes 2.

        // h_idx = 2, p_idx = 3
        // h[2] = 6. Range [6-2, 6+2] = [4, 8].
        // p[3] = 8.
        // Is p[3] < h[2]-T? (8 < 4) No.
        // Is p[3] <= h[2]+T? (8 <= 8) Yes.
        //   Head h[2] covers p[3]. Max reach is 8.
        //   Advance p_idx: p[3]=8. It is <= 8.
        //   New p_idx = 4.
        //   h_idx becomes 3.

        // p_idx = 4. Since p_idx == m, all tracks covered. Return true.

        // This greedy strategy seems correct.
        // For each p[p_idx] that needs to be covered, we find the first available head h[h_idx]
        // that can cover it. If h[h_idx] is too far right (p[p_idx] < h[h_idx] - T), then it's impossible.
        // If h[h_idx] is too far left (p[p_idx] > h[h_idx] + T), then h[h_idx] cannot cover p[p_idx],
        // so we must try the next head.
        // If h[h_idx] can cover p[p_idx], we use it, and it covers up to h[h_idx] + T.
        // We then advance p_idx past all tracks covered by this head.

        // Let's refine the loop structure.
        // `p_idx` is the index of the next target track to cover.
        // `h_idx` is the index of the head we are currently considering to cover `p[p_idx]`.
        // We need to find the *earliest* head `h[k]` (where `k >= h_idx`) that can cover `p[p_idx]`.
        // And then use that head to cover as much as possible.

        // `p_idx` starts at 0.
        // `h_idx` starts at 0.
        // While `p_idx < m`:
        //   `target_p = p[p_idx]`
        //   `best_reach = -1` (max right reach of a head that can cover `target_p`)
        //   `found_head_for_target_p = false`
        //   `candidate_h_idx = h_idx`
        //   While `candidate_h_idx < n`:
        //     `current_h = h[candidate_h_idx]`
        //     `min_h_reach = current_h - T`
        //     `max_h_reach = current_h + T`
        //     If `target_p >= min_h_reach` and `target_p <= max_h_reach`:
        //       `found_head_for_target_p = true`
        //       `best_reach = std::max(best_reach, max_h_reach)`
        //       // We found a head that can cover target_p.
        //       // We want to find the one that extends furthest to the right.
        //       // But we also want to use the *earliest* head possible to free up later heads.
        //       // This is the standard interval covering problem.
        //       // For the current `p[p_idx]`, find the head `h[k]` (with `k >= h_idx`)
        //       // such that `p[p_idx]` is in `[h[k]-T, h[k]+T]`, and `h[k]+T` is maximized.
        //       // This is not quite right. We need to use the *first* head that can cover `p[p_idx]`.
        //       // And then advance `p_idx` as far as possible.

        // Let's use the simpler greedy:
        // `p_idx = 0`
        // For `h_idx` from 0 to `n-1`:
        //   If `p_idx == m`, break (all tracks covered).
        //   `current_h = h[h_idx]`
        //   `min_h_reach = current_h - T`
        //   `max_h_reach = current_h + T`
        //   If `p[p_idx] < min_h_reach`:
        //     // `p[p_idx]` is too far left for `h[h_idx]`.
        //     // Since `h` is sorted, `h[h_idx]` is the earliest head that could potentially cover `p[p_idx]`
        //     // (if we were to consider heads from right to left).
        //     // But we are considering heads from left to right.
        //     // If `p[p_idx]` is to the left of `h[h_idx] - T`, it means `h[h_idx]` cannot cover it.
        //     // And any `h[k]` for `k > h_idx` will be even further right, so it also cannot cover `p[p_idx]`.
        //     // This implies `p[p_idx]` cannot be covered.
        //     Return `false`.
        //   If `p[p_idx] <= max_h_reach`:
        //     // `h[h_idx]` can cover `p[p_idx]`.
        //     // It can cover all tracks up to `max_h_reach`.
        //     // Advance `p_idx` past all tracks that are `<= max_h_reach`.
        //     While `p_idx < m` and `p[p_idx] <= max_h_reach`:
        //       `p_idx++`
        //   Else (`p[p_idx] > max_h_reach`):
        //     // `h[h_idx]` cannot cover `p[p_idx]`.
        //     // We need to use a later head for `p[p_idx]`.
        //     // Do nothing with `p_idx`, just move to the next head.
        //
        // After the loop, if `p_idx == m`, all tracks are covered. Return `true`.
        // Else, return `false`.

        // Example 1: h=[2,5,6], p=[1,3,6,8], T=2
        // p_idx=0
        // h_idx=0: h[0]=2. min_h_reach=0, max_h_reach=4.
        //   p[0]=1. Is 1 < 0? No.
        //   Is 1 <= 4? Yes.
        //     p_idx=0: p[0]=1 <= 4. p_idx becomes 1.
        //     p_idx=1: p[1]=3 <= 4. p_idx becomes 2.
        //     p_idx=2: p[2]=6 > 4. Loop ends.
        //     p_idx is now 2.
        // h_idx=1: h[1]=5. min_h_reach=3, max_h_reach=7.
        //   p[2]=6. Is 6 < 3? No.
        //   Is 6 <= 7? Yes.
        //     p_idx=2: p[2]=6 <= 7. p_idx becomes 3.
        //     p_idx=3: p[3]=8 > 7. Loop ends.
        //     p_idx is now 3.
        // h_idx=2: h[2]=6. min_h_reach=4, max_h_reach=8.
        //   p[3]=8. Is 8 < 4? No.
        //   Is 8 <= 8? Yes.
        //     p_idx=3: p[3]=8 <= 8. p_idx becomes 4.
        //     p_idx=4: p_idx == m. Loop ends.
        //     p_idx is now 4.
        // Loop for h_idx ends. p_idx=4, m=4. p_idx == m. Return true. Correct.

        // Example 3: h=[165], p=[142, 200], T=81
        // p_idx=0
        // h_idx=0: h[0]=165. min_h_reach=165-81=84, max_h_reach=165+81=246.
        //   p[0]=142. Is 142 < 84? No.
        //   Is 142 <= 246? Yes.
        //     p_idx=0: p[0]=142 <= 246. p_idx becomes 1.
        //     p_idx=1: p[1]=200 <= 246. p_idx becomes 2.
        //     p_idx=2: p_idx == m. Loop ends.
        //     p_idx is now 2.
        // Loop for h_idx ends. p_idx=2, m=2. p_idx == m. Return true. Correct.

        // Example with `p[p_idx] < min_h_reach`:
        // h=[100], p=[50], T=10
        // p_idx=0
        // h_idx=0: h[0]=100. min_h_reach=90, max_h_reach=110.
        //   p[0]=50. Is 50 < 90? Yes. Return false. Correct.

        // Example with `p[p_idx] > max_h_reach`:
        // h=[100, 200], p=[150, 250], T=10
        // p_idx=0
        // h_idx=0: h[0]=100. min_h_reach=90, max_h_reach=110.
        //   p[0]=150. Is 150 < 90? No.
        //   Is 150 <= 110? No. (150 > max_h_reach)
        //   Do nothing with p_idx.
        // h_idx=1: h[1]=200. min_h_reach=190, max_h_reach=210.
        //   p[0]=150. Is 150 < 190? Yes. Return false. Correct.
        // This is correct because h[0] cannot reach 150, and h[1] is even further right.

        // The greedy strategy seems robust.

    int current_p_idx = 0;
    for (int i = 0; i < n && current_p_idx < m; ++i) {
        long long head_pos = h[i];
        long long min_reach = head_pos - T;
        long long max_reach = head_pos + T;

        // If the current target track p[current_p_idx] is to the left of what this head can reach,
        // then this head cannot cover it. Since heads are sorted, any subsequent head
        // will be even further to the right and also cannot cover p[current_p_idx].
        // Thus, p[current_p_idx] cannot be covered.
        if (p[current_p_idx] < min_reach) {
            return false;
        }

        // If the current target track p[current_p_idx] is within this head's reach,
        // then this head can cover it. It can also cover all tracks up to max_reach.
        if (p[current_p_idx] <= max_reach) {
            // Advance current_p_idx past all tracks that are covered by this head.
            while (current_p_idx < m && p[current_p_idx] <= max_reach) {
                current_p_idx++;
            }
        }
        // Else (p[current_p_idx] > max_reach), this head cannot cover p[current_p_idx].
        // We need to use a later head for p[current_p_idx].
        // So, we just move to the next head (i+1) without advancing current_p_idx.
    }

    // If all target tracks have been covered (current_p_idx reaches m), return true.
    return current_p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible T:
    // If n=1, m=1, h=[1], p=[10^10]. T = 10^10 - 1.
    // If n=1, m=2, h=[1], p=[1, 10^10]. T = 10^10 - 1.
    // If n=1, m=2, h=[10^10], p=[1, 10^10]. T = 10^10 - 1.
    // The maximum distance between any p_i and any h_j is roughly 10^10.
    // So T can be up to 10^10.
    // A safe upper bound is 2 * 10^10.
    long long high = 20000000000LL; // 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The previous element in the non-decreasing array
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long current_b;

        // Case 1: a[i] + x >= prev_b
        // This means a[i] can be transformed to (a[i] + c) % m where c <= x
        // and (a[i] + c) % m >= prev_b.
        // The smallest such value is max(prev_b, a[i]).
        // This is possible if max(prev_b, a[i]) <= (a[i] + x) % m.
        // If a[i] >= prev_b, we can just keep a[i] (c=0).
        // If a[i] < prev_b, we need to increment a[i] until it's at least prev_b.
        // The number of increments needed is prev_b - a[i].
        // This is possible if prev_b - a[i] <= x.
        // In this case, current_b = prev_b.

        // Case 2: a[i] + x < prev_b
        // This means a[i] must "wrap around" to be at least prev_b.
        // The value (a[i] + x) % m must be >= prev_b.
        // This implies that a[i] + x must be >= m + prev_b.
        // The smallest value a[i] can take that is >= prev_b is prev_b itself.
        // To reach prev_b from a[i] by wrapping around, we need to add (m - a[i] + prev_b) % m.
        // If a[i] <= prev_b, this is prev_b - a[i].
        // If a[i] > prev_b, this is m - a[i] + prev_b.
        // The number of increments needed is (m - a[i] + prev_b) % m.
        // This is possible if (m - a[i] + prev_b) % m <= x.
        // In this case, current_b = prev_b.

        // Let's simplify. We want to find a b_i such that b_i >= prev_b and b_i = (a_i + c_i) % m with c_i <= x.
        // The smallest possible b_i is prev_b.
        // Can we achieve prev_b from a_i with at most x operations?
        // If a_i <= prev_b:
        //   We need to add at least (prev_b - a_i) operations.
        //   If (prev_b - a_i) <= x, then we can set b_i = prev_b.
        //   Otherwise, we cannot reach prev_b. The smallest value we can reach is (a_i + x) % m.
        //   If (a_i + x) % m < prev_b, then it's impossible.
        //   If (a_i + x) % m >= prev_b, then we can set b_i = prev_b.
        //   This means if a_i <= prev_b, we need to check if (a_i + x) >= prev_b.
        //   If (a_i + x) >= prev_b, then we can set b_i = prev_b.
        //   Otherwise, it's impossible.
        // If a_i > prev_b:
        //   We can set b_i = a_i (0 operations). This is valid as a_i >= prev_b.
        //   Or we can increment a_i.
        //   If (a_i + x) % m < prev_b, it means we wrapped around and ended up below prev_b.
        //   This is only possible if a_i + x >= m.
        //   If a_i + x >= m and (a_i + x) % m < prev_b, then we cannot achieve prev_b.
        //   In this case, we must use a_i as b_i.
        //   If a_i + x < m, then (a_i + x) % m = a_i + x. Since a_i > prev_b, a_i + x > prev_b.
        //   So we can always set b_i = a_i.
        //   The only problematic case is when a_i > prev_b, but (a_i + x) % m < prev_b.
        //   This means we must have incremented a_i past m, and the resulting value is too small.
        //   In this case, we must choose b_i = a_i.

        // Let's re-evaluate the condition for b_i.
        // We need b_i >= prev_b.
        // We can choose b_i = a_i if a_i >= prev_b. This requires 0 operations.
        // We can choose b_i = (a_i + c) % m where 0 < c <= x.
        // The smallest value we can achieve for b_i is prev_b.
        // The largest value we can achieve for b_i is (a_i + x) % m.

        // If a_i >= prev_b:
        //   We can potentially keep a_i as is (0 operations).
        //   Or we can increment it. If we increment it such that it wraps around
        //   and becomes less than prev_b, that's bad.
        //   This happens if (a_i + x) >= m AND (a_i + x) % m < prev_b.
        //   If this happens, we must choose b_i = a_i.
        //   Otherwise, we can choose b_i = prev_b (if prev_b is reachable) or b_i = a_i.
        //   Since a_i >= prev_b, we can always choose b_i = a_i.
        //   So if a_i >= prev_b, we check if (a_i + x) % m < prev_b.
        //   If it is, then we must use a_i as current_b.
        //   Otherwise, we can use prev_b as current_b.
        //   This means if a_i >= prev_b:
        //     If (a_i + x) < m: (no wrap-around for a_i+x)
        //       Then (a_i + x) % m = a_i + x. Since a_i >= prev_b, a_i + x >= prev_b.
        //       So we can choose b_i = prev_b.
        //     Else (a_i + x) >= m: (wrap-around for a_i+x)
        //       Then (a_i + x) % m could be < prev_b.
        //       If (a_i + x) % m < prev_b, we must choose b_i = a_i.
        //       Else ((a_i + x) % m >= prev_b), we can choose b_i = prev_b.
        //   This can be summarized: if a_i >= prev_b, and (a_i + x) % m < prev_b, then current_b = a_i.
        //   Otherwise, current_b = prev_b.

        // If a_i < prev_b:
        //   We must increment a_i.
        //   We need to reach at least prev_b.
        //   The number of increments needed to reach prev_b is (prev_b - a_i).
        //   If (prev_b - a_i) <= x, then we can set b_i = prev_b.
        //   Otherwise, we cannot reach prev_b. The maximum we can reach is (a_i + x) % m.
        //   If (a_i + x) % m < prev_b, then it's impossible.
        //   So if a_i < prev_b, we need to check if (a_i + x) >= prev_b.
        //   If (a_i + x) >= prev_b, then we can set b_i = prev_b.
        //   Otherwise, it's impossible.
        //   This means if a_i < prev_b:
        //     If (a_i + x) < prev_b, return false.
        //     Else, current_b = prev_b.

        // Combining these:
        // If a_i >= prev_b:
        //   If (a_i + x) >= m && (a_i + x) % m < prev_b:
        //     current_b = a_i;
        //   Else:
        //     current_b = prev_b;
        // Else (a_i < prev_b):
        //   If (a_i + x) < prev_b:
        //     return false;
        //   Else:
        //     current_b = prev_b;

        // This logic is still a bit convoluted. Let's simplify.
        // We want to find the smallest b_i >= prev_b such that b_i = (a_i + c) % m for some c <= x.
        //
        // Option 1: b_i is obtained without wrapping around m.
        //   This means b_i = a_i + c.
        //   We need a_i + c >= prev_b.
        //   The smallest such c is max(0LL, prev_b - a_i).
        //   If this c <= x, and a_i + c < m, then we can set b_i = a_i + c.
        //   In this case, b_i = max(prev_b, a_i).
        //   This is valid if max(prev_b, a_i) - a_i <= x.
        //   And max(prev_b, a_i) < m.
        //
        // Option 2: b_i is obtained by wrapping around m.
        //   This means b_i = (a_i + c) % m where a_i + c >= m.
        //   The smallest such b_i that is >= prev_b is prev_b itself.
        //   To reach prev_b from a_i by wrapping around, we need to add (m - a_i + prev_b) % m operations.
        //   Let c_wrap = (m - a_i + prev_b) % m.
        //   If c_wrap <= x, then we can set b_i = prev_b.
        //
        // Let's consider the two possible values for b_i:
        // 1. b_i = prev_b. This is possible if a_i can be incremented to prev_b using at most x operations.
        //    The number of operations needed is `ops_to_prev_b`.
        //    If a_i <= prev_b, `ops_to_prev_b = prev_b - a_i`.
        //    If a_i > prev_b, `ops_to_prev_b = m - a_i + prev_b`.
        //    If `ops_to_prev_b <= x`, then we can set `current_b = prev_b`.
        // 2. b_i = a_i. This is possible if a_i >= prev_b. This requires 0 operations.
        //    If we choose b_i = a_i, we must ensure that a_i is not "too large" such that
        //    (a_i + x) % m would be less than prev_b.
        //    This means if a_i >= prev_b, we can potentially use a_i.
        //    But if (a_i + x) % m < prev_b, it means we *could* have incremented a_i past m
        //    and ended up with a value smaller than prev_b.
        //    In this case, we *must* use a_i as current_b.
        //    Otherwise, we can use prev_b.

        // Correct logic:
        // We need to find a `b_i` such that `prev_b <= b_i < m` and `b_i = (a_i + c_i) % m` for some `0 <= c_i <= x`.
        //
        // There are two main scenarios for `a_i` relative to `prev_b`:
        //
        // Scenario A: `a_i >= prev_b`
        //   In this case, `a_i` itself is a valid candidate for `b_i` (using `c_i = 0` operations).
        //   We can also potentially increment `a_i` up to `x` times.
        //   If we increment `a_i` by `c_i` operations, the new value is `(a_i + c_i) % m`.
        //   We want to keep `b_i` as small as possible, so `prev_b` is the ideal choice.
        //   Can we make `b_i = prev_b`?
        //   This requires `(a_i + c_i) % m = prev_b` for some `c_i <= x`.
        //   If `a_i` is incremented to `prev_b` without wrapping around `m`:
        //     This means `a_i + c_i = prev_b`. Since `a_i >= prev_b`, this implies `c_i <= 0`, so `c_i = 0` and `a_i = prev_b`.
        //     If `a_i = prev_b`, then `c_i = 0` works.
        //   If `a_i` is incremented to `prev_b` by wrapping around `m`:
        //     This means `a_i + c_i = m + prev_b`. So `c_i = m + prev_b - a_i`.
        //     If `m + prev_b - a_i <= x`, then we can achieve `prev_b`.
        //   So, if `a_i >= prev_b`:
        //     If `a_i = prev_b`, we can set `current_b = prev_b`.
        //     If `a_i > prev_b`:
        //       We can set `current_b = a_i` (0 operations). This is always valid.
        //       However, we want to keep `current_b` as small as possible, so `prev_b` is preferred.
        //       Can we reach `prev_b` by incrementing `a_i`? This would require `m - a_i + prev_b` operations.
        //       If `m - a_i + prev_b <= x`, then we can set `current_b = prev_b`.
        //       Otherwise, we must set `current_b = a_i`.
        //
        // Scenario B: `a_i < prev_b`
        //   In this case, `a_i` itself is not a valid candidate for `b_i`. We *must* increment `a_i`.
        //   We need to reach at least `prev_b`.
        //   The number of operations needed to reach `prev_b` is `prev_b - a_i`.
        //   If `prev_b - a_i <= x`, then we can set `current_b = prev_b`.
        //   Otherwise, we cannot reach `prev_b` without wrapping around `m`.
        //   The maximum value we can reach is `(a_i + x) % m`.
        //   If `(a_i + x) % m < prev_b`, then it's impossible to make `b_i >= prev_b`. Return `false`.
        //   Otherwise, `(a_i + x) % m >= prev_b`, so we can set `current_b = prev_b`.
        //   This means if `a_i < prev_b`:
        //     If `a_i + x < prev_b`, return `false`.
        //     Else, `current_b = prev_b`.

        // Let's try to combine this into a single condition for `current_b`.
        // We want to find `b_i` such that `b_i >= prev_b` and `b_i = (a_i + c) % m` for `c <= x`.
        //
        // If `a_i + x < m`:
        //   The values `(a_i + c) % m` for `c <= x` are `a_i, a_i+1, ..., a_i+x`.
        //   We need to pick `b_i` from this range such that `b_i >= prev_b`.
        //   If `a_i + x < prev_b`, then no value in this range is `>= prev_b`. So it's impossible. Return `false`.
        //   Otherwise, `a_i + x >= prev_b`. We can pick `b_i = max(a_i, prev_b)`.
        //   So, if `a_i + x < m`:
        //     If `a_i + x < prev_b`, return `false`.
        //     Else, `current_b = prev_b`. (Because we want smallest possible `b_i`, and `prev_b` is reachable).
        //
        // If `a_i + x >= m`:
        //   The values `(a_i + c) % m` for `c <= x` cover the entire range `[0, m-1]` at least once.
        //   Specifically, they cover `[a_i, m-1]` and `[0, (a_i + x) % m]`.
        //   So, any value `v` in `[0, m-1]` can be reached if `v` is in `[a_i, m-1]` (using `c = v - a_i <= x`)
        //   OR if `v` is in `[0, (a_i + x) % m]` (using `c = m - a_i + v <= x`).
        //   We need to pick `b_i` such that `b_i >= prev_b`.
        //   Can we pick `b_i = prev_b`?
        //   This is possible if `prev_b` is in `[a_i, m-1]` (i.e., `a_i <= prev_b`)
        //   OR if `prev_b` is in `[0, (a_i + x) % m]` (i.e., `prev_b <= (a_i + x) % m`).
        //   So, if `a_i + x >= m`:
        //     If `a_i <= prev_b`:
        //       We can always pick `b_i = prev_b` (using `c = prev_b - a_i` or `c = m - a_i + prev_b`).
        //       Since `a_i + x >= m`, `x` is large enough to wrap around.
        //       The cost to reach `prev_b` from `a_i` is `prev_b - a_i` (if `a_i <= prev_b`) or `m - a_i + prev_b` (if `a_i > prev_b`).
        //       Both of these are `<= x` if `x` is large enough to wrap around.
        //       So if `a_i <= prev_b`, we can always set `current_b = prev_b`.
        //     If `a_i > prev_b`:
        //       We can pick `b_i = a_i` (0 operations). This is valid.
        //       We can also pick `b_i = prev_b` if `prev_b` is reachable.
        //       `prev_b` is reachable if `m - a_i + prev_b <= x`.
        //       If `m - a_i + prev_b <= x`, then we can set `current_b = prev_b`.
        //       Otherwise, we must set `current_b = a_i`.
        //
        // This is the most robust logic:
        //
        // If `a_i >= prev_b`:
        //   We can always choose `b_i = a_i` (0 operations). This satisfies `b_i >= prev_b`.
        //   However, we want to make `b_i` as small as possible, so `prev_b` is preferred.
        //   Can we choose `b_i = prev_b`?
        //   This requires `(a_i + c) % m = prev_b` for some `c <= x`.
        //   The number of operations to reach `prev_b` from `a_i` is `m - a_i + prev_b` (wrapping around).
        //   If `m - a_i + prev_b <= x`, then we can choose `b_i = prev_b`.
        //   Otherwise, we must choose `b_i = a_i`.
        //   So, if `a_i >= prev_b`:
        //     If `m - a_i + prev_b <= x`: `current_b = prev_b`.
        //     Else: `current_b = a_i`.
        //
        // If `a_i < prev_b`:
        //   We must increment `a_i`.
        //   Can we choose `b_i = prev_b`?
        //   This requires `(a_i + c) % m = prev_b` for some `c <= x`.
        //   The number of operations to reach `prev_b` from `a_i` is `prev_b - a_i` (without wrapping).
        //   If `prev_b - a_i <= x`, then we can choose `b_i = prev_b`.
        //   Otherwise, it's impossible to reach `prev_b` without wrapping, and `x` is not large enough to wrap around and reach `prev_b`.
        //   (Because if `x` was large enough to wrap around and reach `prev_b`, then `a_i + x >= m + prev_b`, which implies `a_i + x >= prev_b` and `a_i + x >= m`.
        //   If `a_i + x >= prev_b` and `a_i + x < m`, then `prev_b - a_i <= x`.
        //   If `a_i + x >= m` and `(a_i + x) % m < prev_b`, then it's impossible.
        //   If `a_i + x >= m` and `(a_i + x) % m >= prev_b`, then it's possible.
        //   This is equivalent to checking if `a_i + x >= prev_b`.
        //   So, if `a_i < prev_b`:
        //     If `a_i + x < prev_b`: return `false`.
        //     Else: `current_b = prev_b`.

        if (current_a >= prev_b) {
            // Option 1: Keep current_a as is. This is valid (0 operations).
            // Option 2: Try to make it prev_b. This requires (m - current_a + prev_b) % m operations.
            // If (m - current_a + prev_b) % m <= x, we can make it prev_b.
            // The cost to reach prev_b from current_a is `cost = (m - current_a + prev_b) % m`.
            // If current_a == prev_b, cost is 0.
            // If current_a > prev_b, cost is `m - current_a + prev_b`.
            // If `m - current_a + prev_b <= x`, we can set `current_b = prev_b`.
            // Otherwise, we must set `current_b = current_a`.
            if (current_a == prev_b) {
                current_b = prev_b;
            } else { // current_a > prev_b
                if (m - current_a + prev_b <= x) {
                    current_b = prev_b;
                } else {
                    current_b = current_a;
                }
            }
        } else { // current_a < prev_b
            // We must increment current_a.
            // The minimum operations to reach prev_b is `prev_b - current_a`.
            // If `prev_b - current_a <= x`, we can make it prev_b.
            // Otherwise, it's impossible to reach prev_b.
            if (prev_b - current_a <= x) {
                current_b = prev_b;
            } else {
                return false; // Cannot make a_i >= prev_b
            }
        }
        prev_b = current_b;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

