#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The simplest way to get a different permutation with the same fingerprint
        // is to reverse the original permutation.
        // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
        // Let p' be the reverse of p: p' = [p_n, p_{n-1}, ..., p_1]
        // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
        // The set of adjacent sums is the same, just in reverse order.
        // Therefore, after sorting, F(p) will be equal to F(p').
        // The only case where p' might be equal to p is if p is a palindrome.
        // However, a permutation of distinct integers from 1 to n cannot be a palindrome
        // unless n=1 (which is not allowed, n>=2) or n=0.
        // For n >= 2, p_1 must be different from p_n.
        // If p_1 = p_n, then p is not a permutation because elements must be distinct.
        // Thus, p_1 != p_n, which means p cannot be a palindrome.
        // Therefore, reversing p always yields a different permutation p'.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

