void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;
    int half_color_toggle = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // White
        } else if (a[i] > T_half) {
            p[i] = 1; // Black
        } else { // a[i] == T_half
            if (T_is_even) {
                p[i] = half_color_toggle;
                half_color_toggle = 1 - half_color_toggle; // Toggle for the next T/2 element
            } else { // T is odd, so a[i] cannot be T/2. This branch should not be reached if a[i] == T/2.
                     // But if T is odd, T/2 is not an integer, so a[i] can never be exactly T/2.
                     // This means a[i] == T_half (integer division) implies a[i] < T/2 or a[i] > T/2.
                     // So this else branch only executes if T is even and a[i] == T/2.
                p[i] = 0; // Default to white if T is odd and a[i] somehow equals T_half (which is impossible)
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

