#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. It's always beautiful.
        // For m > 1, we expand the segment to include m.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1...m]) to max(pos[1...m]).
        // Let's maintain current_min_idx and current_max_idx for numbers 1 to m-1.
        // When considering m, we update these to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A segment [l, r] is a permutation of [1, ..., m] if:
        // 1. It contains all numbers from 1 to m.
        //    This is guaranteed if l = current_min_idx and r = current_max_idx.
        // 2. Its length is m.
        //    So, current_max_idx - current_min_idx + 1 must be equal to m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

