            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 is true for d >= 4
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a1 and b1 will be non-negative because:
            // d >= 4 implies d^2 >= 4d, so d^2 - 4d >= 0.
            // sqrt(d^2 - 4d) <= sqrt(d^2) = d (since d >= 0).
            // So d - sqrt(d^2 - 4d) >= 0.
            // Thus, both a1 and b1 are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

