    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (the 'a' array elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, we can advance j.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        // If a[j] is greater than a[i], we found a match. We increment count,
        // and then we need to use both a[i] and a[j], so we increment both i and j.
        // The outer loop already increments i, so we just need to increment j.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element for the 'b' array
        } else {
            // No more elements in 'a' (from index j onwards) are greater than a[i].
            // We can stop trying to find matches for the remaining a[i]'s.
            break;
        }
    }

    std::cout << count << std::endl;

