void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We want (current_sum + b1 + b2 + ...) = 2 * (current_xor ^ b1 ^ b2 ^ ...)
    // Let S = current_sum, X = current_xor
    // We want S_new = 2 * X_new

    // Case 1: Append two elements
    // Let b1 = X, b2 = S + X
    // New XOR sum: X_new = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X
    // New sum: S_new = S + b1 + b2 = S + X + (S + X) = 2S + 2X
    // Check condition: S_new = 2 * X_new
    // 2S + 2X = 2 * (S + X)
    // This is always true.
    // So, we can always append X and S+X.
    // The problem states that appended elements don't have to be different.
    // If X = 0, then b1 = 0, b2 = S.
    // If S+X = 0, then b2 = 0.
    // The values can be large, up to 10^18, which fits in long long.

    // The problem asks to append AT MOST 3 elements.
    // If the array is already good, we can append 0 elements.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // Otherwise, append two elements: current_xor and current_sum + current_xor
        std::cout << 2 << std::endl;
        std::cout << current_xor << " " << current_sum + current_xor << std::endl;
    }
}

