// Function to determine if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // To end up in Box 1, the final product must be negative and its absolute value >= 1.
    // This means the total number of negative factors must be odd.
    // And the product of absolute values must be >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of negative toys.
    // The initial number of negative toys is A + B.
    // If A + B is odd, the final product can be negative.
    // If A + B is even, the final product can only be negative if we introduce a negative toy
    // by multiplying a positive and a negative. But the total count of negative factors
    // in the final product is fixed by the initial count of negative toys.
    // So, (A + B) % 2 == 1 is a necessary condition for a negative final product.

    if ((A + B) % 2 == 0) { // Final product must be positive
        return false;
    }

    // Now we know the final product is negative. We need its absolute value to be >= 1.
    // This means we need at least one toy with |value| > 1 (from Box 1 or Box 4)
    // that is not "cancelled out" by too many toys with |value| < 1 (from Box 2 or Box 3).

    // If there are any toys in Box 1 or Box 4 (i.e., A + D > 0),
    // it's possible to make the absolute value >= 1.
    // We can always pick a toy from Box 1 or Box 4, and multiply it with other toys.
    // If we have at least one toy with |val| >= 1, and we have an odd number of negative toys,
    // we can arrange multiplications to keep the absolute value >= 1.
    // For example, if we have a toy with value X >= 1, and many toys with |Y| < 1.
    // We can multiply X with another toy Z. If Z is also |Z| >= 1, product is |XZ| >= 1.
    // If Z is |Z| < 1, product is |XZ|. This might be < 1.
    // However, we can strategically multiply.
    // If A+D > 0, we have at least one "strong" toy.
    // If B+C > 0, we have "weak" toys.
    // If we have a strong toy (from A or D) and an odd number of negative toys (A+B odd),
    // we can always ensure the final product's absolute value is >= 1.
    // Example: Take all B+C toys and multiply them together. This product P_weak will have |P_weak| < 1.
    // Then take all A+D toys and multiply them together. This product P_strong will have |P_strong| >= 1.
    // Finally, multiply P_weak and P_strong. The result |P_weak * P_strong| could be < 1.
    // This strategy is not good.

    // A better strategy:
    // If A+D > 0, we have at least one toy with |value| >= 1.
    // If we have an odd number of negative toys, we can always make the final product negative.
    // To ensure |final_product| >= 1:
    // If A+D > 0, we can pick one toy X from Box 1 or Box 4.
    // We can multiply all other N-1 toys together. Let their product be P_other.
    // The final product is X * P_other.
    // If P_other has |P_other| >= 1, then |X * P_other| >= 1.
    // If P_other has |P_other| < 1, then |X * P_other| could be < 1.
    // However, we can choose the values.
    // If A+D > 0, we can assign values such that one toy is very large (e.g., 1000) or very small (e.g., -1000).
    // All other toys can be assigned values very close to 1 (e.g., 0.99 or -0.99).
    // If A+B is odd, we can ensure the final product is negative.
    // If A+D > 0, we can ensure the absolute value is large enough.
    // For example, if A=1, B=0, C=0, D=0. Toy is -3. Box 1. Yes.
    // If A=1, B=1, C=0, D=0. Toys -3, -0.5. Product 1.5. Box 4. No.
    // If A=1, B=2, C=0, D=0. Toys -3, -0.5, -0.5. Product -0.75. Box 2. No.
    // This implies that having A+D > 0 is not sufficient.

    // Let's re-evaluate.
    // To end up in Box 1: negative, |value| >= 1.
    // Condition 1: (A + B) % 2 == 1 (odd number of negative toys).
    // Condition 2: The product of absolute values must be >= 1.
    // This means we need "enough" toys with |value| > 1 to overcome toys with |value| < 1.
    // If A + D > 0, we have at least one toy with |value| >= 1.
    // If B + C > 0, we have at least one toy with |value| < 1.
    // If A + D == 0, then all toys have |value| < 1. The final product will have |value| < 1. So Box 1 is impossible.
    // If A + D > 0:
    // We can pick one toy X from A or D, and assign it a very large absolute value (e.g., 10^9).
    // All other toys can be assigned values very close to 1 (e.g., 0.999 or -0.999).
    // If A+B is odd, we can ensure the final product is negative.
    // With one very large absolute value, the final product's absolute value will be very large.
    // So, if (A + B) % 2 == 1 AND (A + D > 0), then Box 1 is possible.
    return (A + B) % 2 == 1 && (A + D > 0);
}

// Function to determine if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // To end up in Box 2, the final product must be negative and its absolute value < 1.
    // Condition 1: (A + B) % 2 == 1 (odd number of negative toys).

    if ((A + B) % 2 == 0) { // Final product must be positive
        return false;
    }

    // Condition 2: The product of absolute values must be < 1.
    // This means we need "enough" toys with |value| < 1 to overcome toys with |value| > 1.
    // If B + C > 0, we have at least one toy with |value| < 1.
    // If B + C == 0, then all toys have |value| >= 1. The final product will have |value| >= 1. So Box 2 is impossible.
    // If B + C > 0:
    // We can pick one toy X from Box 2 or Box 3, and assign it a very small absolute value (e.g., 10^-9).
    // All other toys can be assigned values very close to 1 (e.g., 0.999 or -0.999).
    // If A+B is odd, we can ensure the final product is negative.
    // With one very small absolute value, the final product's absolute value will be very small.
    // So, if (A + B) % 2 == 1 AND (B + C > 0), then Box 2 is possible.
    return (A + B) % 2 == 1 && (B + C > 0);
}

// Function to determine if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // To end up in Box 3, the final product must be positive and its absolute value < 1.
    // Condition 1: (A + B) % 2 == 0 (even number of negative toys).

    if ((A + B) % 2 == 1) { // Final product must be negative
        return false;
    }

    // Condition 2: The product of absolute values must be < 1.
    // This means we need "enough" toys with |value| < 1.
    // If B + C == 0, then all toys have |value| >= 1. The final product will have |value| >= 1. So Box 3 is impossible.
    // If B + C > 0:
    // We can pick one toy X from Box 2 or Box 3, and assign it a very small absolute value (e.g., 10^-9).
    // All other toys can be assigned values very close to 1 (e.g., 0.999 or -0.999).
    // If A+B is even, we can ensure the final product is positive.
    // With one very small absolute value, the final product's absolute value will be very small.
    // So, if (A + B) % 2 == 0 AND (B + C > 0), then Box 3 is possible.
    return (A + B) % 2 == 0 && (B + C > 0);
}

// Function to determine if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // To end up in Box 4, the final product must be positive and its absolute value >= 1.
    // Condition 1: (A + B) % 2 == 0 (even number of negative toys).

    if ((A + B) % 2 == 1) { // Final product must be negative
        return false;
    }

    // Condition 2: The product of absolute values must be >= 1.
    // This means we need "enough" toys with |value| > 1.
    // If A + D == 0, then all toys have |value| < 1. The final product will have |value| < 1. So Box 4 is impossible.
    // If A + D > 0:
    // We can pick one toy X from Box 1 or Box 4, and assign it a very large absolute value (e.g., 10^9).
    // All other toys can be assigned values very close to 1 (e.g., 0.999 or -0.999).
    // If A+B is even, we can ensure the final product is positive.
    // With one very large absolute value, the final product's absolute value will be very large.
    // So, if (A + B) % 2 == 0 AND (A + D > 0), then Box 4 is possible.
    return (A + B) % 2 == 0 && (A + D > 0);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        // Special case: If total toys is 1, that toy is the super toy.
        // The problem states A+B+C+D > 0.
        if (A + B + C + D == 1) {
            std::cout << (A == 1 ? "Ya" : "Tidak") << " ";
            std::cout << (B == 1 ? "Ya" : "Tidak") << " ";
            std::cout << (C == 1 ? "Ya" : "Tidak") << " ";
            std::cout << (D == 1 ? "Ya" : "Tidak") << "\n";
            continue;
        }

        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

