// Function to convert a number to its 18-digit parity string
std::string to_parity_string(long long n) {
    std::string s = "";
    if (n == 0) {
        s = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                s += '0';
            } else {
                s += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's (even) from the left to make it 18 digits long
    while (s.length() < 18) {
        s += '0';
    }
    return s;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_string(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_string(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the pattern with '0's (even) from the left to make it 18 digits long
            std::string padded_s = s;
            std::reverse(padded_s.begin(), padded_s.end()); // Reverse to match right-to-left digit processing
            while (padded_s.length() < 18) {
                padded_s += '0';
            }
            // The map stores keys as right-to-left parity strings.
            // So, the query pattern also needs to be right-to-left.
            // The `to_parity_string` function already builds the string right-to-left.
            // The input pattern `s` is given left-to-right.
            // Example: s = "010" means 0 (leftmost) 1 (middle) 0 (rightmost).
            // For matching, we need to compare rightmost digit of number with rightmost of pattern.
            // `to_parity_string` gives "010" for 92 (2 is rightmost, 9 is leftmost).
            // So, if pattern is "010", its rightmost is '0', middle '1', leftmost '0'.
            // The `padded_s` variable already has the correct right-to-left representation after reversing `s` and padding.

            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;
        long long left_items_weight = prefix_sum[i];
        long long right_items_weight = prefix_sum[n] - prefix_sum[i];

        current_energy += left_items_weight * l;
        current_energy += right_items_weight * r;

        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left. The last item must have been from left.
            // The difference is num_left - num_right.
            // We need to add Ql for (num_left - num_right - 1) extra left items.
            // This is equivalent to (num_left - num_right) - 1 times Ql.
            // If num_left = num_right + 1, then no extra Ql.
            // If num_left = num_right + 2, then 1 extra Ql.
            // So, max(0, num_left - num_right - 1) * Ql
            current_energy += std::max(0, num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right. The last item must have been from right.
            // The difference is num_right - num_left.
            // We need to add Qr for (num_right - num_left - 1) extra right items.
            current_energy += std::max(0, num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no extra cost.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

