int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL;
        long long max_y = 2000000000LL;

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1: can move left (x-1). If f1=0, cannot move left.
            // So, if f1=0, target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 1: can move right (x+1). If f3=0, cannot move right.
            // So, if f3=0, target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 1: can move down (y-1). If f4=0, cannot move down.
            // So, if f4=0, target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 1: can move up (y+1). If f2=0, cannot move up.
            // So, if f2=0, target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least f_i^a_i for all i.
        // To make x not divisible by q, we must remove at least one prime factor f_i
        // from p enough times such that the power of f_i in x is less than a_i.
        // We want to maximize x, so we should remove as few factors as possible.
        // For each prime factor f_i of q, we can form a candidate x by dividing p by f_i
        // until the power of f_i in x is less than a_i.
        // Specifically, if p = f_i^b_i * R and q = f_i^a_i * S, where R and S are not divisible by f_i.
        // If b_i >= a_i, then p is divisible by f_i^a_i.
        // We want to find x = p / f_i^k such that (p / f_i^k) % q != 0.
        // The smallest k that makes (p / f_i^k) not divisible by f_i^a_i is k = b_i - a_i + 1.
        // So, for each prime factor f_i of q, we can consider x = p / f_i^(b_i - a_i + 1).
        // We take the maximum of these candidates.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            int a = factor_pair.second; // exponent of f in q

            // Calculate the exponent of f in p
            long long temp_p = p;
            int b = 0; // exponent of f in p
            while (temp_p > 0 && temp_p % f == 0) {
                temp_p /= f;
                b++;
            }

            // If f is a prime factor of q, and p is divisible by f^b, q is divisible by f^a.
            // If b < a, then p is not divisible by q (contradicts initial check p%q==0).
            // So we must have b >= a.
            // To make x not divisible by q, we need to reduce the power of f in x to be less than a.
            // The largest such x would be p / f^(b - a + 1).
            // This ensures that the power of f in x is b - (b - a + 1) = a - 1, which is < a.
            // This candidate x is p / (f^(b-a+1)).
            long long current_x = p;
            for (int i = 0; i < (b - a + 1); ++i) {
                current_x /= f;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1 is odd. Opponent takes 1. N-2.
                // Chanek gets 1. Opponent gets 1.
                // This path is generally worse if N/2 is a good move.

                // Option 2: Take N/2 coins
                // Remaining N/2.
                // This is the main decision point.

                // If N is a power of 2 (and N > 2), taking N/2 leaves N/2, which is also a power of 2.
                // The opponent will also take half, and so on.
                // Example: N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.
                // If N=8. Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                // For powers of 2, taking N/2 seems optimal.

                // If N is even but not a power of 2, say N = 2^k * M where M is odd and M > 1.
                // Example: N=6.
                // Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Chanek takes N/2=3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Both give 4.

                // Example: N=10.
                // Chanek takes 1: N=9. Opponent takes 1. N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+4+1=6. Opponent: 1+2+1=4.
                // Chanek takes N/2=5: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 5+2+1=8. Opponent: 1+1+1=3.
                // Taking N/2 is better for N=10.

                // The strategy for an even N:
                // If N is a power of 2 (N = 2^k, k >= 1):
                //   Taking N/2 is always optimal. The opponent will also take half, and so on.
                //   This leads to Chanek getting N/2 + N/8 + N/32 + ... and Opponent getting N/4 + N/16 + ...
                //   Total Chanek coins = N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * (1/2) / (3/4) = N * (2/3).
                //   This is not quite right because the game ends when N=1.
                //   For N=2^k, Chanek takes 2^(k-1), then 2^(k-3), ..., 2^1 (if k is odd) or 2^0 (if k is even).
                //   Opponent takes 2^(k-2), 2^(k-4), ..., 2^0 (if k is odd) or 2^1 (if k is even).
                //   The last coin is taken by Chanek if k is odd, by Opponent if k is even.
                //   Actually, the last coin is taken by the player whose turn it is when N=1.
                //   If N=2^k, Chanek takes 2^(k-1). N=2^(k-1).
                //   Opponent takes 2^(k-2). N=2^(k-2).
                //   ...
                //   This continues until N=1.
                //   If k is odd, Chanek takes 2^(k-1), 2^(k-3), ..., 2^0.
                //   If k is even, Chanek takes 2^(k-1), 2^(k-3), ..., 2^1. Opponent takes 2^0.
                //   This is equivalent to: Chanek takes N/2. If N/2 is odd, opponent takes 1. If N/2 is even, opponent takes N/4.
                //   This is simpler: if N is a power of 2, Chanek takes N/2. The remaining N/2 is also a power of 2.
                //   The game continues with N/2.
                //   This means Chanek gets N/2 + (N/8) + (N/32) + ...
                //   Opponent gets (N/4) + (N/16) + ...
                //   The last coin (1) is taken by the player whose turn it is when N=1.
                //   If N=2^k, there are k turns of taking half.
                //   If k is odd, Chanek takes 2^(k-1), 2^(k-3), ..., 2^0.
                //   If k is even, Chanek takes 2^(k-1), 2^(k-3), ..., 2^1. Opponent takes 2^0.
                //   This is equivalent to: Chanek gets sum of 2^i for i = k-1, k-3, ... (until i >= 0).
                //   Opponent gets sum of 2^i for i = k-2, k-4, ... (until i >= 0).
                //   Total coins for Chanek = N - (total coins for Opponent).
                //   For N=2^k, Chanek gets N/2 + N/8 + ...
                //   Opponent gets N/4 + N/16 + ...
                //   The sum of a geometric series 1 + r + r^2 + ... + r^(m-1) = (1-r^m)/(1-r).
                //   Sum of 2^i from i=0 to k-1 is 2^k - 1 = N-1.
                //   Chanek's coins: (N/2) + (N/8) + ...
                //   Opponent's coins: (N/4) + (N/16) + ...
                //   This is not simple. Let's re-evaluate.

                // The key insight for even N:
                // If N is even, Chanek has two choices:
                // 1. Take 1 coin: N becomes N-1 (odd). Opponent must take 1. N becomes N-2 (even).
                // 2. Take N/2 coins: N becomes N/2.
