#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long mod = 1000000007;
    long long n_mod = n % mod;
    long long n_plus_1_mod = (n + 1) % mod;
    long long two_inv = 500000004; // Modular inverse of 2 mod 10^9 + 7

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    long long sum = (term1 * term2) % mod;
    sum = (sum * two_inv) % mod;
    return sum;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long mod = 1000000007;

    // Sum of r from 1 to b-1: (b-1)*b/2
    long long sum_r = sum_arithmetic_series(b - 1);

    // Sum of (k*b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a*(a+1)/2) + a
    long long sum_kb_plus_1_term1 = (b % mod * sum_arithmetic_series(a)) % mod;
    long long sum_kb_plus_1_term2 = a % mod;
    long long sum_kb_plus_1 = (sum_kb_plus_1_term1 + sum_kb_plus_1_term2) % mod;

    long long total_sum = (sum_r * sum_kb_plus_1) % mod;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos_char(26);
    for (int i = 0; i < L; ++i) {
        pos_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char char0 = s[k_actual];
        int char0_idx = char0 - 'a';

        // Step 1: Vasya knows char0.
        // Find all possible k's that could result in this char0.
        const std::vector<int>& possible_k_for_char0 = pos_char[char0_idx];

        if (possible_k_for_char0.empty()) { // Should not happen for valid k_actual
            continue;
        }

        // If there's only one k that produces char0, Vasya wins immediately.
        // This is not how the game works. Vasya must choose a position p.
        // The problem states "after he sees it, open one more letter on some position".
        // So, even if char0 uniquely determines k, Vasya still has to pick p.
        // The condition for winning is "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
        // This means after knowing t[0] and t[p], there must be exactly one k_candidate.

        // Vasya plays optimally, so he will choose p to maximize his win probability for this specific char0.
        double max_win_prob_for_char0 = 0.0;

        // Iterate over all possible positions p (1 to L-1) Vasya can choose.
        for (int p = 1; p < L; ++p) {
            // For a fixed char0 and a chosen p, what is the probability of winning?
            // This probability is (number of k_candidates that lead to unique (char0, char_p) pair) / (total number of k_candidates for char0)

            // We need to count how many (char0, char_p) pairs, for this fixed p,
            // lead to a unique k_candidate.

            // Map to store counts of (char0, char_p) pairs for the current p
            // key: char_p, value: count of k_candidates that produce this char_p
            std::vector<int> char_p_counts(26, 0);

            for (int k_cand : possible_k_for_char0) {
                char char_p = s[(k_cand + p) % L];
                char_p_counts[char_p - 'a']++;
            }

            int unique_k_count = 0;
            for (int count : char_p_counts) {
                if (count == 1) {
                    unique_k_count++;
                }
            }

            // The probability of winning for this specific char0 and chosen p
            // is the number of unique (char0, char_p) pairs divided by the total number of k_candidates for char0.
            // This is because each k_candidate for char0 is equally likely to be the actual k.
            // If the actual k is one of those that results in a unique (char0, char_p) pair, Vasya wins.
            double current_p_win_prob = (double)unique_k_count / possible_k_for_char0.size();
            max_win_prob_for_char0 = std::max(max_win_prob_for_char0, current_p_win_prob);
        }

        // Each k_actual is chosen with probability 1/L.
        // So, we sum up max_win_prob_for_char0 for each k_actual, weighted by 1/L.
        total_win_prob += max_win_prob_for_char0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

