    std::vector<int> right_ones(n, n); // Stores index of nearest 1 to the right (inclusive)
    std::vector<int> left_zeros(n, -1); // Stores index of nearest 0 to the left (inclusive)
    std::vector<int> right_zeros(n, n); // Stores index of nearest 0 to the right (inclusive)

    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = i;
        } else if (i > 0) {
            left_ones[i] = left_ones[i - 1];
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = i;
        } else if (i < n - 1) {
            right_ones[i] = right_ones[i + 1];
        }
    }

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = i;
        } else if (i > 0) {
            left_zeros[i] = left_zeros[i - 1];
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = i;
        } else if (i < n - 1) {
            right_zeros[i] = right_zeros[i + 1];
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0, might turn to 1
            int r_one = right_ones[i];
            int l_one = left_ones[i];

            if (r_one != n && l_one != -1) { // 0 is surrounded by 1s
                int dist_l = i - l_one;
                int dist_r = r_one - i;

                if (dist_l == dist_r) { // 0 is exactly in the middle of two 1s
                    std::cout << -1 << std::endl;
                    return 0;
                }

                int k_val = std::min(dist_l, dist_r);
                max_k = std::max(max_k, k_val);

                if (dist_l < dist_r) { // Closer to left 1, will become 1
                    final_a[i] = 1;
                } else { // Closer to right 1, will become 1
                    final_a[i] = 1;
                }
            }
        } else { // Current element is 1, might turn to 0
            int r_zero = right_zeros[i];
            int l_zero = left_zeros[i];

            if (r_zero != n && l_zero != -1) { // 1 is surrounded by 0s
                int dist_l = i - l_zero;
                int dist_r = r_zero - i;

                if (dist_l == dist_r) { // 1 is exactly in the middle of two 0s
                    std::cout << -1 << std::endl;
                    return 0;
                }

                int k_val = std::min(dist_l, dist_r);
                max_k = std::max(max_k, k_val);

                if (dist_l < dist_r) { // Closer to left 0, will become 0
                    final_a[i] = 0;
                } else { // Closer to right 0, will become 0
                    final_a[i] = 0;
                }
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.

// dp_val[i][parity] stores the final y value if starting at x=i with the given parity of step.
// dp_val[i][0] means starting at x=i, performing x = x + a[x], y = y + a[x]
// dp_val[i][1] means starting at x=i, performing x = x - a[x], y = y + a[x]
// dp_next_x[i][parity] stores the next x value if starting at x=i with the given parity.
// dp_next_x[i][0] means next x after x = x + a[x]
// dp_next_x[i][1] means next x after x = x - a[x]

// visited[i][parity] is used for cycle detection.
// 0: not visited
// 1: currently visiting (in recursion stack)
// 2: finished visiting (value computed)

std::vector<long long> a_arr;
std::vector<std::vector<long long>> dp_val;
std::vector<std::vector<int>> dp_next_x;
std::vector<std::vector<int>> visited;
int N;

// Function to compute the result for a given (x, parity) state.
// parity = 0 for step 2 (x+a[x]), parity = 1 for step 3 (x-a[x])
void solve(int x, int parity) {
    if (x <= 0 || x > N) {
        dp_val[x][parity] = 0; // Base case: terminated, no further y added
        dp_next_x[x][parity] = x; // Base case: x remains x (or some indicator)
        visited[x][parity] = 2;
        return;
    }

    if (visited[x][parity] == 1) { // Cycle detected
        dp_val[x][parity] = -1;
        dp_next_x[x][parity] = -1; // Indicate cycle
        visited[x][parity] = 2;
        return;
    }
    if (visited[x][parity] == 2) { // Already computed
        return;
    }

    visited[x][parity] = 1; // Mark as currently visiting

    long long current_a_x = a_arr[x];
    int next_x;
    int next_parity = 1 - parity; // Alternate parity for the next step

    if (parity == 0) { // Current step is x = x + a[x]
        next_x = x + current_a_x;
    } else { // Current step is x = x - a[x]
        next_x = x - current_a_x;
    }

    // Handle out-of-bounds next_x for dp table access
    int effective_next_x;
    if (next_x <= 0) effective_next_x = 0; // Map all x <= 0 to index 0
    else if (next_x > N) effective_next_x = N + 1; // Map all x > N to index N+1
    else effective_next_x = next_x;

    solve(effective_next_x, next_parity); // Recursively solve for the next state

    long long next_y_val = dp_val[effective_next_x][next_parity];
    int final_next_x = dp_next_x[effective_next_x][next_parity];

    if (next_y_val == -1) { // If the next state leads to a cycle
        dp_val[x][parity] = -1;
        dp_next_x[x][parity] = -1;
    } else {
        dp_val[x][parity] = current_a_x + next_y_val;
        dp_next_x[x][parity] = final_next_x;
    }

    visited[x][parity] = 2; // Mark as finished
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    // a_arr is 1-indexed, so size N+1.
    // We will temporarily set a_arr[1] for each query.
    // The input a_2, ..., a_N means a_arr[2] to a_arr[N].
    a_arr.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_arr[i];
    }

    // dp_val and dp_next_x need to store results for x from 0 to N+1.
    // Index 0 for x <= 0, Index N+1 for x > N.
    // Parity 0 for x+a[x], Parity 1 for x-a[x].
    dp_val.resize(N + 2, std::vector<long long>(2));
    dp_next_x.resize(N + 2, std::vector<int>(2));
    visited.resize(N + 2, std::vector<int>(2, 0));

    // Precompute for all possible (x, parity) states.
    // We iterate x from N down to 1 to potentially benefit from memoization
    // if a[x] is small, but the recursive calls handle arbitrary jumps.
    // The loop order doesn't strictly matter for correctness due to recursion + memoization.
    for (int x = 1; x <= N; ++x) {
        for (int parity = 0; parity < 2; ++parity) {
            if (visited[x][parity] == 0) {
                solve(x, parity);
            }
        }
    }

    // For each i from 1 to N-1, set a_arr[1] = i and run.
    for (int i = 1; i < N; ++i) {
        a_arr[1] = i; // Set a_1 for this run

        // Initial state: x=1, y=0. First operation is x = x + a[x], y = y + a[x].
        // This corresponds to calling solve(1, 0).
        // The value a_arr[1] is used in the first step.
        // The result is a_arr[1] + dp_val[1][0] (if not -1).

        // We need to re-calculate for (1,0) and (1,1) because a_arr[1] changes.
        // However, the problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a_1 is set to i.
        // The first step is x=1, y=0. Then x becomes 1 + a_1, y becomes 0 + a_1.
        // The next state is (1 + a_1, 1) (x-a[x] step).
        // So we need to compute the value for (1+a_1, 1) and add a_1 to it.
        // The values for (x, parity) where x != 1 are already computed and valid.
        // Only the path starting from x=1 is affected by changing a_arr[1].

        long long current_a_1 = a_arr[1];
        int next_x_from_1 = 1 + current_a_1;
        int effective_next_x_from_1;
        if (next_x_from_1 <= 0) effective_next_x_from_1 = 0;
        else if (next_x_from_1 > N) effective_next_x_from_1 = N + 1;
        else effective_next_x_from_1 = next_x_from_1;

        long long result_y = dp_val[effective_next_x_from_1][1]; // Next step is parity 1 (x-a[x])

        if (result_y == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_a_1 + result_y << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Max possible length for a good substring.
    // If len = f(binary_string), then len <= 2^len - 1.
    // For len = 1, f(1) = 1.
    // For len = 2, f(10) = 2, f(11) = 3.
    // For len = 18, 2^18 = 262144.
    // For len = 19, 2^19 = 524288.
    // If len is around 20, f(binary_string) can be up to 2^20 - 1.
    // The maximum value of len for which we can have len = f(binary_string)
    // is limited by the maximum value of f(binary_string) that can be represented
    // by a substring of length N.
    // If N = 2e5, then f(binary_string) can be at most 2e5.
    // 2^17 = 131072, 2^18 = 262144.
    // So, if len > 18, then f(binary_string) would be at least 2^18 = 262144,
    // which is greater than N.
    // Thus, the maximum possible length of a good substring is around 18-20.
    // Let's use a safe upper bound, say 20.
    const int MAX_GOOD_LEN = 20; // log2(2e5) approx 17.6. So 18 or 19 is enough. 20 is safe.

    for (int i = 0; i < n; ++i) {
        // Case 1: Substring starts with '1'
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                current_val = (current_val << 1) | (s[j] - '0');
                int len = j - i + 1;

                // Optimization: If current_val exceeds MAX_GOOD_LEN,
                // then for any longer substring starting at i, current_val will only grow.
                // Since len also grows, current_val will quickly outpace len.
                // Specifically, if current_val > len + MAX_GOOD_LEN, it's unlikely to be good.
                // A tighter bound: if current_val > n, it can't be a good substring length.
                // Also, if len > MAX_GOOD_LEN, then current_val will be much larger than len.
                // For example, if len = 20, current_val can be up to 2^20-1.
                // If len = 20, current_val = 20 is only possible if it's 0...010100.
                // But we are starting with '1', so current_val >= 2^(len-1).
                // If len > MAX_GOOD_LEN, then 2^(len-1) is already much larger than len.
                // E.g., if len = 21, 2^20 = 1048576, which is >> 21.
                // So we can break early if len exceeds MAX_GOOD_LEN.
                if (len > MAX_GOOD_LEN && current_val > len + MAX_GOOD_LEN) { // Heuristic break
                    break;
                }
                if (current_val > n) { // If value exceeds max possible length of string, it can't be a good length.
                    break;
                }
                if (current_val == len) {
                    count++;
                }
            }
        }
    }

    // Case 2: Substring starts with '0'
    // These substrings are of the form 0...01...
    // We need to count leading zeros.
    // For each '1' at index `j`, we can form substrings `s[i...j]` where `i <= j`.
    // If `s[i...j]` is `0...01...`, its value `f(s[i...j])` is determined by the part after leading zeros.
    // Let `k` be the index of the first '1' in `s[i...j]`.
    // Then `f(s[i...j]) = f(s[k...j])`.
    // The length is `j - i + 1`.
    // We need `j - i + 1 = f(s[k...j])`.
    // This means `i = j + 1 - f(s[k...j])`.
    // For a fixed `j` and `k` (where `s[k] == '1'`), we need to find `i` such that `i < k` and `s[i...k-1]` are all '0's.
    // The number of such `i` is `k - (j + 1 - f(s[k...j]))`.
    // This is `k - (target_i)`.
    // We need `target_i >= 0` and `target_i < k`.
    // So, `0 <= j + 1 - f(s[k...j]) < k`.

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    for (int j = 0; j < n; ++j) { // `j` is the right endpoint of the substring
        if (s[j] == '0') {
            // Find the first '1' to the left of or at `j`.
            // If no '1' exists, then all characters up to `j` are '0's.
            // f(0...0) = 0. Length is j-i+1.
            // j-i+1 = 0 implies j+1=i, which is impossible for a non-empty substring.
            // So, substrings of all '0's are never good.
            // Thus, we only care about substrings that contain at least one '1'.
            // The first '1' must be at some index `k <= j`.

            // Iterate `k` from `j` downwards, representing the start of the non-zero part.
            // `k` is the index of the first '1' in `s[i...j]`.
            long long current_val = 0;
            for (int k = j; k >= 0; --k) {
                if (s[k] == '1') {
                    // Calculate f(s[k...j])
                    // This is equivalent to iterating from k to j and building the value.
                    // We can do this efficiently by reusing current_val from previous iteration (k+1).
                    // current_val = f(s[k...j])
                    // The loop for `k` goes downwards.
                    // `current_val` here represents `f(s[k...j])`.
                    // When `k` decreases, `s[k]` is prepended.
                    // So `f(s[k...j]) = s[k] * 2^(j-k) + f(s[k+1...j])`.
                    // This is not efficient. Let's re-evaluate.

                    // For a fixed `j`, iterate `k` from `j` down to `0`.
                    // `k` is the index of the first '1' in `s[i...j]`.
                    // So `s[k]` must be '1'.
                    // `s[k+1...j]` forms the suffix of the binary number.
                    // `s[k...j]` is the binary number.
                    // `current_val` will be `f(s[k...j])`.
                    // We need to calculate `f(s[k...j])` for each `k`.
                    // This is the same as the first loop, but `i` is now `k`.
                    // So `current_val` is `f(s[k...j])`.
                    // The length of `s[k...j]` is `j - k + 1`.
                    // The actual length of the good substring is `j - i + 1`.
                    // We need `j - i + 1 = f(s[k...j])`.
                    // This means `i = j + 1 - f(s[k...j])`.
                    // We need to find how many `i` satisfy this.
                    // `i` must be less than `k` and `s[i...k-1]` must be all '0's.
                    // This means `i` must be in the range `[max(0, k - MAX_GOOD_LEN), k-1]`.
                    // The number of leading zeros before `s[k]` is `k - i`.
                    // So `k - i = f(s[k...j]) - (j - k + 1)`.
                    // `i = k - (f(s[k...j]) - (j - k + 1))`.
                    // Let `val_k_j = f(s[k...j])`.
                    // Let `len_k_j = j - k + 1`.
                    // We need `i = k - (val_k_j - len_k_j)`.
                    // This `i` must be a valid starting index for a substring ending at `j`.
                    // Specifically, `i` must be non-negative.
                    // And `s[i...k-1]` must be all zeros.
                    // The number of leading zeros required is `k - i = val_k_j - len_k_j`.
                    // Let `num_leading_zeros = val_k_j - len_k_j`.
                    // If `num_leading_zeros < 0`, then `val_k_j < len_k_j`, so no `i` can satisfy this.
                    // If `num_leading_zeros >= 0`, we need to check if there are enough leading zeros before `k`.
                    // The starting index `i` would be `k - num_leading_zeros`.
                    // We need `i >= 0`.
                    // We also need `s[i...k-1]` to be all '0's.
                    // This means `s[i-1]` (if `i > 0`) must be '0' or `i=0`.
                    // More precisely, the first '1' before `k` must be at an index `prev_one_idx < i`.
                    // Or, if no '1' before `k`, then `i` can be `0`.

                    // Find the index of the '1' just before `k`.
                    auto it = std::lower_bound(ones_pos.begin(), ones_pos.end(), k);
                    int prev_one_idx = -1;
                    if (it != ones_pos.begin()) {
                        --it;
                        prev_one_idx = *it;
                    }

                    // Calculate f(s[k...j])
                    current_val = 0;
                    for (int p = k; p <= j; ++p) {
                        current_val = (current_val << 1) | (s[p] - '0');
                        if (current_val > n + MAX_GOOD_LEN) break; // Optimization
                    }
                    if (current_val == 0) continue; // f(0...0) is 0, but we already handled this.
                                                    // This case means s[k...j] is all zeros, which is not possible if s[k]=='1'.

                    int len_k_j = j - k + 1;
                    long long num_leading_zeros = current_val - len_k_j;

                    if (num_leading_zeros >= 0) {
                        int target_i = k - num_leading_zeros;
                        if (target_i >= 0 && target_i <= prev_one_idx + 1) {
                            // This means s[target_i ... k-1] are all zeros.
                            // The number of valid `i` values is `(prev_one_idx + 1) - target_i + 1` if `target_i` is the start.
                            // No, it's simpler: `i` must be `target_i`.
                            // We need `target_i` to be a valid start.
                            // `target_i` must be `0` or `s[target_i-1]` must be `0`.
                            // This is equivalent to `target_i` being greater than the index of the previous '1'.
                            // `target_i > prev_one_idx`.
                            count++;
                        }
                    }
                }
            }
        }
    }

    // The above logic for Case 2 is flawed. Let's rethink.
    // The problem is that `f(s_l \dots s_r)` is the value of the binary string `s_l \dots s_r`.
    // If `s_l` is '0', it's a leading zero.
    // Example: s = 0001000, n = 8
    // Substring s[4...4] = '1'. f('1') = 1. len = 1. Good.
    // Substring s[3...4] = '01'. f('01') = 1. len = 2. Not good.
    // Substring s[2...4] = '001'. f('001') = 1. len = 3. Not good.
    // Substring s[1...4] = '0001'. f('0001') = 1. len = 4. Not good.
    // Substring s[0...4] = '00001'. f('00001') = 1. len = 5. Not good.
    // Substring s[4...5] = '10'. f('10') = 2. len = 2. Not good.
    // Substring s[4...6] = '100'. f('100') = 4. len = 3. Not good.
    // Substring s[4...7] = '1000'. f('1000') = 8. len = 4. Not good.

    // The example output for 0001000 is 3.
    // Let's find them:
    // s[4...4] = '1'. f('1') = 1. len = 1. Good.
    // s[3...5] = '010'. f('010') = 2. len = 3. Not good.
    // s[2...5] = '0010'. f('0010') = 2. len = 4. Not good.
    // s[1...5] = '00010'. f('00010') = 2. len = 5. Not good.
    // s[0...5] = '000010'. f('000010') = 2. len = 6. Not good.

    // s[3...6] = '0100'. f('0100') = 4. len = 4. Good.
    // s[2...6] = '00100'. f('00100') = 4. len = 5. Not good.
    // s[1...6] = '000100'. f('000100') = 4. len = 6. Good.
    // s[0...6] = '0000100'. f('0000100') = 4. len = 7. Not good.

    // s[2...7] = '001000'. f('001000') = 8. len = 6. Not good.
    // s[1...7] = '0001000'. f('0001000') = 8. len = 7. Not good.
    // s[0...7] = '00001000'. f('00001000') = 8. len = 8. Good.

    // The good substrings are:
    // s[4...4] = '1', f=1, len=1.
    // s[3...6] = '0100', f=4, len=4.
    // s[1...6] = '000100', f=4, len=6.
    // s[0...7] = '00001000', f=8, len=8.
    // Total 4 for 0001000. Example output is 3. Why?
    // Ah, the example output for 0001000 is 3.
    // The example output for 00001000 is 4.
    // My string was 0001000.
    // For 0001000:
    // s[3...3] = '1', f=1, len=1. Good.
    // s[2...5] = '0100', f=4, len=4. Good.
    // s[0...5] = '000100', f=4, len=6. Good.
    // Total 3. My manual check matches example.

    // The first loop (starting with '1') is correct.
    // The second loop (starting with '0') needs to be implemented carefully.
    // For each `j` (right endpoint), iterate `k` from `j` down to `0`.
    // `k` is the index of the first '1' in `s[i...j]`.
    // If `s[k]` is '0', skip.
    // If `s[k]` is '1':
    //   Calculate `val = f(s[k...j])`.
    //   `len_val_part = j - k + 1`.
    //   We are looking for `i` such that `s[i...j]` is good.
    //   `s[i...k-1]` must be all '0's.
    //   `len_total = j - i + 1`.
    //   We need `len_total = val`.
    //   So `j - i + 1 = val`.
    //   `i = j + 1 - val`.
    //   We need to check if this `i` is valid.
    //   1. `i >= 0`.
    //   2. `i < k`. (Because `s[k]` is the first '1').
    //   3. `s[i...k-1]` must be all '0's. This means `i` must be greater than the index of the previous '1'.
    //      Let `prev_one_idx` be the index of the '1' immediately before `k`. If no such '1', `prev_one_idx = -1`.
    //      Then we need `i > prev_one_idx`.

    // Let's re-implement the second part.
    // The first loop already covers all substrings starting with '1'.
    // So we only need to consider substrings starting with '0'.
    // A substring `s[i...j]` starts with '0' if `s[i] == '0'`.
    // Let `k` be the index of the first '1' in `s[i...j]`. So `i <= k <= j` and `s[k] == '1'`.
    // `s[i...k-1]` must be all '0's.
    // The value `f(s[i...j])` is `f(s[k...j])`.
    // Let `val = f(s[k...j])`.
    // We need `j - i + 1 = val`.
    // This implies `i = j + 1 - val`.
    // For a fixed `j` and `k` (where `s[k] == '1'` and `k <= j`):
    //   Calculate `val = f(s[k...j])`.
    //   Calculate `target_i = j + 1 - val`.
    //   If `target_i < 0` or `target_i >= k`, this `i` is not valid.
