// Function to calculate the parity of a string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int parity_a = calculate_parity(a);
    int parity_b = calculate_parity(b);

    // The minimum number of '1's in string 'a' that can be achieved
    // by appending parity bits is parity_a.
    // If parity_a is 0, it means 'a' has an even number of '1's.
    // We can append '0's indefinitely, keeping the '1's count even.
    // If parity_a is 1, it means 'a' has an odd number of '1's.
    // We can append '1', making the '1's count even.
    // So, the minimum number of '1's we can achieve is parity_a.
    // If parity_a is 0, min_ones_a_reachable = 0.
    // If parity_a is 1, min_ones_a_reachable = 1.
    // This is equivalent to parity_a itself.

    // The maximum number of '1's in string 'a' that can be achieved
    // by appending parity bits is the current count of '1's plus 1 (if parity_a is 1).
    // If parity_a is 0, we can only append '0', so '1's count doesn't change.
    // If parity_a is 1, we can append '1', so '1's count increases by 1.
    // So, the maximum number of '1's we can achieve is (count of '1's in original 'a') + parity_a.

    // Let's count ones in original 'a'
    int ones_in_a_orig = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a_orig++;
        }
    }

    // The maximum number of '1's we can ever have in a string derived from 'a'
    // by appending parity bits is ones_in_a_orig + parity_a.
    // This is because if parity_a is 0, we append '0', ones count doesn't change.
    // If parity_a is 1, we append '1', ones count increases by 1, and the new parity becomes 0.
    // After that, we can only append '0's, so the ones count never increases further.
    int max_ones_a_reachable = ones_in_a_orig + parity_a;

    // Count ones in 'b'
    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Condition 1: The number of '1's in 'b' must be less than or equal to the maximum '1's reachable from 'a'.
    if (ones_in_b > max_ones_a_reachable) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // after 'a' has been potentially extended to match the '1's count of 'b'.
    // If ones_in_b is less than ones_in_a_orig, we must have removed characters from 'a'.
    // If ones_in_b is greater than ones_in_a_orig, we must have appended '1' (if parity_a was 1)
    // and then removed characters.
    // If ones_in_b == ones_in_a_orig and parity_a == 1, we must have appended '1' and then removed it.
    // This is equivalent to saying that the length of 'b' must be at most
    // the length of 'a' plus the number of '1's we needed to add to 'a' to reach ones_in_b.
    // The number of '1's we needed to add is (ones_in_b - ones_in_a_orig).
    // This is only possible if parity_a was 1 and ones_in_b == ones_in_a_orig + 1.
    // Otherwise, if ones_in_b <= ones_in_a_orig, we don't need to add '1's.
    // The effective length of 'a' that we can work with is its current length plus
    // any '1's we might have appended.
    // If parity_a is 1, we can append a '1', increasing length by 1.
    // So, the effective maximum length of 'a' we can achieve before removing characters
    // is |a| + parity_a.
    if (b.length() > a.length() + parity_a) {
        std::cout << "NO\n";
        return 0;
    }

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effects from previous children crying in the hall
            if (total_d_effect > 0) {
                children[j].p -= total_d_effect;
            }

            // Apply effect from current child in dentist's office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

