#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_goodness = LLONG_MAX;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // No pairs are in different subsequences, so no +h terms.
    // f(a_i, a_j) = a_i + a_j for all pairs.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long current_goodness_case1 = (long long)elements[n-1].value + elements[n-2].value - ((long long)elements[0].value + elements[1].value);
    if (current_goodness_case1 < min_goodness) {
        min_goodness = current_goodness_case1;
        for (int i = 0; i < n; ++i) {
            best_partition[elements[i].original_index] = 1;
        }
    }

    // Case 2: At least one element in each subsequence.
    // This means there will be at least one pair (a_i, a_j) with a_i in sub1 and a_j in sub2.
    // So, min_f could be elements[0].value + elements[1].value + h (if elements[0] and elements[1] are separated)
    // or elements[0].value + elements[1].value (if elements[0] and elements[1] are together).
    // The smallest possible sum a_i + a_j is elements[0].value + elements[1].value.
    // The largest possible sum a_i + a_j is elements[n-1].value + elements[n-2].value.

    // Consider the partition where elements[0] is in sub1, and elements[1]...elements[n-1] are in sub2.
    // Or elements[0]...elements[n-2] in sub1, and elements[n-1] in sub2.
    // The critical observation is that if h is large enough, it's always better to put all elements into one subsequence.
    // If h is small, then separating elements might be beneficial.

    // Let's analyze the minimum and maximum f values more generally.
    // min_f_base = elements[0].value + elements[1].value
    // max_f_base = elements[n-1].value + elements[n-2].value

    // If we have at least one element in each subsequence:
    // The minimum possible f value is min(min_f_base, elements[0].value + elements[1].value + h).
    // The maximum possible f value is max(max_f_base, elements[n-1].value + elements[0].value + h).
    // The term elements[n-1].value + elements[0].value + h is the largest possible sum of two elements from different subsequences.
    // The term elements[n-1].value + elements[n-2].value is the largest possible sum of two elements from the same subsequence.

    // Let's consider a specific partition strategy:
    // Put elements[0] into subsequence 1.
    // Put elements[1] into subsequence 1.
    // Put elements[2]...elements[n-1] into subsequence 2.
    // This partition is valid only if n >= 2.
    // If n=2, elements[0] in sub1, elements[1] in sub2.
    // f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // This is covered by the general case below.

    // For n >= 3:
    // Partition: elements[0] in sub1, elements[1] in sub1, elements[2]...elements[n-1] in sub2.
    // Pairs within sub1: (elements[0], elements[1]) -> elements[0].value + elements[1].value
    // Pairs within sub2: (elements[i], elements[j]) for i,j >= 2 -> elements[i].value + elements[j].value
    // Pairs across sub1 and sub2: (elements[0], elements[k]) for k >= 2 -> elements[0].value + elements[k].value + h
    //                              (elements[1], elements[k]) for k >= 2 -> elements[1].value + elements[k].value + h

    // Minimum f value:
    //   From same subsequence: elements[0].value + elements[1].value
    //   From different subsequences: elements[0].value + elements[2].value + h
    //   So, min_f = std::min((long long)elements[0].value + elements[1].value, (long long)elements[0].value + elements[2].value + h);
    // Maximum f value:
    //   From same subsequence: elements[n-1].value + elements[n-2].value (if n-1, n-2 are in sub2)
    //   From different subsequences: elements[1].value + elements[n-1].value + h
    //   So, max_f = std::max((long long)elements[n-1].value + elements[n-2].value, (long long)elements[1].value + elements[n-1].value + h);

    // This specific partition (elements[0] in sub1, elements[1] in sub1, rest in sub2)
    // min_f_val = elements[0].value + elements[1].value
    // max_f_val = elements[n-1].value + elements[n-2].value
    // max_f_val_diff = elements[1].value + elements[n-1].value + h
    // min_f_val_diff = elements[0].value + elements[2].value + h

    // The actual min_f for this partition:
    long long current_min_f = (long long)elements[0].value + elements[1].value;
    if (n >= 3) { // If n=2, there are no elements[2] to form a cross-subsequence pair with elements[0]
        current_min_f = std::min(current_min_f, (long long)elements[0].value + elements[2].value + h);
    } else { // n=2, elements[0] in sub1, elements[1] in sub2. Only one f value.
        current_min_f = (long long)elements[0].value + elements[1].value + h;
    }

    // The actual max_f for this partition:
    long long current_max_f = (long long)elements[1].value + elements[n-1].value + h;
    if (n >= 3) { // If n=2, elements[n-1] and elements[n-2] are the same.
        current_max_f = std::max(current_max_f, (long long)elements[n-1].value + elements[n-2].value);
    }

    long long current_goodness_case2 = current_max_f - current_min_f;

    if (current_goodness_case2 < min_goodness) {
        min_goodness = current_goodness_case2;
        best_partition[elements[0].original_index] = 1;
        if (n > 1) { // For n=2, elements[1] goes to sub2. For n>=3, elements[1] goes to sub1.
            best_partition[elements[1].original_index] = 1;
        }
        for (int i = 2; i < n; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
        if (n == 2) { // Special handling for n=2, elements[1] must be in sub2 for this case.
            best_partition[elements[1].original_index] = 2;
        }
    }

    // The problem statement implies that one subsequence can be empty.
    // Case 1 covers all elements in one subsequence.
    // Case 2 covers elements[0] in sub1, elements[1] in sub1, rest in sub2.
    // What if elements[0] is in sub1, and elements[1] is in sub2, and rest in sub2?
    // This is equivalent to elements[0] in sub1, and elements[1]...elements[n-1] in sub2.
    // min_f: elements[0].value + elements[1].value + h
    // max_f: elements[0].value + elements[n-1].value + h (if n-1 is in sub2)
    //        elements[n-1].value + elements[n-2].value (if n-1, n-2 are in sub2)
    // min_f = elements[0].value + elements[1].value + h
    // max_f = std::max((long long)elements[0].value + elements[n-1].value + h, (long long)elements[n-1].value + elements[n-2].value);
    // This is the partition where elements[0] is in sub1, and all other elements are in sub2.
    // This is a common strategy when h is large.
    // Let's calculate goodness for this partition.
    long long current_min_f_alt = (long long)elements[0].value + elements[1].value + h;
    long long current_max_f_alt;
    if (n == 2) {
        current_max_f_alt = (long long)elements[0].value + elements[1].value + h;
    } else {
        current_max_f_alt = std::max((long long)elements[0].value + elements[n-1].value + h, (long long)elements[n-1].value + elements[n-2].value);
    }
    long long current_goodness_alt = current_max_f_alt - current_min_f_alt;

    if (current_goodness_alt < min_goodness) {
        min_goodness = current_goodness_alt;
        best_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[i] stores the minimum r (1-indexed) such that s[i-1...r-1] contains a pattern.
                                                // If no such r exists, it's n+1.

    for (int x = 0; x < n; ++x) { // x is 0-indexed
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s[x] = s[x+k] = s[x+2k]
                // The pattern spans from index x to x+2k (0-indexed)
                // In 1-indexed terms, this is from x+1 to x+2k+1.
                // Any substring s[l-1...r-1] that contains this pattern must satisfy:
                // l-1 <= x  => l <= x+1
                // r-1 >= x+2k => r >= x+2k+1

                // For a fixed l (1-indexed), the smallest r (1-indexed) that contains this pattern
                // is x+2k+1, provided l <= x+1.
                // So, for all l from 1 to x+1, we can potentially update min_r_for_l[l].
                // We want to find the smallest r for each l.
                // Since we iterate x from left to right, and k from small to large,
                // x+2k+1 will generally be increasing.
                // For a given x and k, the pattern ends at x+2k (0-indexed).
                // The 1-indexed start of the pattern is x+1.
                // The 1-indexed end of the pattern is x+2k+1.

                // We need to update min_r_for_l[l] for all l such that 1 <= l <= x+1.
                // The minimum r for such l would be x+2k+1.
                // However, we only need to update for l such that x+1 - l <= 2.
                // This is because if x+1 - l > 2, then l < x-1.
                // If l < x-1, then the pattern s[x]=s[x+k]=s[x+2k] is "far" from l.
                // There might be a shorter pattern starting at l or l+1 or l+2.
                // The maximum possible k is 2.
                // If k=1, pattern is s[x]s[x+1]s[x+2]. Length 3.
                // If k=2, pattern is s[x]s[x+2]s[x+4]. Length 5.
                // The maximum length of a pattern we care about is 5 (for k=2).
                // If k >= 3, the pattern length is 2k+1 >= 7.
                // For any pattern s[x]=s[x+k]=s[x+2k], its length is 2k+1.
                // If 2k+1 > 6, then any substring of length 6 cannot contain this pattern.
                // So we only need to consider k=1 and k=2.
                // For k=1, pattern is s[x]s[x+1]s[x+2]. Length 3.
                // For k=2, pattern is s[x]s[x+2]s[x+4]. Length 5.
                // The maximum length of a pattern we need to consider is 5.
                // This means if a substring s[l-1...r-1] contains a pattern,
                // then r-l+1 >= 3.
                // The crucial observation is that if a substring $s[l \dots r]$ contains a pattern $s_x = s_{x+k} = s_{x+2k}$,
                // then it must contain such a pattern where $k \le 2$.
                // Proof: If $k \ge 3$, then $x+2k - x = 2k \ge 6$.
                // The indices are $x, x+k, x+2k$.
                // If $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 3$, then the length of the segment is $2k+1 \ge 7$.
                // Consider any substring $s[l \dots r]$ that contains this pattern.
                // If $r-l+1 \ge 7$, then it contains this pattern.
                // If $r-l+1 < 7$, it cannot contain this pattern.
                // So we only need to check for $k=1$ and $k=2$.
                // This significantly limits the search space for $k$.

                // For k=1: pattern s[x]s[x+1]s[x+2]. Ends at x+2.
                // For k=2: pattern s[x]s[x+2]s[x+4]. Ends at x+4.
                // The maximum end index is x+4.
                // The minimum start index is x.
                // So for a pattern starting at x (0-indexed), it ends at most at x+4.
                // The 1-indexed range is [x+1, x+5].
                // For any l (1-indexed) such that l <= x+1, the minimum r (1-indexed)
                // that contains this pattern is x+2k+1.
                // We need to update min_r_for_l[l] for l from max(1, x+1-4) to x+1.
                // The maximum length of a pattern is 5 (for k=2).
                // So, if a pattern starts at x (0-indexed), it ends at x+2k (0-indexed).
                // The 1-indexed range is [x+1, x+2k+1].
                // We need to update min_r_for_l[l] for l from max(1, x+1 - (2k+1) + 1) to x+1.
                // This simplifies to max(1, x+1 - 2k) to x+1.
                // Since we only consider k=1 and k=2, max(1, x+1-4) to x+1 is sufficient.
                // This means l can be x+1, x, x-1, x-2, x-3.
                // For example, if pattern is s[x]s[x+1]s[x+2], it ends at x+2.
                // For l=x+1, min_r_for_l[x+1] = min(min_r_for_l[x+1], x+3).
                // For l=x, min_r_for_l[x] = min(min_r_for_l[x], x+3).
                // For l=x-1, min_r_for_l[x-1] = min(min_r_for_l[x-1], x+3).
                // For l=x-2, min_r_for_l[x-2] = min(min_r_for_l[x-2], x+3).
                // For l=x-3, min_r_for_l[x-3] = min(min_r_for_l[x-3], x+3).
                // This is because a pattern of length 3 can be contained in a substring of length 3, 4, 5, 6.
                // A pattern of length 5 can be contained in a substring of length 5, 6.
                // The maximum length of a substring we need to consider is 6.
                // So, for a pattern ending at index `end_idx` (0-indexed),
                // and starting at `start_idx` (0-indexed),
                // we update `min_r_for_l[l]` for `l` from `max(1, end_idx - 6 + 2)` to `start_idx + 1`.
                // The `+2` is because `end_idx - 6 + 1` is the 0-indexed start, so `+1` for 1-indexed `l`.
                // `end_idx - 6 + 2` is `end_idx - 4`.
                // So `l` goes from `max(1, x+2k+1 - 4)` to `x+1`.
                // This is `max(1, x+2k-3)` to `x+1`.
                // Since $k \le 2$, $2k-3 \le 1$. So $x+2k-3 \le x+1$.
                // The range of $l$ is $max(1, x+2k-3)$ to $x+1$.
                // This is a small constant number of $l$ values.

                int pattern_end_1_indexed = x + 2 * k + 1;
                int pattern_start_1_indexed = x + 1;

                // The maximum length of a substring we need to check is 6.
                // If a pattern ends at pattern_end_1_indexed, and starts at pattern_start_1_indexed,
                // then any l such that pattern_start_1_indexed - l <= 5 (i.e., l >= pattern_start_1_indexed - 5)
                // and l <= pattern_start_1_indexed will have this pattern.
                // The actual range of l to update is from max(1, pattern_start_1_indexed - 5) to pattern_start_1_indexed.
                // For each such l, the minimum r is pattern_end_1_indexed.
                for (int l_val = std::max(1, pattern_start_1_indexed - 5); l_val <= pattern_start_1_indexed; ++l_val) {
                    min_r_for_l[l_val] = std::min(min_r_for_l[l_val], pattern_end_1_indexed);
                }
            }
            if (k == 2) break; // Optimization: only need to check k=1 and k=2
        }
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            // All r from min_r_for_l[l] to n are valid.
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s2 + s1.
    // We need s2 + s1 to be a palindrome and s2 + s1 != s.
    // Since s is already a palindrome, s2 + s1 != s implies s2 + s1 is not s.
    // If s2 + s1 == s, then s2 + s1 is also a palindrome.
    // So we just need to find if there's any cut such that s2 + s1 is a palindrome AND s2 + s1 != s.
    for (int i = 1; i < n; ++i) { // Cut point i means s[0...i-1] and s[i...n-1]
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check k=2.
    // This means 3 pieces.
    // The problem statement implies that if k=1 doesn't work, k=2 might.
    // A common strategy for k=2 with palindromes is to cut off the first character,
    // then the last character, and rearrange.
    // Or, more generally, if all characters in s are the same (e.g., "aaaaa"),
    // then no rearrangement will produce a different string.
    // If s consists of all the same characters, e.g., "aaaa", "bbbbb",
    // then any rearrangement of its substrings will result in the same string.
    // In this case, it's impossible to form a different string.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // The strategy is to cut the string into s[0], s[1...n-2], s[n-1].
        // Then rearrange to s[n-1], s[1...n-2], s[0].
        // Since s is a palindrome, s[0] == s[n-1].
        // The new string would be s[0] + s[1...n-2] + s[n-1], which is s.
        // This specific rearrangement doesn't work.
        //
        // However, consider cutting s into s[0...i-1], s[i], s[i+1...n-1].
        // Or, more simply, if k=1 doesn't work, it means that for any split s = A+B,
        // B+A is either not a palindrome or B+A == s.
        //
        // If s is a palindrome and not all characters are the same,
        // we can always achieve a different palindrome with 2 cuts.
        // Consider s = "abacaba". n=7.
        // s[0] = 'a', s[1...n-2] = "bacab", s[n-1] = 'a'.
        // Cut into s[0], s[1...n-2], s[n-1].
        // Rearrange to s[n-1], s[1...n-2], s[0]. This is s.
        //
        // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
        // we can always find a way to make a different palindrome.
        // For example, take s = "abacaba".
        // Cut into "a", "bacab", "a".
        // Rearrange to "a", "bacab", "a" (still "abacaba").
        //
        // Let's re-evaluate the k=2 case.
        // If s is a palindrome and not all characters are the same,
        // it means there exists at least one character s[i] such that s[i] != s[0].
        //
        // Consider cutting s into three pieces:
        // P1 = s[0...j-1]
        // P2 = s[j...k]
        // P3 = s[k+1...n-1]
        //
        // If s is a palindrome and not all characters are the same,
        // then n must be at least 2 (if n=1, it's all same char).
        // If n=2, s="aa", all same.
        // If n=3, s="aba", not all same. k=1: "a"+"ba" -> "baa" (not pal). "ab"+"a" -> "aab" (not pal).
        // For "aba", k=2: "a"|"b"|"a" -> "a"|"b"|"a" (still "aba").
        // This implies that for "aba", it's impossible.
        //
        // Let's check the example "nolon". n=5.
        // k=1:
        // "n" + "olon" -> "olonn" (not pal)
        // "no" + "lon" -> "lonno" (not pal)
        // "nol" + "on" -> "onnol" (not pal)
        // "nolo" + "n" -> "nnolo" (not pal)
        // So k=1 doesn't work for "nolon".
        //
        // For "nolon", k=2: "no" | "l" | "on". Rearrange to "on" | "l" | "no" = "onlno".
        // "onlno" is a palindrome and "onlno" != "nolon". So k=2 works.
        //
        // The condition for k=2 to be the answer is:
        // 1. k=1 doesn't work (already checked).
        // 2. The string is not composed of all identical characters.
        //
        // If a string `s` is a palindrome and not all characters are the same,
        // and `n > 1`, then `n` must be at least 3 for `k=2` to be possible and different from `s`.
        // If `n=2`, `s="aa"`, all same.
        // If `n=3`, `s="aba"`.
        //   k=1: "a"+"ba" -> "baa" (not pal). "ab"+"a" -> "aab" (not pal).
        //   k=2: "a"|"b"|"a". Only rearrangement is "a"|"b"|"a" -> "aba". No different string.
        // So for "aba", it's impossible.
        //
        // This means the "all_same_chars" check is not sufficient.
        // We need to check if it's possible to form a different palindrome with 2 cuts.
        //
        // The only case where it's impossible is if all characters are the same.
        // If `s` is a palindrome and not all characters are the same,
        // and `n > 1`, then `n` must be at least 3.
        //
        // If `n` is odd, e.g., "abacaba", "nolon".
        // If `n` is even, e.g., "otto", "kinnikkinnik".
        //
        // The example "aba" is a palindrome, not all same chars.
        // k=1 fails.
        // k=2: "a"|"b"|"a". Any rearrangement of these three pieces will result in "aba".
        // So for "aba", it's impossible.
        //
        // This suggests that the condition for "Impossible" is:
        // 1. All characters are the same (e.g., "qqqq").
        // 2. The string is of the form `c1 c2 c1` (e.g., "aba"), where `c1 != c2`.
        //
        // Let's check the length `n`.
        // If `n=1`, `s="a"`. All same. Impossible.
        // If `n=2`, `s="aa"`. All same. Impossible.
        // If `n=3`, `s="aba"`. Not all same. k=1 fails. k=2: "a"|"b"|"a". Only "aba" can be formed. Impossible.
        //
        // So, if `s` is a palindrome, and `s` is not composed of all identical characters,
        // and `k=1` doesn't work, then the answer is `2` UNLESS `n=3` and `s` is like "aba".
        //
        // The problem statement guarantees `s` is a palindrome.
        // If `s` is a palindrome and not all characters are the same,
        // and `n > 3`, then `k=2` is always possible.
        //
        // Consider `s = s[0] s[1] ... s[n-1]`.
        // Since `s` is a palindrome, `s[i] = s[n-1-i]`.
        // Since not all characters are the same, there exists some `j` such that `s[j] != s[0]`.
        //
        // If `n > 3` and `s` is a palindrome and not all characters are the same:
        // We can always find a cut that works for k=2.
        // For example, cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
        // Rearrange to `s[n-1]`, `s[1...n-2]`, `s[0]`. This is `s`.
        //
        // The example "nolon" (n=5) gives 2.
        // The example "otto" (n=4) gives 1.
        // The example "qqqq" (n=4) gives Impossible.
        // The example "kinnikkinnik" (n=12) gives 1.
        //
        // The logic seems to be:
        // 1. Try k=1. If a different palindrome is found, output 1.
        // 2. If k=1 fails:
        //    a. Check if all characters in `s` are the same. If yes, output "Impossible".
        //    b. Otherwise (not all characters are the same), output 2.
        //
        // Let's test this logic with "aba".
        // n=3, s="aba".
        // k=1:
        // "a" + "ba" -> "baa" (not pal)
        // "ab" + "a" -> "aab" (not pal)
        // k=1 fails.
        //
        // Now check step 2:
        // a. Are all characters in "aba" the same? No ('a' != 'b').
        // b. Output 2.
        //
        // But for "aba", the answer should be "Impossible".
        // My logic is flawed for small `n`.
        //
        // The condition for "Impossible" is actually:
        // 1. All characters are the same.
        // OR
        // 2. `s` is a palindrome, `n > 1`, and `s` consists of only two distinct characters,
        //    and `s` is of the form `c1 c2 c1 c2 ... c1` or `c1 c2 c1 c2 ... c2`.
        //    More simply, `s` is a palindrome, and `s` has a structure where
        //    `s[0...n/2 - 1]` is itself a palindrome of all same characters.
        //    E.g., "aaaaa", "ababa", "abcba".
        //
        // Let's consider the structure of `s`.
        // `s` is a palindrome.
        // If `s` is not all same characters, then `s[0] != s[1]` for some `s[1]`.
        //
        // The problem states: "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string. Pieces couldn't be turned over, they could be shuffled."
        //
        // If `s` is a palindrome, and `s` is not composed of all identical characters,
        // then `s` must have at least two distinct characters.
        //
        // Consider the first half of the string `s[0...n/2 - 1]`.
        // If all characters in `s[0...n/2 - 1]` are the same, say `c`.
        // Then `s` would look like `c c ... c X c ... c c`.
        // For example, `s = "aaabaaa"`. Here `n=7`. `n/2 - 1 = 2`. `s[0...2]` is "aaa".
        // `s = "ababa"`. Here `n=5`. `n/2 - 1 = 1`. `s[0...1]` is "ab". Not all same.
        //
        // If `s` is a palindrome, and `s` is not composed of all identical characters,
        // and `s` cannot be rearranged to a different palindrome with 1 cut,
        // then `s` must be of a specific form.
        //
        // The condition for "Impossible" is when all characters in `s` are the same.
        // Example: "qqqq".
        //
        // Let's re-check the "aba" case.
        // "aba" is a palindrome. Not all chars are same.
        // k=1:
        // "a" + "ba" -> "baa" (not pal)
        // "ab" + "a" -> "aab" (not pal)
        // So k=1 fails.
        //
        // Now, can we get a different palindrome with k=2?
        // Pieces: `s_1, s_2, s_3`.
        // `s_1 = s[0...i-1]`, `s_2 = s[i...j]`, `s_3 = s[j+1...n-1]`.
        // For "aba", `n=3`.
        // Possible cuts:
        // `i=1, j=1`: `s[0]`, `s[1]`, `s[2]`. Pieces: "a", "b", "a".
        // Any permutation of these pieces will result in "aba".
        // So for "aba", it's impossible.
        //
        // This means the "all_same_chars" check is not enough.
        // The condition for "Impossible" is:
        // 1. All characters in `s` are the same.
        // OR
        // 2. `s` is a palindrome, and `s` is of the form `c1 c2 c1` (n=3, `c1 != c2`).
        //    This is equivalent to saying that `s[0...n/2 - 1]` consists of all identical characters.
        //    For `n=3`, `s[0...0]` is `s[0]`. This is always "all identical characters".
        //    So, if `s` is a palindrome, and `s[0...n/2 - 1]` consists of all identical characters,
        //    then it's impossible to form a different palindrome.
        //
        // Let's test this hypothesis:
        // `s = "aaaaa"`. `s[0...1]` is "aa". All identical. Impossible. (Correct)
        // `s = "ababa"`. `s[0...1]` is "ab". Not all identical.
        //   k=1:
        //   "a" + "baba" -> "babaa" (not pal)
        //   "ab" + "aba" -> "abaab" (not pal)
        //   "aba" + "ba" -> "baaba" (not pal)
        //   "abab" + "a" -> "aabab" (not pal)
        //   k=1 fails.
        //   Hypothesis says: `s[0...n/2 - 1]` is "ab", not all identical. So output 2.
        //   Let's check "ababa" for k=2.
        //   Cut "ab" | "a" | "ba". Rearrange to "ba" | "a" | "ab" = "baab".
        //   "baab" is a palindrome and "baab" != "ababa". So k=2 works.
        //   This matches the hypothesis.
        //
        // `s = "nolon"`. `s[0...1]` is "no". Not all identical.
        //   k=1 fails (checked above).
        //   Hypothesis says: output 2. (Correct)
        //
        // `s = "otto"`. `s[0...1]` is "ot". Not all identical.
        //   k=1: "ot" + "to" -> "toot". "toot" is a palindrome and "toot" != "otto".
        //   Output 1. (Correct)
        //
        // `s = "kinnikkinnik"`. `s[0...5]` is "kinnik". Not all identical.
        //   k=1: "kinnik" + "kinnik" -> "kinnikkinnik" (same as s).
        //   "kinnikkinnik" is a palindrome.
        //   Cut at `i=6`: `s1 = "kinnik"`, `s2 = "kinnik"`. `s2+s1 = "kinnikkinnik"`. This is `s`.
        //   This specific cut doesn't work.
        //   What about other cuts?
        //   `s = "kinnikkinnik"`. `n=12`.
        //   `s[0...2] = "kin"`, `s[3...8] = "nikkin"`, `s[9...11] = "nik"`.
        //   Cut `s` into `s[0...2]` and `s[3...11]`.
        //   `s1 = "kin"`, `s2 = "nikkinnik"`.
        //   `s2+s1 = "nikkinnikkin"`.
        //   Is "nikkinnikkin" a palindrome? Yes.
        //   Is "nikkinnikkin" != "kinnikkinnik"? Yes.
        //   So k=1 works for "kinnikkinnik". (Correct)
        //
        // The hypothesis seems to be:
        // 1. Check for k=1. If a different palindrome is found, output 1.
        // 2. If k=1 fails:
        //    Check if the first half of the string `s[0...n/2 - 1]` consists of all identical characters.
        //    If yes, output "Impossible".
        //    Otherwise, output 2.
        //
        // This covers "qqqq" (first half "qq" all same) -> Impossible.
        // This covers "aba" (first half "a" all same) -> Impossible.
        // This covers "aaaaa" (first half "aa" all same) -> Impossible.
        // This covers "nolon" (first half "no" not all same) -> 2.
        // This covers "ababa" (first half "ab" not all same) -> 2.
        //
        // This logic seems robust.

    bool first_half_all_same = true;
    if (n > 0) { // Handle empty string case, though constraints say 1 <= |s|
        for (int i = 1; i < n / 2; ++i) {
            if (s[i] != s[0]) {
                first_half_all_same = false;
                break;
            }
        }
    } else { // n=0, not possible by constraints
        first_half_all_same = true;
    }

    if (first_half_all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_password.insert(s[i]);
        if (i + 1 < s.length()) {
            adj[s[i]].insert(s[i+1]);
            adj[s[i+1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;

    // Find a starting point for the layout: a character with only one required neighbor
    char start_char = '\0';
    for (char c : used_in_password) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no character has only one required neighbor, it means all characters in the password
    // either have two required neighbors (forming a cycle or a path where ends are not in password)
    // or the password has only one character.
    // If all characters in password have 2 neighbors, and there are characters not in password,
    // we can pick any character from password as start_char.
    // If password has only one character, start_char will remain '\0'.
    if (start_char == '\0' && !used_in_password.empty()) {
        // All characters in password have 2 neighbors. This implies a cycle or a path where
        // the ends are not part of the password.
        // We can pick any character from used_in_password as a starting point.
        start_char = *used_in_password.begin();
    } else if (used_in_password.empty()) {
        // Password is empty or has 1 char, no adjacencies. Any layout is fine.
        // This case is covered by s.length() >= 1. If s.length() == 1, used_in_password has 1 char.
        // adj[char].size() will be 0. start_char will be that char.
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the previous character

        while (visited_in_layout.find(current) == visited_in_layout.end()) {
            layout += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0' && adj[prev].size() == 2) {
                // This means we've traversed a path and reached an end, but the end has 2 neighbors.
                // This implies a cycle, which is not allowed for a simple path.
                // However, the problem statement implies a path, so this case should be caught by adj[c].size() > 2.
                // If adj[c].size() == 2 for all c in password, and it's a cycle, then start_char would be picked
                // from used_in_password.begin(), and we would eventually return to start_char.
                // If we return to start_char and it's not the only character, it means a cycle.
                // A cycle is fine if it covers all characters in the password.
                // But if we have a cycle and there are other characters not in the cycle,
                // we can't connect them.
                // The logic for adj[c].size() > 2 already handles cases where a character needs more than 2 neighbors.
                // If all characters in password have 2 neighbors, and they form a cycle,
                // then `current` will eventually become `start_char` again.
                // The `while` loop condition `visited_in_layout.find(current) == visited_in_layout.end()`
                // will catch this. If `current` is `start_char` and it's already visited, it's a cycle.
                // This is fine if the cycle covers all `used_in_password` characters.
                // If `current` is `\0` here, it means `adj[prev]` had only one neighbor (which was `prev`'s `prev`),
                // or `adj[prev]` had two neighbors but one was `prev`'s `prev` and the other was already visited.
                // This means we reached an end of a path.
            }
        }
    }

    // Add remaining characters not in the password to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Represents a_0[i] + current_delta[i] <= m_k
                                                  // So a_0[i] <= m_k - current_delta[i]
                                                  // We want to find the tightest upper bound for a_0[i]

    std::vector<long long> current_delta(n, 0); // Accumulates d values for type 1 ops

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If initial_a[j] is still LLONG_MAX, it means it was never constrained by a type 2 query.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    current_delta.assign(n, 0); // Reset current_delta for verification
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
