// Function to check if all tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks p
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        // If all target tracks are already covered, return true
        if (p_idx == m) {
            return true;
        }

        // Find the first target track p[p_idx] that can be reached by h[h_idx]
        // A track p_j can be reached by h_i if abs(h_i - p_j) <= T
        // This means p_j is in [h_i - T, h_i + T]
        // We are looking for the first p_j such that p_j >= h_i - T
        // And we want to cover as many tracks as possible to the right.

        // If p[p_idx] is too far to the left for h[h_idx] to reach,
        // i.e., p[p_idx] < h[h_idx] - T, then h[h_idx] cannot cover p[p_idx].
        // This implies that p[p_idx] must be covered by a previous head.
        // Since we iterate h_idx from left to right, and p_idx from left to right,
        // if p[p_idx] is not covered by h[h_idx], it means it wasn't covered by h[h_idx-1] either.
        // This logic is flawed. We need to find the first p_idx that *can* be covered by h[h_idx].

        // Let's rephrase: for each head h[h_idx], we want to cover a contiguous block of p tracks.
        // The head h[h_idx] can cover tracks in the range [h[h_idx] - T, h[h_idx] + T].
        // We need to find the first p[p_idx] that is within this range.
        // If p[p_idx] is already greater than h[h_idx] + T, then h[h_idx] cannot cover p[p_idx]
        // and any subsequent p tracks. This means p[p_idx] must be covered by a previous head.
        // This is also not quite right.

