int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = 10001; // k_max is 10^4, so 10001 is safe initial max
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile, add min_val as many times as possible
            // The current pile value is a[i]. We want a[i] + x * min_val <= k
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            if (min_val > 0) { // To prevent division by zero, though problem constraints say a_i >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach: use 5s, then 2s, then 1s
        // This works because 5 is not a multiple of 2, and 2 is not a multiple of 1.
        // Also, 5 is not a multiple of 1.
        // The optimal strategy for making change with denominations 1, 2, 5 is greedy.

        presses += diff / 5;
        diff %= 5;

        // Now diff can be 0, 1, 2, 3, 4
        // If diff is 0, we are done.
        // If diff is 1, we need 1 press (+1 or -1).
        // If diff is 2, we need 1 press (+2 or -2).
        // If diff is 3, we need 2 presses (+2, +1 or -2, -1).
        // If diff is 4, we need 2 presses (+2, +2 or -2, -2).

        if (diff == 1 || diff == 2) {
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            presses += 2;
        }
        // If diff is 0, presses remains unchanged.

        std::cout << presses << "\n";
    }
    return 0;
}

