    while (t--) {
        int n;
        std::cin >> n;
        if (n == 1) {
            std::cout << -1 << "\n";
        } else {
            // For n >= 2, we can construct a number that satisfies the conditions.
            // The number will start with '2' and end with '3', with '7's in between.
            // Example: n=2 -> 23
            //          n=3 -> 273
            //          n=4 -> 2773
            //
            // Let s be this number.
            // The digits are 2, 3, and 7.
            // We need to ensure s is not divisible by 2, 3, or 7.
            //
            // Divisibility by 2: s ends with 3, which is odd. So s is not divisible by 2.
            //
            // Divisibility by 3: The sum of digits is 2 + 3 + (n-2)*7.
            // Sum = 5 + 7n - 14 = 7n - 9.
            // For s to be divisible by 3, 7n - 9 must be divisible by 3.
            // 7n - 9 = (6n + n) - 9 = 3(2n - 3) + n.
            // So, 7n - 9 is divisible by 3 if and only if n is divisible by 3.
            // If n is divisible by 3, this construction fails for digit 3.
            //
            // To fix this, if n is divisible by 3, we can use '2' followed by (n-1) '3's.
            // Example: n=3 -> 233
            //          n=6 -> 233333
            //
            // Let's check this alternative construction: s = 2 followed by (n-1) 3s.
            // Digits are 2 and 3.
            // Divisibility by 2: s ends with 3, which is odd. Not divisible by 2.
            // Divisibility by 3: Sum of digits = 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
            // For s to be divisible by 3, 3n - 1 must be divisible by 3.
            // 3n - 1 is never divisible by 3 (it leaves a remainder of 2 when divided by 3).
            // So, this construction (2 followed by n-1 3s) is always valid for n >= 2.
            //
            // Let's verify the example for n=2: 23.
            // Not div by 2 (ends in 3). Not div by 3 (sum=5). Valid.
            //
            // Example for n=3: 233.
            // Not div by 2 (ends in 3). Not div by 3 (sum=8). Valid.
            //
            // Example for n=4: 2333.
            // Not div by 2 (ends in 3). Not div by 3 (sum=11). Valid.
            //
            // This construction seems robust for all n >= 2.

            std::cout << '2';
            for (int i = 0; i < n - 1; ++i) {
                std::cout << '3';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

