    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // We can add a ')' if we still need closing brackets
            // AND if the current balance allows it (balance > 0)
            // AND if adding it won't make us exceed k/2 closing brackets
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        // If we have already collected k characters, we can stop.
        // This is an optimization, as the problem guarantees a solution exists.
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the first peak from the right
    // This is the first index `i` from the right such that `a[i] > a[i+1]`
    // All elements from `a[i+1]` to `a[n-1]` are non-decreasing.
    int right_peak_idx = n - 1;
    while (right_peak_idx > 0 && a[right_peak_idx - 1] >= a[right_peak_idx]) {
        right_peak_idx--;
    }

    // If right_peak_idx is 0, it means the entire array is non-decreasing.
    // In this case, the array is good, and we need to erase 0 elements.
    if (right_peak_idx == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, `a[right_peak_idx ... n-1]` is a non-decreasing suffix.
    // We need to find the first valley from the right, starting from `right_peak_idx`.
    // This is the first index `i` from the right such that `a[i] < a[i+1]`
    // All elements from `a[i+1]` to `a[right_peak_idx-1]` are non-increasing.
    int right_valley_idx = right_peak_idx;
    while (right_valley_idx > 0 && a[right_valley_idx - 1] <= a[right_valley_idx]) {
        right_valley_idx--;
    }

    std::cout << right_valley_idx << std::endl;
}

