int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of multiples of m up to n

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of multiples of m repeat every 10 terms.
        // (k * m) % 10
        // ( (k+1) * m ) % 10
        // ...
        // ( (k+10) * m ) % 10
        // The last digit of ( (k+10) * m ) % 10 is the same as (k * m) % 10
        // because ( (k+10) * m ) % 10 = ( k*m + 10*m ) % 10 = ( k*m % 10 + 10*m % 10 ) % 10 = ( k*m % 10 + 0 ) % 10 = k*m % 10.

        std::vector<long long> cycle_last_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_last_digits[i - 1];
        }

        long long num_full_cycles = count / 10;
        long long remaining_terms = count % 10;

        long long total_sum = num_full_cycles * cycle_sum;

        for (int i = 0; i < remaining_terms; ++i) {
            total_sum += cycle_last_digits[i];
        }
        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we extend the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index of {1..m-1}
        // to the maximum index of {1..m-1}, and also include 'm'.
        // So, the new min_idx will be min(old_min_idx, pos[m])
        // and the new max_idx will be max(old_max_idx, pos[m]).

        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This implies two conditions:
        // 1. The length of this subsegment must be m.
        //    Length = current_max_idx - current_min_idx + 1.
        // 2. The minimum element in this subsegment must be 1. (Guaranteed by construction)
        // 3. The maximum element in this subsegment must be m. (Guaranteed by construction)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

