int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For real solutions, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this means d - 4 >= 0, so d >= 4.
            // If d = 0, d^2 - 4d = 0, which is handled above.
            // If d < 4 and d > 0, then d^2 - 4d < 0, no real solutions.

            double sqrt_discriminant = std::sqrt(d * d - 4 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Ensure a and b are non-negative.
            // Since d >= 4, d^2 >= 4d, so d^2 - 4d >= 0.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is clearly non-negative.
            // d - sqrt(d^2 - 4d):
            // We need to check if d >= sqrt(d^2 - 4d).
            // Squaring both sides (both are non-negative):
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, b will also be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

