    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // They must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // They must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check for the left increasing part
    // For a_1 < a_2 < ... < a_k, we need a_i >= i-1 for i=1..k
    // This means a_i must be at least its index (0-indexed)
    // If a[i] < i, then it's impossible to make a[i] >= i.
    // The first element a[0] must be >= 0.
    // The second element a[1] must be >= 1.
    // ...
    // The i-th element a[i-1] must be >= i-1.
    // So, a[i] must be >= i for 0-indexed array.

    // Find the maximum possible 'k' (0-indexed) for the left part
    // where a[i] >= i for all i <= k.
    int max_left_k_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        max_left_k_idx = i;
    }

    // If no such 'k' exists (e.g., a[0] < 0, which is impossible for non-negative a_i,
    // or n=0, which is not allowed by constraints), or if the array is empty.
    // max_left_k_idx will be -1 if a[0] < 0, but a[0] is always >= 0.
    // So max_left_k_idx will be at least 0 if n >= 1.

    // Check for the right decreasing part
    // For a_k > a_{k+1} > ... > a_n, we need a_i >= n-1-i for i=k..n-1
    // This means a[n-1] must be >= 0.
    // a[n-2] must be >= 1.
    // ...
    // a[i] must be >= n-1-i.

    // Find the minimum possible 'k' (0-indexed) for the right part
    // where a[i] >= n-1-i for all i >= k.
    int min_right_k_idx = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        min_right_k_idx = i;
    }

    // If there is any overlap between the possible peak indices, then it's possible.
    // The peak index 'k' (0-indexed) must satisfy:
    // 1. It can be the end of a valid left increasing sequence (i.e., k <= max_left_k_idx)
    // 2. It can be the start of a valid right decreasing sequence (i.e., k >= min_right_k_idx)
    // So, we need to find if there exists a k such that min_right_k_idx <= k <= max_left_k_idx.
    // This is true if min_right_k_idx <= max_left_k_idx.

    if (min_right_k_idx <= max_left_k_idx) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

