int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int b_ptr = 0; // Pointer for elements to be placed (from sorted 'a')
    int a_ptr = 0; // Pointer for original positions (from sorted 'a')

    while (b_ptr < n && a_ptr < n) {
        // We are trying to find an element a[b_ptr] to place at position a[a_ptr]
        // such that a[b_ptr] > a[a_ptr].
        // Since both arrays are sorted, we can use a two-pointer approach.
        // If a[b_ptr] is greater than a[a_ptr], we found a valid pair.
        // We increment both pointers and the count.
        if (a[b_ptr] > a[a_ptr]) {
            count++;
            b_ptr++;
            a_ptr++;
        } else {
            // If a[b_ptr] is not greater than a[a_ptr], it means a[b_ptr]
            // is either equal to or smaller than a[a_ptr].
            // In this case, a[b_ptr] cannot be placed at position a[a_ptr]
            // to satisfy the condition.
            // Since a[b_ptr] is the smallest available element from the 'b_elements' pool
            // (because b_ptr is incrementing through a sorted array),
            // and a[a_ptr] is the smallest available element from the 'a_sorted' pool,
            // we must try a larger element from the 'b_elements' pool.
            // So, we only increment b_ptr to consider the next larger element.
            b_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // Create the result array A'
    // The i-th smallest B value should be paired with the i-th largest A value.
    // This means b_elements[i] (which is the i-th smallest B)
    // should be paired with a_elements[m - 1 - i] (which is the i-th largest A).
    // The original index of b_elements[i] tells us where in the output array A'
    // the value a_elements[m - 1 - i].value should go.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

