#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Check if N is a power of 2
                // If N is a power of 2, N/2 is the only optimal move for Chanek
                // if N > 2. If N=2, taking 1 or N/2=1 yields same result.
                // If N is not a power of 2, N/2 might be better.
                // The opponent will try to maximize their own coins.
                // If Chanek takes N/2, opponent gets N/2.
                // If Chanek takes 1, opponent gets (N-1)/2 or (N-1)/2 + 1.
                // The strategy is: if N is even, and N is not 4, take N/2.
                // If N is 4, taking N/2=2 leaves 2 for opponent. Opponent takes 1, Chanek takes 1. Chanek gets 2.
                // If N is 4, taking 1 leaves 3 for opponent. Opponent takes 1, leaves 2. Chanek takes 1, leaves 1. Opponent takes 1. Chanek gets 1+1=2.
                // For N=4, both moves yield 2 for Chanek.
                // The special case is when N is even and N/2 is odd.
                // If N is even and N/2 is odd, it means N = 2 * (odd number).
                // Example: N=6. N/2=3 (odd).
                //   Chanek takes N/2=3. N becomes 3. Opponent takes 1. N becomes 2. Chanek takes 1. N becomes 1. Opponent takes 1.
                //   Chanek gets 3+1=4. Opponent gets 1+1=2.
                //   If Chanek takes 1. N becomes 5. Opponent takes 1. N becomes 4. Chanek takes 2. N becomes 2. Opponent takes 1. N becomes 1. Chanek takes 1.
                //   Chanek gets 1+2+1=4. Opponent gets 1+1=2.
                // It seems taking N/2 is generally better or equal.
                // The only exception is when N/2 is odd, and taking 1 would lead to a better outcome.
                // This happens when N is a power of 2, specifically N = 2^k where k >= 2.
                // If N is a power of 2 (and N > 2), then N/2 is also a power of 2.
                // If N is even, and N/2 is odd, it means N = 2 * (odd number).
                // In this case, taking 1 makes N-1 odd, forcing opponent to take 1.
                // This is the optimal strategy for Chanek.
                // If N is even, and N/2 is even, then N = 4k.
                // In this case, taking N/2 is generally better.
                // The only case where taking 1 is better for Chanek is when N is even, and N/2 is odd.
                // This means N = 2 * (odd number).
                // Example: N=6. N/2=3 (odd).
                //   Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //   Chanek: 1+2+1=4. Opponent: 1+1=2.
                //   If Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                //   Chanek: 3+1=4. Opponent: 1+1=2.
                // Both yield 4.
                // The only case where taking 1 is strictly better is when N is a power of 2, and N/2 is odd.
                // This is impossible. If N is a power of 2, N/2 is also a power of 2.
                // So, if N is even, and N/2 is odd, it means N = 2 * (odd number).
                // In this specific scenario, taking 1 coin is better for Chanek.
                // Why? Because if Chanek takes N/2, the opponent gets an odd number of coins (N/2).
                // If Chanek takes 1, the opponent gets an odd number of coins (N-1).
                // The key insight is that if N is even, and N/2 is odd, then N is of the form 2 * (odd number).
                // In this case, taking 1 coin is always optimal for Chanek.
                // This is because it forces the opponent to take 1 coin (since N-1 is odd),
                // and then Chanek gets to play on an even number again.
                // If Chanek takes N/2, the opponent gets to play on an odd number.
                // This is a known pattern in such games.
                // If N is even and N/2 is odd (i.e., N = 2 * (odd number)), Chanek takes 1.
                // Otherwise (N is even and N/2 is even, i.e., N = 4k), Chanek takes N/2.

                if ((n / 2) % 2 != 0 && n != 2) { // N is even, N/2 is odd, and N is not 2
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even, N/2 is even (N=4k), or N=2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                // Opponent also plays optimally to maximize their own coins.
                // Same logic as Chanek.
                if ((n / 2) % 2 != 0 && n != 2) { // N is even, N/2 is odd, and N is not 2
                    n -= 1;
                } else { // N is even, N/2 is even (N=4k), or N=2
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

