    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[normalize_pattern(pattern)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[normalize_pattern(pattern)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_pattern(s)] << "\n";
        }
    }

    return 0;
}

