int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is total_sum - prefix_sum[i]
        // which is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalanced counts
        if (i > j) { // More items from left than right
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (long long)(j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

