    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1, y)
            // If f1 == 0, robot cannot move left.
            // This means it cannot reach any point (X, Y) where X < x.
            // So, X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x, y+1)
            // If f2 == 0, robot cannot move up.
            // This means it cannot reach any point (X, Y) where Y > y.
            // So, Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x+1, y)
            // If f3 == 0, robot cannot move right.
            // This means it cannot reach any point (X, Y) where X > x.
            // So, X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 == 0, robot cannot move down.
            // This means it cannot reach any point (X, Y) where Y < y.
            // So, Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
            // Our calculated min_x, max_x, min_y, max_y might be outside this range
            // if all robots allow movement far away.
            // However, any point within [min_x, max_x] x [min_y, max_y] is valid.
            // We can just pick min_x and min_y, as they are guaranteed to be within [-10^5, 10^5]
            // if a solution exists.
            // The problem statement says: "Both X and Y should not exceed 10^5 by absolute value;
            // it is guaranteed that if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
            // This means we can just output min_x and min_y directly, as they will be valid.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int x = 0; x <= 9; ++x) { // Iterate through all possible pivot digits (0-9)
        std::string current_result(n, ' ');
        char last1 = '0'; // Last digit in sequence 1
        char last2 = '0'; // Last digit in sequence 2
        bool valid_x = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < x + '0') { // Digit is strictly less than pivot
                if (digit < last1) { // Violates non-decreasing for color 1
                    valid_x = false;
                    break;
                }
                current_result[i] = '1';
                last1 = digit;
            } else if (digit > x + '0') { // Digit is strictly greater than pivot
                if (digit < last2) { // Violates non-decreasing for color 2
                    valid_x = false;
                    break;
                }
                current_result[i] = '2';
                last2 = digit;
            } else { // Digit is equal to pivot
                // Try to assign to color 2 first if possible, to keep color 1 digits smaller
                if (digit < last2) { // Cannot assign to color 2 without violating non-decreasing
                    if (digit < last1) { // Cannot assign to color 1 either
                        valid_x = false;
                        break;
                    }
                    current_result[i] = '1';
                    last1 = digit;
                } else { // Can assign to color 2
                    current_result[i] = '2';
                    last2 = digit;
                }
            }
        }

        if (valid_x) {
            // After assigning all digits, check the final condition:
            // last digit of S1 <= first digit of S2.
            // In our construction, last1 is the maximum digit assigned to color 1.
            // last2 is the minimum digit assigned to color 2.
            // This is implicitly handled by the logic:
            // - All digits < x are '1'.
            // - All digits > x are '2'.
            // - Digits == x are either '1' or '2'.
            //   - If '1', they must be >= last '1' digit.
            //   - If '2', they must be >= last '2' digit.
            // The critical part is that any digit '1' must be <= any digit '2'.
            // Our strategy ensures this:
            // Any digit colored '1' is either < x or = x.
            // Any digit colored '2' is either > x or = x.
            // If a digit '1' is < x and a digit '2' is > x, then '1' < '2'.
            // If a digit '1' is = x and a digit '2' is > x, then '1' < '2'.
            // If a digit '1' is < x and a digit '2' is = x, then '1' < '2'.
            // The only case where it's not immediately obvious is if both are = x.
            // But if a digit '1' is = x and a digit '2' is = x, then '1' == '2', which is fine.
            // The crucial part is that all digits colored '1' must be <= all digits colored '2'.
            // Our construction ensures this by partitioning around 'x'.
            // The only remaining check is that last1 <= first_digit_in_S2.
            // Our logic for assigning 'x' digits (preferring '2' if possible)
            // ensures that last1 will be as small as possible, and first_digit_in_S2
            // will be as large as possible among the 'x' digits.
            // If last1 is an 'x' digit, and first_digit_in_S2 is an 'x' digit, they are equal.
            // If last1 is < x, and first_digit_in_S2 is x, then last1 < first_digit_in_S2.
            // If last1 is < x, and first_digit_in_S2 is > x, then last1 < first_digit_in_S2.
            // So, the conditions are met.

            result = current_result;
            possible = true;
            break; // Found a valid coloring, no need to check other x values
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <deque>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    std::string s;
    std::cin >> s;

    std::deque<char> keyboard_layout;
    std::set<char> used_chars;
    bool possible = true;

    if (s.empty()) {
        // This case is not explicitly mentioned but |s| >= 1.
        // If it were possible, any layout would be fine.
        // For now, assume s is never empty based on constraints.
    } else {
        keyboard_layout.push_back(s[0]);
        used_chars.insert(s[0]);

        for (size_t i = 1; i < s.length(); ++i) {
            char current_char = s[i];
            char prev_char = s[i-1];

            // Check if current_char is already in the layout
            if (used_chars.count(current_char)) {
                // If current_char is already in the layout, it must be adjacent to prev_char.
                // Find prev_char's position
                auto it_prev = std::find(keyboard_layout.begin(), keyboard_layout.end(), prev_char);

                // Check left neighbor
                if (it_prev != keyboard_layout.begin()) {
                    if (*std::prev(it_prev) == current_char) {
                        continue; // Valid adjacency
                    }
                }
                // Check right neighbor
                if (std::next(it_prev) != keyboard_layout.end()) {
                    if (*std::next(it_prev) == current_char) {
                        continue; // Valid adjacency
                    }
                }
                // If current_char is used but not adjacent to prev_char, it's impossible
                possible = false;
                break;
            } else {
                // current_char is not yet in the layout. Add it adjacent to prev_char.
                // Find prev_char's position
                auto it_prev = std::find(keyboard_layout.begin(), keyboard_layout.end(), prev_char);

                // Try to add to the left
                if (it_prev == keyboard_layout.begin()) {
                    keyboard_layout.push_front(current_char);
                    used_chars.insert(current_char);
                } 
                // Try to add to the right
                else if (std::next(it_prev) == keyboard_layout.end()) {
                    keyboard_layout.push_back(current_char);
                    used_chars.insert(current_char);
                }
                // If prev_char is in the middle, we can't add current_char without breaking existing adjacencies.
                // This means prev_char already has two neighbors, and current_char is new.
                // This scenario implies impossibility.
                else {
                    possible = false;
                    break;
                }
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
    } else {
        std::cout << "YES\n";
        for (char c : keyboard_layout) {
            std::cout << c;
        }
        // Add remaining unused characters
        for (char c = 'a'; c <= 'z'; ++c) {
            if (used_chars.find(c) == used_chars.end()) {
                std::cout << c;
            }
        }
        std::cout << "\n";
    }
}

