int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r for 1 <= r < b: sum_r = (b-1) * b / 2
    // This is (b-1) * b * inv(2) mod MOD
    long long sum_r_term = (b - 1);
    sum_r_term %= MOD;
    long long sum_r_term_div_2 = (sum_r_term * b) % MOD;
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_term_div_2 = (sum_r_term_div_2 * inv2) % MOD;

    // Sum of (k * b + 1) for 1 <= k <= a:
    // sum_k = sum(k*b + 1) = b * sum(k) + sum(1)
    // sum(k) for 1 <= k <= a is a * (a+1) / 2
    // sum(1) for 1 <= k <= a is a
    long long sum_k_b_plus_1_term = (a * (a + 1)) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term * inv2) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term * b) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term + a) % MOD;

    long long total_sum = (sum_r_term_div_2 * sum_k_b_plus_1_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

