        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = 1;

    for (int i = 0; i < n; i += k) {
        int block_start_val = current_val;
        int block_end_val = std::min(n, current_val + k - 1);

        for (int j = 0; j <= block_end_val - block_start_val; ++j) {
            p[i + j] = block_end_val - j;
        }
        current_val += k;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute character occurrences for each shift
    // char_at_shift[k][char_code] = count of char_code at position k
    std::vector<std::vector<int>> char_at_shift(L, std::vector<int>(26, 0));
    for (int k = 0; k < L; ++k) {
        char_at_shift[k][s[k] - 'a']++;
    }

    // For each possible first character c0 (which is s[k_actual])
    // and for each possible second character cp (which is s[(p + k_actual) % L])
    // count how many k values satisfy s[k] = c0 and s[(p+k)%L] = cp.
    // This is stored in `counts[c0_idx][p][cp_idx]`.
    // `c0_idx` is `s[k_actual] - 'a'`.
    // `p` is the chosen second position.
    // `cp_idx` is `s[(p + k_actual) % L] - 'a'`.
    std::vector<std::vector<std::vector<int>>> counts(26, std::vector<std::vector<int>>(L, std::vector<int>(26, 0)));

    for (int k = 0; k < L; ++k) { // Iterate through all possible actual shifts k_actual
        int c0_idx = s[k] - 'a'; // The first character Vasya sees is s[k_actual]
        for (int p = 1; p < L; ++p) { // Iterate through all possible second positions p Vasya might choose
            int cp_idx = s[(p + k) % L] - 'a'; // The second character Vasya sees is s[(p + k_actual) % L]
            counts[c0_idx][p][cp_idx]++;
        }
    }

    double total_win_prob = 0.0;

    // Iterate through each possible first character Vasya might observe (c0)
    for (int c0_idx = 0; c0_idx < 26; ++c0_idx) {
        // Number of shifts k for which s[k] == c0
        int num_k_for_c0 = 0;
        for (int k = 0; k < L; ++k) {
            if (s[k] - 'a' == c0_idx) {
                num_k_for_c0++;
            }
        }

        if (num_k_for_c0 == 0) {
            continue; // This c0 will never be observed as t[0]
        }

        // Vasya plays optimally: choose p to maximize win probability for this c0
        double max_win_prob_for_c0 = 0.0;

        // Iterate through all possible second positions p Vasya can choose
        for (int p = 1; p < L; ++p) {
            double current_win_prob_for_p = 0.0;
            // For a fixed c0 and p, iterate through all possible second characters cp
            for (int cp_idx = 0; cp_idx < 26; ++cp_idx) {
                int num_matches = counts[c0_idx][p][cp_idx];
                if (num_matches == 1) {
                    // If only one k matches (c0, cp), Vasya wins for this (c0, cp) pair
                    current_win_prob_for_p += 1.0;
                }
            }
            // Divide by num_k_for_c0 because this is the number of actual k's that could lead to c0
            // and for each such k, a specific cp is observed.
            // The sum `current_win_prob_for_p` is effectively the count of unique (k, p) pairs
            // that result in a win for this c0 and chosen p.
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, current_win_prob_for_p / num_k_for_c0);
        }

        // Add the contribution of this c0 to the total probability
        // (num_k_for_c0 / L) is the probability of observing this c0 as t[0]
        total_win_prob += (static_cast<double>(num_k_for_c0) / L) * max_win_prob_for_c0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance (strawberry - blueberry)
    // 1 -> +1, 2 -> -1
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // If initial balance is 0, no jars need to be emptied.
    if (initial_balance == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Store prefix sums for the left side (jars 1 to n)
    // `left_diff[k]` is the balance of jars `n-k+1` to `n`
    // `left_diff[0]` is 0 (no jars removed from left)
    // `left_diff[1]` is balance of jar `n`
    // `left_diff[k]` is balance of jars `n-k+1` ... `n`
    std::map<int, int> left_diff_to_k; // maps balance_diff -> k (number of jars removed from left)
    left_diff_to_k[0] = 0; // 0 jars removed from left, balance change is 0

    int current_left_balance_change = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n - k; // 0-indexed: jar n is at index n-1, jar n-1 is at index n-2, etc.
        if (a[jar_idx] == 1) {
            current_left_balance_change++;
        } else {
            current_left_balance_change--;
        }
        if (left_diff_to_k.find(current_left_balance_change) == left_diff_to_k.end()) {
            left_diff_to_k[current_left_balance_change] = k;
        }
    }

    // Iterate through possible number of jars removed from right (k_right)
    // `right_diff[k]` is the balance of jars `n+1` to `n+k`
    // `right_diff[0]` is 0 (no jars removed from right)
    // `right_diff[1]` is balance of jar `n+1`
    // `right_diff[k]` is balance of jars `n+1` ... `n+k`
    int min_removed_jars = 2 * n; // Max possible jars to remove

    // Case 1: Only remove jars from the left
    // We need initial_balance - current_left_balance_change = 0
    // So, current_left_balance_change = initial_balance
    if (left_diff_to_k.count(initial_balance)) {
        min_removed_jars = std::min(min_removed_jars, left_diff_to_k[initial_balance]);
    }

    // Case 2: Remove jars from both left and right, or only from right
    int current_right_balance_change = 0;
    for (int k_right = 0; k_right <= n; ++k_right) {
        if (k_right > 0) {
            int jar_idx = n + k_right - 1; // 0-indexed: jar n+1 is at index n, jar n+2 is at index n+1, etc.
            if (a[jar_idx] == 1) {
                current_right_balance_change++;
            } else {
                current_right_balance_change--;
            }
        }

        // We need initial_balance - current_left_balance_change - current_right_balance_change = 0
        // So, current_left_balance_change = initial_balance - current_right_balance_change
        int target_left_balance_change = initial_balance - current_right_balance_change;

        if (left_diff_to_k.count(target_left_balance_change)) {
            int k_left = left_diff_to_k[target_left_balance_change];
            min_removed_jars = std::min(min_removed_jars, k_left + k_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // We need to track the final state of a bit if it starts as 0, and if it starts as 1.
    // Since constants are up to 1023 (10 bits), we only care about bits 0-9.
    // Let's represent the state for a bit position `j`:
    // `val_if_0[j]` is the value of bit `j` if the initial input bit `j` was 0.
    // `val_if_1[j]` is the value of bit `j` if the initial input bit `j` was 1.
    // Initially, for each bit `j`:
    // `val_if_0[j] = 0`
    // `val_if_1[j] = 1`
    int val_if_0 = 0; // Represents the state of all bits if they started as 0
    int val_if_1 = 1023; // Represents the state of all bits if they started as 1 (all 1s up to 10th bit)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val_if_0 &= x;
            val_if_1 &= x;
        } else if (op_char == '|') {
            val_if_0 |= x;
            val_if_1 |= x;
        } else if (op_char == '^') {
            val_if_0 ^= x;
            val_if_1 ^= x;
        }
    }

    // Now we have the final state for each bit position.
    // For each bit `j` (from 0 to 9):
    // `final_bit_0[j]` is the `j`-th bit of `val_if_0`.
    // `final_bit_1[j]` is the `j`-th bit of `val_if_1`.

    // We want to find three constants A, B, C such that:
    // (input_bit & A) | B ^ C = final_bit
    //
    // Let's analyze the effect of (input_bit & A) | B ^ C for input_bit = 0 and input_bit = 1.
    // If input_bit = 0: (0 & A) | B ^ C = 0 | B ^ C = B ^ C
    // This must be equal to `final_bit_0`. So, `B ^ C = final_bit_0`.
    //
    // If input_bit = 1: (1 & A) | B ^ C = A | B ^ C
    // This must be equal to `final_bit_1`. So, `A | B ^ C = final_bit_1`.
    // Substituting `B ^ C = final_bit_0`:
    // `A | final_bit_0 = final_bit_1`.

    // We need to find A, B, C (each from 0 to 1023) that satisfy these conditions for all bits.
    // Let's construct A, B, C bit by bit.
    int A = 0;
    int B = 0;
    int C = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_mask = (1 << j);
        int final_bit_0_j = (val_if_0 & bit_mask) >> j;
        int final_bit_1_j = (val_if_1 & bit_mask) >> j;

        // Case 1: final_bit_0_j = 0, final_bit_1_j = 0
        // B_j ^ C_j = 0  => B_j = C_j
        // A_j | (B_j ^ C_j) = 0 => A_j | 0 = 0 => A_j = 0
        // So, A_j = 0, B_j = C_j = 0 (or 1, but 0 is simpler)
        if (final_bit_0_j == 0 && final_bit_1_j == 0) {
            // A_j = 0, B_j = 0, C_j = 0
        }
        // Case 2: final_bit_0_j = 0, final_bit_1_j = 1
        // B_j ^ C_j = 0  => B_j = C_j
        // A_j | (B_j ^ C_j) = 1 => A_j | 0 = 1 => A_j = 1
        // So, A_j = 1, B_j = C_j = 0 (or 1, but 0 is simpler)
        else if (final_bit_0_j == 0 && final_bit_1_j == 1) {
            A |= bit_mask; // A_j = 1
            // B_j = 0, C_j = 0
        }
        // Case 3: final_bit_0_j = 1, final_bit_1_j = 0
        // B_j ^ C_j = 1
        // A_j | (B_j ^ C_j) = 0 => A_j | 1 = 0 (impossible for A_j >= 0)
        // This means this combination of final_bit_0_j and final_bit_1_j cannot be achieved
        // with (x & A) | B ^ C.
        // However, we know that any sequence of operations can be reduced to at most 3 operations.
        // The general form is (x & A) | B ^ C.
        // Let's re-evaluate the general form.
        // A single bit transformation can be one of four types:
        // 0 -> 0, 1 -> 0 (always 0)
        // 0 -> 0, 1 -> 1 (identity)
        // 0 -> 1, 1 -> 0 (NOT)
        // 0 -> 1, 1 -> 1 (always 1)
        //
        // Let's map these to (x_j & A_j) | B_j ^ C_j:
        //
        // Type 1: 0 -> 0, 1 -> 0
        // final_bit_0_j = 0, final_bit_1_j = 0
        // (0 & A_j) | B_j ^ C_j = 0  => B_j ^ C_j = 0
        // (1 & A_j) | B_j ^ C_j = 0  => A_j | (B_j ^ C_j) = 0 => A_j | 0 = 0 => A_j = 0
        // Solution: A_j = 0, B_j = 0, C_j = 0. (x_j & 0) | 0 ^ 0 = 0
        //
        // Type 2: 0 -> 0, 1 -> 1
        // final_bit_0_j = 0, final_bit_1_j = 1
        // (0 & A_j) | B_j ^ C_j = 0  => B_j ^ C_j = 0
        // (1 & A_j) | B_j ^ C_j = 1  => A_j | (B_j ^ C_j) = 1 => A_j | 0 = 1 => A_j = 1
        // Solution: A_j = 1, B_j = 0, C_j = 0. (x_j & 1) | 0 ^ 0 = x_j
        //
        // Type 3: 0 -> 1, 1 -> 0
        // final_bit_0_j = 1, final_bit_1_j = 0
        // (0 & A_j) | B_j ^ C_j = 1  => B_j ^ C_j = 1
        // (1 & A_j) | B_j ^ C_j = 0  => A_j | (B_j ^ C_j) = 0 => A_j | 1 = 0 (impossible)
        // This means the form (x & A) | B ^ C is not general enough.
        // The general form is actually (x & A) | (x' & B) | C, where x' is NOT x.
        // Or, more simply, any bit transformation can be represented by at most 3 operations.
        //
        // Let's use the standard reduction:
        // We need to find `and_val`, `or_val`, `xor_val` such that:
        // `( (x & and_val) | or_val ) ^ xor_val`
        //
        // Let's track the two values `val_if_0` and `val_if_1` as before.
        //
        // For each bit `j`:
        // `final_bit_0_j` is the `j`-th bit of `val_if_0`.
        // `final_bit_1_j` is the `j`-th bit of `val_if_1`.
        //
        // We want to find `A_j`, `O_j`, `X_j` such that:
        // `((0 & A_j) | O_j) ^ X_j = final_bit_0_j`
        // `((1 & A_j) | O_j) ^ X_j = final_bit_1_j`
        //
        // This simplifies to:
        // `O_j ^ X_j = final_bit_0_j`
        // `(A_j | O_j) ^ X_j = final_bit_1_j`
        //
        // From the first equation, `X_j = O_j ^ final_bit_0_j`.
        // Substitute `X_j` into the second equation:
        // `(A_j | O_j) ^ (O_j ^ final_bit_0_j) = final_bit_1_j`
        //
        // Let's try to find `A_j`, `O_j`, `X_j` for each of the 4 cases:
        //
        // Case 1: (0 -> 0, 1 -> 0)  => final_bit_0_j = 0, final_bit_1_j = 0
        // `O_j ^ X_j = 0`
        // `(A_j | O_j) ^ X_j = 0`
        // Choose `O_j = 0`. Then `X_j = 0`.
        // `(A_j | 0) ^ 0 = 0` => `A_j = 0`.
        // Solution: `A_j = 0, O_j = 0, X_j = 0`.
        //
        // Case 2: (0 -> 0, 1 -> 1)  => final_bit_0_j = 0, final_bit_1_j = 1
        // `O_j ^ X_j = 0`
        // `(A_j | O_j) ^ X_j = 1`
        // Choose `O_j = 0`. Then `X_j = 0`.
        // `(A_j | 0) ^ 0 = 1` => `A_j = 1`.
        // Solution: `A_j = 1, O_j = 0, X_j = 0`.
        //
        // Case 3: (0 -> 1, 1 -> 0)  => final_bit_0_j = 1, final_bit_1_j = 0
        // `O_j ^ X_j = 1`
        // `(A_j | O_j) ^ X_j = 0`
        // Choose `O_j = 0`. Then `X_j = 1`.
        // `(A_j | 0) ^ 1 = 0` => `A_j ^ 1 = 0` => `A_j = 1`.
        // Solution: `A_j = 1, O_j = 0, X_j = 1`.
        //
        // Case 4: (0 -> 1, 1 -> 1)  => final_bit_0_j = 1, final_bit_1_j = 1
        // `O_j ^ X_j = 1`
        // `(A_j | O_j) ^ X_j = 1`
        // Choose `O_j = 1`. Then `X_j = 0`.
        // `(A_j | 1) ^ 0 = 1` => `A_j | 1 = 1`. This is true for any `A_j`. Choose `A_j = 0`.
        // Solution: `A_j = 0, O_j = 1, X_j = 0`.

        // Let's build the constants `and_const`, `or_const`, `xor_const` based on these rules.
        // `and_const` corresponds to `A`
        // `or_const` corresponds to `O`
        // `xor_const` corresponds to `X`
        int A_j = 0, O_j = 0, X_j = 0;

        if (final_bit_0_j == 0 && final_bit_1_j == 0) {
            // A_j = 0, O_j = 0, X_j = 0
        } else if (final_bit_0_j == 0 && final_bit_1_j == 1) {
            A_j = 1;
            // O_j = 0, X_j = 0
        } else if (final_bit_0_j == 1 && final_bit_1_j == 0) {
            A_j = 1;
            X_j = 1;
            // O_j = 0
        } else if (final_bit_0_j == 1 && final_bit_1_j == 1) {
            O_j = 1;
            // A_j = 0, X_j = 0
        }

        if (A_j == 1) A |= bit_mask;
        if (O_j == 1) B |= bit_mask;
        if (X_j == 1) C |= bit_mask;
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', A});
    }
    if (B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', B});
    }
    if (C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', C});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        // Case 1: Substrings starting with '0'
        // If s[i] is '0', then f(s[i...r]) = f(s[i+1...r])
        // The length is r - i + 1.
        // We need r - i + 1 = f(s[i+1...r]).
        // The maximum value for f(s[i+1...r]) is 2^(r-i) - 1.
        // So, r - i + 1 <= 2^(r-i) - 1.
        // Let k = r - i. Then k+1 <= 2^k - 1.
        // This holds for k >= 2.
        // If k=0 (r=i), f(s[i]) = 0. Length = 1. 1 != 0. Not good.
        // If k=1 (r=i+1), f(s[i...i+1]) = f(s[i+1]). Length = 2.
        //   If s[i+1] = '0', f=0. 2 != 0. Not good.
        //   If s[i+1] = '1', f=1. 2 != 1. Not good.
        // So, for s[i] = '0', we only need to check substrings s[i...r] where r-i+1 is small.
        // The maximum length we need to check for f(s[i...r]) is around 20 (since 2^18 is ~2.6e5, 2^19 is ~5.2e5).
        // If s[i] is '0', the value f(s[i...r]) is the same as f(s[i+1...r]).
        // The length is `len = r - i + 1`.
        // The value `val` is `f(s[i+1...r])`.
        // We need `len = val`.
        // The maximum `len` is `n`. The maximum `val` is `n`.
        // So `val` can be at most `n`.
        // The maximum number of bits needed to represent `n` is `log2(n) + 1`.
        // For `n = 2 * 10^5`, `log2(2 * 10^5)` is about `17.6`. So about 18 bits.
        // This means `r - (i+1) + 1` (length of `s[i+1...r]`) can be at most around 18-20.
        // So `r - i` can be at most around 18-20.
        // This means `r` can be at most `i + 19`.
        // We can iterate `r` from `i` up to `min(n-1, i + MAX_BITS_FOR_N)`.
        // Let's use a safe upper bound for MAX_BITS_FOR_N, say 20.
        // This is because 2^18 is 262144, which is > 2e5. So a binary string of length 18 can represent any value up to 2e5.
        // If s[i] is '0', the value is computed from s[i+1...r].
        // The length of s[i+1...r] is `r - (i+1) + 1 = r - i`.
        // The maximum value of `r - i` is `n-1`.
        // The maximum value of `f(s[i+1...r])` is `n`.
        // So `r - i` can be at most `log2(n) + 1`.
        // For `n = 2e5`, `log2(2e5) + 1` is about `18.6`. So `r-i` can be at most 19.
        // So `r` can be at most `i + 19`.
        // This means we only need to check a small window for `r`.

        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // If s[i] is '0', the value is derived from s[i+1...j].
            // If s[i] is '1', the value is derived from s[i...j].
            // We can compute current_val for s[i...j] directly.
            // If current_val exceeds a certain threshold (e.g., n + MAX_BITS_FOR_N), we can break.
            // The maximum possible length is n.
            // The maximum possible value is n.
            // If len > 60, current_val will overflow long long if it starts with '1'.
            // But we only care if current_val == len.
            // If len > 20, and current_val starts with '1', then current_val >= 2^(len-1).
            // 2^(20-1) = 2^19 = 524288. This is already greater than n (2e5).
            // So if len > 20 and s[i] == '1', current_val will be too large.
            // If len > 20 and s[i] == '0', then current_val is f(s[i+1...j]).
            // The length of s[i+1...j] is len-1.
            // If len-1 > 20, then f(s[i+1...j]) will be too large if s[i+1] == '1'.
            // So we only need to check for len up to around 20 + 1 = 21.
            // Let's use a slightly larger bound, say 25, to be safe.

            if (len > 25) { // If length is too large, value will exceed N unless it's all zeros.
                            // But if it's all zeros, value is 0, and len > 0, so len != value.
                            // If s[i] is '1', then current_val >= 2^(len-1).
                            // If len-1 >= 18, then current_val >= 2^18 = 262144 > 2e5.
                            // So if len >= 19 and s[i] == '1', current_val > n.
                            // If s[i] == '0', then current_val = f(s[i+1...j]).
                            // The length of s[i+1...j] is len-1.
                            // If len-1 >= 19 and s[i+1] == '1', then current_val > n.
                            // So we can break if len is large enough.
                            // A safe upper bound for len is around 20 + 1 (for the leading zero) = 21.
