    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_j to a very large positive value.
    // b_j represents the maximum possible initial value for a_j.
    // If a_j + current_delta_j <= m_i, then a_j <= m_i - current_delta_j.
    // So, a_j must be less than or equal to min(m_i - current_delta_j) over all relevant type 2 ops.
    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // Calculate b_j values
    std::vector<long long> current_delta(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize a_j_prime to b_j. This is our candidate initial array.
    std::vector<long long> a_prime(n);
    for (int i = 0; i < n; ++i) {
        a_prime[i] = b[i];
    }

    // Verify the candidate array a_prime
    std::vector<long long> current_a(n);
    for (int i = 0; i < n; ++i) {
        current_a[i] = a_prime[i];
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_prime[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

