    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // If 'a' has an odd number of ones, we can append a '1'.
    // If 'a' has an even number of ones, we can append a '0'.
    // This means we can always increase the number of ones by 1 if it's odd,
    // or keep it the same if it's even, by appending '1' or '0' respectively.
    // Effectively, we can always make the number of ones in 'a' (after appending parity)
    // equal to ones_in_a or ones_in_a + 1.
    // The maximum number of ones we can achieve in an extended 'a' of length |b|
    // is ones_in_a + (a.length() % 2) + (b.length() - a.length()).
    // However, a simpler approach is to consider the total number of ones.
    // If ones_in_a is odd, we can append '1', making it even.
    // If ones_in_a is even, we can append '0', keeping it even.
    // So, if ones_in_a is odd, we can effectively have ones_in_a + 1 ones
    // in the string of length a.length() + 1.
    // If ones_in_a is even, we can effectively have ones_in_a ones
    // in the string of length a.length() + 1.
    // This means the maximum number of ones we can have in a string of length L
    // that is derived from 'a' by appending parity bits is:
    // initial_ones_in_a + (initial_ones_in_a % 2) + (L - a.length() - 1) if L > a.length()
    // or just initial_ones_in_a if L == a.length().
    // A more concise way:
    // The number of ones in 'a' can be increased by 1 if it's odd (by appending '1'),
    // or stay the same if it's even (by appending '0').
    // So, the effective number of ones in 'a' that can be used to form 'b'
    // (after potentially appending one parity bit to make it odd if it was even,
    // or keeping it odd if it was odd) is `ones_in_a + (ones_in_a % 2)`.
    // This is the maximum number of '1's we can have in the initial part of 'a'
    // that is at least as long as 'b' (or can be extended to be as long as 'b').

    // The crucial observation is that we can always append a '0' or '1' to 'a'.
    // If we need more '1's, and current parity is '1', we append '1'.
    // If we need more '1's, and current parity is '0', we append '0' then '1' (if possible).
    // But we can only append the *current* parity.
    // The total number of ones in 'a' can be increased by 1 if its current parity is 1.
    // If its current parity is 0, it stays the same.
    // So, the maximum number of ones we can have in 'a' after any number of parity appends
    // is `ones_in_a + (ones_in_a % 2)`.
    // This is because if `ones_in_a` is even, we append '0', `ones_in_a` remains even.
    // If `ones_in_a` is odd, we append '1', `ones_in_a` becomes even.
    // So, after one append, `ones_in_a` becomes `ones_in_a + (ones_in_a % 2)`.
    // After that, it will always be even, so we will always append '0's.
    // Thus, the maximum number of ones we can ever achieve in any string derived from 'a'
    // by appending parity bits is `ones_in_a + (ones_in_a % 2)`.

    int max_ones_reachable_in_a = ones_in_a + (ones_in_a % 2);

    if (max_ones_reachable_in_a >= ones_in_b && a.length() <= b.length()) {
