struct Child {
    int id;
    long long v; // Use long long for v, d, p to avoid overflow during calculations
    long long d;
    long long p;
    bool present;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].present = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].present) {
            continue; // This child has already run away
        }

        // Child i goes to the doctor
        cured_children_ids.push_back(children[i].id);
        children[i].present = false; // Child i is now cured and out of the line

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d values from children who run away

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].present) {
                continue; // This child has already run away
            }

            // Apply effects from the child in the doctor's office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--; // v_i, v_i-1, v_i-2, ...
            }

            // Apply effects from children who ran away earlier in this round
            children[j].p -= total_d_effect;

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].present = false;
                total_d_effect += children[j].d; // Add their d value to the total effect for subsequent children
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // All f values are of the form a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-2].value + a[n-1].value + h.
    // This happens if a[0] and a[1] are in the same group, and a[n-2] and a[n-1] are in different groups.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in the same group.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in different groups.
    // The minimum f value will be min(a[0].value + a[1].value, a[0].value + a[1].value + h).
    // The maximum f value will be max(a[n-2].value + a[n-1].value, a[n-2].value + a[n-1].value + h).
    //
    // The critical observation is that if we have two non-empty subsequences,
    // then there must be at least one pair (a_i, a_j) in the same subsequence,
    // and at least one pair (a_k, a_l) in different subsequences.
    //
    // So, min_f will be at most a[0].value + a[1].value.
    // And max_f will be at least a[n-2].value + a[n-1].value + h.
    //
    // However, we can try to make the minimum f value as large as possible,
    // and the maximum f value as small as possible.
    //
    // Consider a partition where a[0] is in group 1, and all other elements are in group 2.
    // min_f:
    //   - a[0].value + a[1].value + h (a[0] in group 1, a[1] in group 2)
    //   - a[1].value + a[2].value (a[1], a[2] in group 2)
    //   The minimum of these two is a[1].value + a[2].value.
    // max_f:
    //   - a[n-2].value + a[n-1].value (a[n-2], a[n-1] in group 2)
    //   - a[0].value + a[n-1].value + h (a[0] in group 1, a[n-1] in group 2)
    //   The maximum of these two is a[0].value + a[n-1].value + h.
    //
    // Goodness = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) - min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Let's simplify.
    // The smallest possible sum is `a[0].value + a[1].value`.
    // The largest possible sum is `a[n-1].value + a[n-2].value`.
    //
    // If we put `a[0]` in group 1 and all others in group 2:
    // Pairs in same group: `(a[i], a[j])` for `i,j >= 1`. Smallest is `a[1].value + a[2].value`. Largest is `a[n-2].value + a[n-1].value`.
    // Pairs in different groups: `(a[0], a[j])` for `j >= 1`. Smallest is `a[0].value + a[1].value + h`. Largest is `a[0].value + a[n-1].value + h`.
    //
    // So, for this partition:
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    // Goodness = max_f - min_f;
    //
    // This is the goodness for the partition where a[0] is in group 1, and all others are in group 2.
    // Let's call this goodness2.
    long long min_f2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long max_f2 = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
    long long goodness2 = max_f2 - min_f2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        std::vector<int> result_partition(n);
        for (int i = 0; i < n; ++i) {
            result_partition[a[i].original_index] = 1;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        std::vector<int> result_partition(n);
        result_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[a[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();
    long long total_pairs = static_cast<long long>(n) * (n + 1) / 2;

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[i] stores the minimum r (1-based) such that (i, r) is a "good" pair.
                                                // If no such r exists, it's n+1.

    // Iterate through all possible starting positions x (0-based)
    for (int x = 0; x < n; ++x) {
        // Iterate through possible values of k.
        // The maximum value for k is such that x + 2k < n.
        // So 2k < n - x, or k < (n - x) / 2.
        // Since k must be at least 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a "bad" triplet (x, x+k, x+2k)
                // This triplet covers the range [x, x+2k] (0-based).
                // In 1-based indexing, this is [x+1, x+2k+1].
                // Any pair (l, r) such that l <= x+1 and r >= x+2k+1 is "good".
                // We are interested in the smallest r for a given l.
                // For l = x+1, the smallest r is x+2k+1.
                // We want to update min_r_for_l[x+1] with min(current_value, x+2k+1).
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
        }
    }

    // Now, propagate the minimum r values.
    // If (l, r) is good, then (l, r+1) is also good.
    // If (l, r) is good, then (l-1, r) is also good.
    // This means min_r_for_l[l] should be at most min_r_for_l[l+1].
    // We want to find the smallest r for each l.
    // If min_r_for_l[l] is n+1, it means no triplet starts at l.
    // However, a triplet starting at l' < l might extend to cover l.
    // The current min_r_for_l[l] only considers triplets starting exactly at l.
    // We need to find the minimum r such that [l, r] contains *any* triplet.
    // Let `last_valid_r[i]` be the maximum `r_end` (1-based) of a triplet `(x, x+k, x+2k)`
    // such that `x+1 <= i`.
    // This is equivalent to finding the maximum `x+2k+1` for all `x+1 <= i`.
    // Let `max_end_idx[i]` be the maximum `x+2k+1` for any triplet `(x, x+k, x+2k)`
    // such that `x+1 <= i`.
    // `max_end_idx[i] = max(max_end_idx[i-1], min_r_for_l[i])`.
    // Note: `min_r_for_l[i]` here is actually the `r_end` of a triplet starting at `i`.
    // So, `max_end_idx[i]` will store the maximum `r_end` of any triplet whose `x_start` is `<= i`.

    std::vector<int> max_r_end_covered_by_prefix(n + 1, 0); // max_r_end_covered_by_prefix[i] = max(x+2k+1) for all x+1 <= i
                                                            // Initialize with 0, as 1-based indices start from 1.

    for (int i = 1; i <= n; ++i) {
        max_r_end_covered_by_prefix[i] = std::max(max_r_end_covered_by_prefix[i-1], min_r_for_l[i]);
    }

    long long good_pairs_count = 0;
    for (int l = 1; l <= n; ++l) {
        int current_max_r_end = max_r_end_covered_by_prefix[l];
        if (current_max_r_end != 0 && current_max_r_end <= n) { // If there's at least one triplet starting at or before l
                                                                 // and its end is within string bounds.
            // For this 'l', any 'r' from 'current_max_r_end' to 'n' will form a good pair (l, r).
            // The number of such 'r' values is (n - current_max_r_end + 1).
            good_pairs_count += (n - current_max_r_end + 1);
        }
    }

    std::cout << good_pairs_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] = N, then min(p[i], p[j]) = p[j] for all j!=i.
        // So max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = N-1.
        // If p[i] < N, then there is some p[k] = N.
        // Then min(p[i], p[k]) = p[i].
        // So max_{j!=i} min(p[i], p[j]) will be at least p[i].
        // In fact, it will be exactly p[i] because for any p[j] > p[i], min(p[i], p[j]) = p[i].
        // And for any p[j] < p[i], min(p[i], p[j]) = p[j] < p[i].
        // So the maximum value in row i (excluding a[i][i]) is p[i] if p[i] < N.
        // If p[i] = N, the maximum value is N-1.
        // To distinguish these two cases, we can check if max_val_in_row is N-1.
        // If it is N-1, then p[i] must be N. Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1: Try all possible single cuts
    // A single cut divides s into s1 and s2.
    // We can form s1+s2 (which is s) or s2+s1.
    // We need s2+s1 to be a palindrome and s2+s1 != s.
    for (int i = 1; i < n; ++i) { // i is the length of s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2:
    // If k=1 didn't work, we check if k=2 is always possible,
    // unless all characters are the same.
    //
    // If all characters in s are the same (e.g., "qqqq"),
    // then any reordering of substrings will result in the same string,
    // because all substrings will consist of the same character.
    // For example, "qqqq" -> "q|q|q|q" -> "qqqq".
    // In this case, it's impossible to form a new string.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        //
        // Consider s = "nolon". n=5.
        // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'
        //
        // If n is odd, and s is a palindrome, and not all chars are same:
        // s = A + c + reverse(A), where c is the middle char.
        // Example: "nolon" -> A="no", c='l', reverse(A)="on"
        // Cut: A | c | reverse(A)
        // Pieces: "no", "l", "on"
        // Reorder: "on" | "l" | "no" -> "onlno"
        // "onlno" is a palindrome and "onlno" != "nolon".
        // This uses 2 cuts.
        //
        // If n is even, and s is a palindrome, and not all chars are same:
        // s = A + reverse(A)
        // Example: "otto" -> A="ot", reverse(A)="to"
        // This case is covered by k=1.
        // Cut: A | reverse(A)
        // Pieces: "ot", "to"
        // Reorder: "to" | "ot" -> "toot"
        // "toot" is a palindrome and "toot" != "otto".
        //
        // The problem statement guarantees s is a palindrome.
        // If k=1 fails, it means for any split s=s1+s2, s2+s1 is either s or not a palindrome.
        //
        // Let's re-evaluate the k=2 logic.
        // If s is a palindrome and not all characters are the same,
        // we can always make 2 cuts to form a new palindrome.
        //
        // Consider the first half of the string: s.substr(0, n/2).
        // If this substring is itself a palindrome, and s is not all same chars,
        // then it implies s must be of the form "abccba" where "abc" is a palindrome.
        // E.g., "abccba" -> "a" + "bccb" + "a".
        // This is not quite right.
        //
        // The condition for k=1 to fail is that for any split s = s1 + s2,
        // either s2 + s1 == s OR s2 + s1 is not a palindrome.
        //
        // If s is a palindrome, and not all characters are the same,
        // then there must be at least two distinct characters.
        //
        // Consider the string s' = s.substr(0, n/2).
        // If s' is a palindrome, then s must be of the form "aaaa...a" or "abccba" where "abc" is a palindrome.
        // Example: "abacaba". n=7. n/2=3. s'="aba". "aba" is a palindrome.
        // If s' is a palindrome, and s is not all same chars, then s must be of the form XcX or XX.
        // If s = "abacaba", s'="aba".
        // If we cut "abacaba" into "a" | "bacab" | "a", and reorder to "a" | "bacab" | "a", it's still "abacaba".
        //
        // The example "nolon" -> 2 cuts.
        // "no|l|on" -> "on|l|no" = "onlno". This is a palindrome and != "nolon".
        // This is exactly the strategy: s = A + c + reverse(A). Cut into A, c, reverse(A). Reorder to reverse(A), c, A.
        // This works if A is not empty.
        //
        // What if n/2 is 0? (n=1) "a". All same chars. Impossible.
        // What if n/2 is 1? (n=2) "aa". All same chars. Impossible.
        // (n=3) "aba". A="a", c="b". reverse(A)="a".
        // Cut "a|b|a". Reorder "a|b|a". Still "aba".
        // This strategy doesn't work for "aba".
        //
        // Let's re-examine the condition for k=2.
        // If s is a palindrome, and not all characters are the same.
        // If n is odd, and s.substr(0, n/2) is a palindrome, then s must be of the form XcX where X is a palindrome.
        // Example: "abacaba". s'="aba". "aba" is a palindrome.
        // In this case, any reordering of pieces will result in the same string.
        // "a|b|a|c|a|b|a" -> "abacaba"
        // "ab|acab|a" -> "aabacab" (not palindrome)
        //
        // The crucial observation is that if s is a palindrome, and not all characters are the same,
        // then we can always achieve k=2 unless the string is of the form where its first half is also a palindrome.
        //
        // Consider the first half of the string: `s_half = s.substr(0, n/2)`.
        // If `s_half` is a palindrome, then `s` looks like `P + (middle_char_if_odd) + P_reversed`.
        // Since `s` is already a palindrome, `P_reversed` is just `P`.
        // So `s` looks like `P + (middle_char_if_odd) + P`.
        // Example: "abacaba". `s_half` = "aba". `s` = "aba" + "c" + "aba".
        // Example: "racecar". `s_half` = "rac". Not a palindrome.
        // Example: "madam". `s_half` = "ma". Not a palindrome.
        //
        // If `s_half` is a palindrome, and `s` is not all same characters,
        // then `s` must be of the form `XcX` (if n is odd) or `XX` (if n is even), where `X` is a palindrome.
        // Example: "abacaba". `X`="aba", `c`="c".
        // Example: "level". `X`="le", `c`="v". `s_half`="le". Not a palindrome.
        // Example: "noon". `X`="no". `s_half`="no". Not a palindrome.
        //
        // The only case where k=2 is impossible (given k=1 failed and not all chars are same)
        // is when the string is of the form `XcX` or `XX` where `X` is a palindrome.
        // In such a case, any permutation of cuts will result in the same string.
        // Example: "abacaba". Cut "a|b|a|c|a|b|a". Any reordering is "abacaba".
        //
        // So, the condition for "Impossible" is:
        // 1. All characters are the same (e.g., "qqqq").
        // 2. OR, the string is a palindrome, and its first half (s.substr(0, n/2)) is also a palindrome.
        //    And k=1 failed.
        //
        // Let's check the example "nolon". n=5. s_half = "no". Not a palindrome.
        // So it should be 2. Correct.
        //
        // Let's check "kinnikkinnik". n=12. s_half = "kinnik". Not a palindrome.
        // So it should be 1 or 2. Example says 1.
        // For "kinnikkinnik", cut at 6: s1="kinnik", s2="kinnik".
        // s2+s1 = "kinnikkinnik". This is s. So this cut doesn't work.
        // Cut at 3: s1="kin", s2="nikkinnik".
        // s2+s1 = "nikkinnikkin". Is this a palindrome?
        // "nikkinnikkin" reversed is "nikkinnikkin". Yes.
        // Is it != s? Yes.
        // So k=1 works for "kinnikkinnik".
        //
        // The logic seems to be:
        // 1. Try k=1. If successful, print 1.
        // 2. If k=1 fails:
        //    a. If all characters in s are the same, print "Impossible".
        //    b. Otherwise (not all characters are the same), print 2.
        //
        // This covers all cases.
        // Why is it always 2 if k=1 fails and not all chars are same?
        // If s is a palindrome and not all chars are the same,
        // then s must contain at least two distinct characters.
        //
        // Consider s = "abacaba". n=7.
        // s_half = "aba". This is a palindrome.
        // All chars are not same.
        // k=1 check:
        // i=1: s1="a", s2="bacaba". s2+s1="bacabaa". Not palindrome.
        // i=2: s1="ab", s2="acaba". s2+s1="acabaab". Not palindrome.
        // i=3: s1="aba", s2="caba". s2+s1="cabaaba". Not palindrome.
        //
        // So for "abacaba", k=1 fails.
        // Not all chars are same.
        // According to the logic, it should be 2.
        // But "abacaba" is like "qqqq" in structure (XcX where X is palindrome).
        // Any reordering of pieces will result in "abacaba".
        //
        // The condition for "Impossible" is actually:
        // If all characters in s are the same, OR
        // If s is a palindrome, and its first half (s.substr(0, n/2)) is also a palindrome.
        //
        // Let's test this refined "Impossible" condition.
        // "qqqq": all_same_chars = true. Impossible. Correct.
        // "abacaba": all_same_chars = false.
        // s_half = "aba". is_palindrome("aba") is true.
        // So "abacaba" should be Impossible.
