// Function to check if all tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        // If all target tracks are covered, return true
        if (p_idx == m) {
            return true;
        }

        // Current head position
        long long current_h = h[h_idx];

        // If the current head cannot reach the first uncovered target track p[p_idx]
        // within time t, then this head cannot cover it.
        // We need to find a head that can cover p[p_idx].
        // If current_h + t < p[p_idx], this head is too far left.
        // We need to move to the next head.
        if (current_h + t < p[p_idx]) {
            continue;
        }

        // This head can potentially cover p[p_idx].
        // Determine the leftmost track this head can cover.
        long long left_reach = current_h - t;

        // Determine the rightmost track this head can cover.
        long long right_reach = current_h + t;

        // Find the first target track that this head can cover.
        // This is p[p_idx] if p[p_idx] >= left_reach.
        // If p[p_idx] < left_reach, it means p[p_idx] is too far left for this head.
        // This should not happen if the previous check (current_h + t < p[p_idx]) passed,
        // because p[p_idx] <= current_h + t.
        // If p[p_idx] < current_h - t, then current_h - t is to the right of p[p_idx].
        // This means current_h is too far right to cover p[p_idx] if it moves left by t.
        // This implies current_h - p[p_idx] > t.
        // This is equivalent to p[p_idx] < current_h - t.
        // In this case, this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        if (p[p_idx] < left_reach) {
            continue;
        }

        // This head can cover p[p_idx].
        // Now, find how many subsequent target tracks this head can cover.
        // The head can cover a range [L, R].
        // If it covers tracks from p_start to p_end, then it must be able to reach
        // both p_start and p_end.
        // The time taken would be max(p_end - current_h, current_h - p_start).
        // This is not quite right. The head can move to any point x in [h-t, h+t].
        // If it covers a range [P_min, P_max], then it needs to be able to reach both.
        // The minimum time to cover [P_min, P_max] starting from h is:
        // If h is within [P_min, P_max], time = max(P_max - h, h - P_min).
        // If h < P_min, time = P_max - h.
        // If h > P_max, time = h - P_min.
        // All these can be summarized as:
        // The head needs to be able to reach P_min and P_max.
        // This means P_min >= current_h - t and P_max <= current_h + t.
        // Also, the total span P_max - P_min must be covered.
        // If current_h is outside [P_min, P_max], say current_h < P_min,
        // then the head must move right to cover P_min and P_max.
        // The time taken is P_max - current_h. This must be <= t.
        // If current_h > P_max, then the head must move left to cover P_min and P_max.
        // The time taken is current_h - P_min. This must be <= t.
        // If current_h is inside [P_min, P_max], then the head can move to P_min or P_max
        // or somewhere in between. The time taken is max(P_max - current_h, current_h - P_min).
        // This must be <= t.

        // The key insight for this part is that if a head covers a range of target tracks [p_start, p_end],
        // it must be able to reach both p_start and p_end.
        // The time taken for this head is `max(p_end - current_h, current_h - p_start)` if `current_h` is between `p_start` and `p_end`.
        // If `current_h < p_start`, time is `p_end - current_h`.
        // If `current_h > p_end`, time is `current_h - p_start`.
        // All these conditions must be <= `t`.

        // We are trying to cover p[p_idx] using current_h.
        // We want to find the maximum p_end such that current_h can cover [p[p_idx], p_end] within time t.
        // Case 1: current_h is to the left of p[p_idx].
        // Then current_h must move right. The time taken is p_end - current_h.
        // So, p_end - current_h <= t  =>  p_end <= current_h + t.
        // Case 2: current_h is to the right of p_end.
        // Then current_h must move left. The time taken is current_h - p[p_idx].
        // This implies current_h - p[p_idx] <= t.
        // Case 3: current_h is between p[p_idx] and p_end.
        // Time taken is max(p_end - current_h, current_h - p[p_idx]).
        // So, p_end - current_h <= t AND current_h - p[p_idx] <= t.

        // Combining these:
        // The head can cover tracks up to `p_end` such that:
        // 1. `p_end <= current_h + t` (rightmost reach)
        // 2. `p_end - p[p_idx] <= 2 * t` (span of tracks covered, if head moves to center)
        // This is not quite right. The head can move to any point `x` in `[h-t, h+t]`.
        // From `x`, it can cover `[x - (t - |x-h|), x + (t - |x-h|)]`.
        // This is equivalent to saying it can cover any range `[P_min, P_max]` such that
        // `P_max - P_min <= 2*t` AND `P_min >= h - t` AND `P_max <= h + t`.
        // This is also not quite right. The condition is that there exists a final position `x` for the head
        // such that `|x - h| <= t`, and for all `p_k` in the set of tracks covered by this head, `|p_k - x| <= t - |x - h|`.
        // This simplifies to: for all `p_k` covered by this head, `|p_k - h| <= t` if `p_k` is between `h-t` and `h+t`.
        // No, this is wrong. The time is `max(|p_k - h|)` for all `p_k` covered.
        // The time is `max(max(P_i) - h_i, h_i - min(P_i))` if `h_i` is outside `[min(P_i), max(P_i)]`.
        // The time is `max(max(P_i) - h_i, h_i - min(P_i))` if `h_i` is inside `[min(P_i), max(P_i)]`.
        // This is simply `max(max(P_i) - h_i, h_i - min(P_i))` for any `h_i`.
        // So, we need `max(p_end - current_h, current_h - p[p_idx]) <= t`.

        // Let's find the maximum `p_end` such that `current_h` can cover `[p[p_idx], p_end]` within time `t`.
        // This means `p_end - current_h <= t` AND `current_h - p[p_idx] <= t` AND `p_end - p[p_idx] <= 2*t`.
        // The first two conditions are `p_end <= current_h + t` and `p[p_idx] >= current_h - t`.
        // The third condition `p_end - p[p_idx] <= 2*t` is always implied by the first two if `p_end >= p[p_idx]`.
        // `p_end - p[p_idx] <= (current_h + t) - (current_h - t) = 2t`.
        // So, we just need to find the largest `p_end` such that `p_end <= current_h + t` and `p[p_idx] >= current_h - t`.
        // The `p[p_idx] >= current_h - t` condition was already checked (p[p_idx] < left_reach).
        // So, we need to find the largest `p_end` such that `p_end <= current_h + t`.
        // This is the simple greedy approach: cover as many tracks to the right as possible.

        // The actual condition for a head at `h` to cover a range `[P_min, P_max]` in time `t` is:
        // `P_max - h <= t` (if `h` is to the left of `P_min`)
        // `h - P_min <= t` (if `h` is to the right of `P_max`)
        // `max(P_max - h, h - P_min) <= t` (if `h` is within `[P_min, P_max]`)
        // This can be simplified to:
        // `P_max <= h + t` AND `P_min >= h - t` AND `P_max - P_min <= 2*t`.
        // The last condition `P_max - P_min <= 2*t` is crucial.
        // It means the span of tracks covered cannot exceed `2*t`.

        // So, for the current head `current_h` and starting target track `p[p_idx]`:
        // We need to find the maximum `p_end` such that:
        // 1. `p_end >= p[p_idx]` (it's a range)
        // 2. `p_end <= current_h + t` (rightmost point reachable by head)
        // 3. `p[p_idx] >= current_h - t` (leftmost point reachable by head) - this was already checked
        // 4. `p_end - p[p_idx] <= 2 * t` (span constraint)

        // Combining 2 and 4:
        // `p_end <= current_h + t`
        // `p_end <= p[p_idx] + 2 * t`
        // So, `p_end` can be at most `min(current_h + t, p[p_idx] + 2 * t)`.

        long long max_p_end_for_this_head = std::min(current_h + t, p[p_idx] + 2 * t);

        // Advance p_idx as long as p[p_idx] is within the range this head can cover.
        while (p_idx < m && p[p_idx] <= max_p_end_for_this_head) {
            p_idx++;
        }
    }
    return p_idx == m; // True if all target tracks are covered
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time 't'
    long long low = 0;
    // The maximum possible time could be the distance between the furthest target track
    // and the furthest head, or the span of all target tracks.
    // A safe upper bound: max(p_m-1 - h_0, h_n-1 - p_0) or p_m-1 - p_0.
    // A very loose upper bound: 2 * 10^10 (max coordinate value).
    long long high = 20000000000LL; // Max possible coordinate is 10^10, so max diff is 10^10.
                                    // If one head needs to cover a range of 10^10, it takes 10^10 time.
                                    // If a head is at 1 and needs to cover 10^10, it takes 10^10 time.
                                    // If a head is at 10^10 and needs to cover 1, it takes 10^10 time.
                                    // So 10^10 is a reasonable upper bound. Let's use 2*10^10 for safety.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

