#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // with the same fingerprint.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reverse of p. So p'_i = p_{n-i+1}.
    // The adjacent sums for p' are:
    // p'_1+p'_2 = p_n+p_{n-1}
    // p'_2+p'_3 = p_{n-1}+p_{n-2}
    // ...
    // p'_{n-1}+p'_n = p_2+p_1
    // These are exactly the same set of sums as for p, just in reverse order.
    // Since the fingerprint involves sorting these sums, the sorted list will be identical.
    // The only case where p' might be equal to p is if p is a palindrome,
    // but a permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2)
    // or n=0 (not allowed). For n>=2, p_1 != p_n (unless n=1), so p cannot be equal to its reverse.
    // For example, if p = [1,2,3], p' = [3,2,1].
    // If p = [1,2,3,4], p' = [4,3,2,1].
    // If p = [2,1,6,5,4,3], p' = [3,4,5,6,1,2].
    // These are always different.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

