int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach: use as many 5s as possible, then 2s, then 1s.
        // This works because 5 > 2*2 and 2 > 1*1.
        // For example, using three 1s (3 presses) is worse than one 2 and one 1 (2 presses) for a diff of 3.
        // Using five 1s (5 presses) is worse than one 5 (1 press) for a diff of 5.
        // Using two 2s (2 presses) is worse than one 5 (1 press) for a diff of 4.
        // This greedy strategy is optimal for denominations {1, 2, 5}.

        presses += diff / 5;
        diff %= 5;

        if (diff == 4) {
            // 4 can be covered by one 5 and one 1 (2 presses)
            // or two 2s (2 presses).
            // The greedy approach would have 0 fives, then two 2s.
            // If diff was 4, after 5s, it remains 4.
            // Then 4 / 2 = 2 presses. Total 2.
            // If we use one 5 and one 1, it's also 2 presses.
            // So, 4 is covered by 2 presses.
            presses += 2;
        } else if (diff == 3) {
            // 3 can be covered by one 5 and two 1s (3 presses)
            // or one 2 and one 1 (2 presses).
            // The greedy approach would have 0 fives, then one 2, then one 1.
            // If diff was 3, after 5s, it remains 3.
            // Then 3 / 2 = 1 press (for 2), diff becomes 1.
            // Then 1 / 1 = 1 press (for 1). Total 1+1=2.
            // So, 3 is covered by 2 presses.
            presses += 2;
        } else if (diff == 2) {
            // 2 is covered by one 2 (1 press).
            // The greedy approach would have 0 fives, then one 2.
            // If diff was 2, after 5s, it remains 2.
            // Then 2 / 2 = 1 press. Total 1.
            presses += 1;
        } else if (diff == 1) {
            // 1 is covered by one 1 (1 press).
            // The greedy approach would have 0 fives, then 0 twos, then one 1.
            // If diff was 1, after 5s, it remains 1.
            // Then 1 / 2 = 0 presses. diff remains 1.
            // Then 1 / 1 = 1 press. Total 1.
            presses += 1;
        }
        // If diff is 0, no additional presses needed.

        std::cout << presses << "\n";
    }
    return 0;
}

