int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Start with initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            int pile_index = i; // 0-indexed
            int pile_number = i + 1; // 1-indexed
            int haybales_in_pile = a[i];

            // Cost to move one haybale from pile_number to pile 1 is (pile_number - 1) days
            int cost_per_haybale = pile_number - 1;

            if (cost_per_haybale <= d) { // If we have enough days to move at least one haybale
                // Calculate how many haybales we can move from this pile
                // It's limited by haybales_in_pile and remaining days / cost_per_haybale
                int haybales_to_move = std::min(haybales_in_pile, d / cost_per_haybale);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            }
            // If d < cost_per_haybale, we can't move any haybales from this pile or further piles
            // because further piles will have even higher costs.
            if (d == 0) {
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

