#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this element.
        // The flags `has_one` and `has_minus_one` are updated based on original `a` values
        // for elements *before* index `i`.
        // This is crucial: the problem states `a_i` is added to `a_j`, implying the current value of `a_i`.
        // However, the values `a_k` for `k < i` are effectively "fixed" for operations on `a_i`
        // because `a_k` cannot be changed by `a_p` where `p > k`.
        // So, `has_one` and `has_minus_one` should reflect the presence of 1s and -1s
        // in the prefix `a[0...i-1]`.
        // The current logic correctly updates these flags based on `a[i-1]` for the next iteration.
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    std::cout << "YES\n";
}

