#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is 0 (which would mean all a[i][j] for j!=i were 0).
    // If so, it means p[i] must be n, as 0 is not a valid value for p[i].
    // This happens if n=2 and a[0][1]=0, a[1][0]=0. Then p[0]=0, p[1]=0.
    // But p must be a permutation of 1..n.
    // The problem statement guarantees a solution exists.
    // If max_val_in_row is 0, it means all a[i][j] for j!=i are 0.
    // This implies p[i] is the smallest element in the permutation (1).
    // However, if all a[i][j] are 0, it means min(p[i], p[j]) = 0 for all i!=j.
    // This is only possible if p[i] = 0 for some i, which is not allowed.
    // The only case where max_val_in_row could be 0 is if n=1, but n>=2.
    // So max_val_in_row will always be at least 1.
    // The only exception is if n=2 and a[0][1]=0, a[1][0]=0.
    // In this case, p[0]=0, p[1]=0. This is not a valid permutation.
    // The problem states "permutation of integers from 1 to n".
    // If max_val_in_row is 0, it means p[i] is 1.
    // If all a[i][j] for j!=i are 0, then p[i] must be 1.
    // But if p[i]=1, then for any j!=i, min(p[i], p[j]) = min(1, p[j]) = 1.
    // This contradicts a[i][j]=0.
    // So, max_val_in_row will always be at least 1.

    // The only case where p[i] might be n is if all a[i][j] for j!=i are less than n,
    // and p[i] is the largest value.
    // If for some i, all a[i][j] (j!=i) are equal to some value X,
    // then p[i] could be X or any value greater than X.
    // If p[i] is the largest value in the permutation (n), then for all j!=i,
    // a[i][j] = min(n, p[j]) = p[j].
    // So, if p[i] = n, then max(a[i][j] for j!=i) would be max(p[j] for j!=i),
    // which is n-1.
    // So, if p[i] is n, then max_val_in_row for that i would be n-1.
    // Our current assignment `p[i] = max_val_in_row` would set p[i] to n-1.
    // This means we need to find the element that should be n.
    // The element that should be n is the one whose `p[i]` (as calculated above)
    // is `n-1`, and all other `p[j]` (as calculated above) are less than `n-1`.
    // Or, more simply, the element that should be `n` is the one whose `p[i]`
    // (as calculated above) is `n-1`, and all other `p[j]` are distinct and smaller.

    // Let's find the maximum value in the calculated p array.
    int current_max_p = 0;
    for (int val : p) {
        if (val > current_max_p) {
            current_max_p = val;
        }
    }

    // If current_max_p is less than n, it means one of the elements
    // should actually be n. This happens when p[k] = n.
    // In this case, for all j != k, a[k][j] = min(n, p[j]) = p[j].
    // So, max(a[k][j] for j != k) would be max(p[j] for j != k), which is n-1.
    // Our current calculation would set p[k] to n-1.
    // All other p[j] (j!=k) would be correctly calculated as p[j].
    // So, if current_max_p is n-1, it means one of the elements that was assigned n-1
    // should actually be n. We need to find such an element and increment it.
    // Since there's only one 'n' in the permutation, there should be exactly one
    // element whose value needs to be adjusted from n-1 to n.
    // This is guaranteed because the input guarantees a solution.

    if (current_max_p < n) { // This implies current_max_p must be n-1
        // Find the first element in p that has the value current_max_p (which is n-1)
        // and increment it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == current_max_p) {
                p[i] = n;
                break; // Only one such element needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)

        // Iterate through the string to find consecutive 'L's
        // The positions are 1-indexed for the string characters.
        // Cell 0 is the start.
        // Cell n+1 is the end.
        // s[i] corresponds to cell i+1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R', it means we can jump from 'last_r_pos'
                // to this 'R' cell (i+1). The gap is (i+1) - last_r_pos.
                // We need to be able to jump over all 'L's between them.
                // The distance required is (i+1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current 'R' cell
            }
        }

        // After the loop, we need to consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's were found) to the target cell n+1.
        // The distance required is (n+1) - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

