int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use to generate k distinct differences

    // Generate k distinct differences: 1, 2, ..., k
    // We can achieve this by alternating between left and right pointers
    // For example, if k=4, we use numbers 1, 2, 3, 4, 5.
    // Sequence: 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This generates k distinct differences (from 1 to k) using k+1 numbers.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            std::cout << left++;
        } else { // Odd index, take from right
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k + 1) numbers, we need to ensure no new distinct differences are introduced.
    // The easiest way is to continue with increasing numbers, which will only produce a difference of 1.
    // Since 1 is already among the k distinct differences (unless k=0, which is not allowed), this is fine.
    // The last number printed was either `left-1` or `right+1`.
    // If it was `left-1`, then `left` is the next available number.
    // If it was `right+1`, then `right` is the next available number.
    // In both cases, `left` is the correct next number to print.
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

