        while (true) {
            // Calculate cells for the next nice staircase.
            // If current_stair_height is n, the next nice staircase has 2n+1 stairs.
            // The number of cells for a staircase with k stairs is k*(k+1)/2.
            // The number of cells for a nice staircase with 2n+1 stairs is (2n+1)*(2n+2)/2 = (2n+1)*(n+1).
            // This is equivalent to 2 * (cells for n stairs) + (n+1) * (n+1)
            // Or, more simply, the formula for cells in a nice staircase with k stairs is k*(k+1)/2.
            // The sequence of k for nice staircases is 1, 3, 7, 15, ... which is 2^p - 1.
            // Let's use the derived formula for cells in a nice staircase with 2^p - 1 stairs:
            // (2^p - 1) * (2^p) / 2 = (2^p - 1) * 2^(p-1).
            // Let's track the number of cells for the next nice staircase directly.
            // The first nice staircase (n=1) costs 1 cell.
            // The second nice staircase (n=3) costs 3*4/2 = 6 cells.
            // The third nice staircase (n=7) costs 7*8/2 = 28 cells.
            // The pattern for the number of cells for the k-th nice staircase (where k is 1-indexed)
            // is (2^k - 1) * 2^(k-1).
            // Let's use the iterative approach:
            // If current_stair_height is n, the next nice staircase has 2n+1 stairs.
            // The number of cells for a staircase with n stairs is n*(n+1)/2.
            // The number of cells for a nice staircase with (2*current_stair_height + 1) stairs is:
            // (2*current_stair_height + 1) * (2*current_stair_height + 2) / 2
            // = (2*current_stair_height + 1) * (current_stair_height + 1)

            long long cells_for_next_nice_staircase = (2 * current_stair_height + 1) * (current_stair_height + 1);

            if (x >= cells_for_next_nice_staircase) {
                x -= cells_for_next_nice_staircase;
                count++;
                current_stair_height = 2 * current_stair_height + 1; // Update n for the next iteration
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

