        for (int i = 1; i <= 10; ++i) {
            sum_of_first_ten_last_digits += (m * i) % 10;
        }

        // The number of full cycles of 10 multiples
        long long num_full_cycles = k / 10;

        // The sum from full cycles
        long long total_sum = num_full_cycles * sum_of_first_ten_last_digits;

        // The remaining multiples (k % 10)
        long long remaining_multiples = k % 10;

        // Add the sum of last digits for the remaining multiples
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
