void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if a_i can be made strictly increasing from left
    // i.e., a_i >= i-1 for i=0 to k-1
    // Find the maximum index 'left_reach' such that a[i] >= i for all i from 0 to left_reach
    int left_reach = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_reach = i;
        } else {
            break;
        }
    }

    // Check if a_i can be made strictly decreasing from right
    // i.e., a_i >= (n-1)-i for i=k to n-1
    // Find the minimum index 'right_reach' such that a[i] >= (n-1)-i for all i from right_reach to n-1
    int right_reach = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) {
            right_reach = i;
        } else {
            break;
        }
    }

    // If there is an overlap, it's possible.
    // The peak 'k' (0-indexed) must be such that k <= left_reach and k >= right_reach.
    // So we need left_reach >= right_reach.
    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

