int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // Or d = 0, which is handled above.
        if (d < 4) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // Using the quadratic formula: a = (d +/- sqrt(d^2 - 4d)) / 2
            // We want a and b to be non-negative.
            // Since d >= 4, d is positive. sqrt_discriminant is also non-negative.
            // Both (d + sqrt_discriminant) / 2 and (d - sqrt_discriminant) / 2 will be non-negative.
            // (d - sqrt_discriminant) / 2 >= 0 because d^2 >= d^2 - 4d => d >= sqrt(d^2 - 4d) for d >= 0.

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // The problem statement requires a + b = d and a * b = d.
            // The quadratic formula guarantees a + b = d and a * b = d.
            // We just need to ensure a and b are non-negative, which they are for d >= 4.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

