int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        long long total_toys = A + B + C + D;

        // Determine if Box 1 can be the special box
        // Box 1: x <= -1 (negative, magnitude >= 1)
        bool can_be_box1 = false;
        if (total_toys == 1) {
            if (A == 1) can_be_box1 = true;
        } else {
            // Final sign must be negative. This means an odd number of negative toys.
            // Final magnitude must be >= 1.
            //
            // Case 1: Final sign is negative.
            // This requires (A + B) to be odd.
            //
            // Case 2: Final magnitude is >= 1.
            // This requires at least one toy with magnitude >= 1 (from Box 1 or Box 4)
            // AND the number of toys with magnitude < 1 (from Box 2 or Box 3)
            // must not be so large that it forces the product magnitude below 1.
            //
            // Let's simplify the magnitude condition.
            // If there are any toys in Box 1 or Box 4 (A+D > 0),
            // it's possible to make the final magnitude >= 1.
            // If all toys are in Box 2 or Box 3 (A+D == 0),
            // then the final magnitude will always be < 1 (unless total_toys is 1).
            //
            // So, for Box 1:
            // 1. Final sign is negative: (A + B) % 2 == 1
            // 2. Final magnitude is >= 1: (A + D > 0)
            //
            // Exception: If A+D=0, then all toys are in B or C.
            // The product magnitude will always be < 1.
            // So, if A+D=0, Box 1 is impossible.
            //
            // Combining:
            // (A + B) % 2 == 1 AND (A + D > 0)
            //
            // What if A+D=0? Then A=0, D=0.
            // (0 + B) % 2 == 1 AND (0 > 0) -> false. Correct.
            //
            // What if A+D > 0?
            // If (A+B) is odd, then it's possible.
            //
            // Consider the edge case where A+D > 0 but all toys with magnitude >= 1 are multiplied by
            // many toys with magnitude < 1, resulting in a final magnitude < 1.
            // This is not how it works. We can choose the order of multiplication.
            // If A+D > 0, we can always ensure the final magnitude is >= 1.
            // For example, if we have one toy with magnitude >= 1 (say, from Box 4) and many from Box 3.
            // We can multiply all Box 3 toys together first, resulting in a toy in Box 3.
            // Then multiply this with the Box 4 toy, resulting in a toy in Box 4.
            //
            // The only way to guarantee magnitude < 1 is if all initial toys have magnitude < 1.
            // This means A=0 and D=0.
            //
            // So, for Box 1:
            // (A + B) % 2 == 1 AND (A + D > 0)
            can_be_box1 = ((A + B) % 2 == 1 && (A + D > 0));
        }

        // Determine if Box 2 can be the special box
        // Box 2: -1 < x < 0 (negative, magnitude < 1)
        bool can_be_box2 = false;
        if (total_toys == 1) {
            if (B == 1) can_be_box2 = true;
        } else {
            // Final sign must be negative: (A + B) % 2 == 1
            // Final magnitude must be < 1: (A + D == 0) OR (A + D > 0 AND B + C > 0)
            //
            // If A+D == 0, all toys are in B or C. Product magnitude will always be < 1.
            // If A+D > 0, and B+C > 0, we can pick one toy from A or D, and one from B or C.
            // Multiply them. If we pick a large and a small, we can get a small.
            // Example: 3 * 0.1 = 0.3.
            // We can always arrange multiplications to get magnitude < 1 if there's at least one
            // toy with magnitude < 1 (B+C > 0) and at least one toy with magnitude >= 1 (A+D > 0).
            //
            // So, for Box 2:
            // (A + B) % 2 == 1 AND ((A + D == 0) || (A + D > 0 && B + C > 0))
            can_be_box2 = ((A + B) % 2 == 1 && ((A + D == 0) || (A + D > 0 && B + C > 0)));
        }

        // Determine if Box 3 can be the special box
        // Box 3: 0 < x < 1 (positive, magnitude < 1)
        bool can_be_box3 = false;
        if (total_toys == 1) {
            if (C == 1) can_be_box3 = true;
        } else {
            // Final sign must be positive: (A + B) % 2 == 0
            // Final magnitude must be < 1: (A + D == 0) || (A + D > 0 && B + C > 0)
            //
            // So, for Box 3:
            // (A + B) % 2 == 0 AND ((A + D == 0) || (A + D > 0 && B + C > 0))
            can_be_box3 = ((A + B) % 2 == 0 && ((A + D == 0) || (A + D > 0 && B + C > 0)));
        }

        // Determine if Box 4 can be the special box
        // Box 4: x >= 1 (positive, magnitude >= 1)
        bool can_be_box4 = false;
        if (total_toys == 1) {
            if (D == 1) can_be_box4 = true;
        } else {
            // Final sign must be positive: (A + B) % 2 == 0
            // Final magnitude must be >= 1: (A + D > 0)
            //
            // So, for Box 4:
            // (A + B) % 2 == 0 AND (A + D > 0)
            can_be_box4 = ((A + B) % 2 == 0 && (A + D > 0));
        }

        print_bool(can_be_box1);
        std::cout << " ";
        print_bool(can_be_box2);
        std::cout << " ";
        print_bool(can_be_box3);
        std::cout << " ";
        print_bool(can_be_box4);
        std::cout << "\n";
    }

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // 0-indexed median position

    // Operations for elements smaller than s that must be <= s
    // These are elements a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s.
    // However, the problem states that elements to the left of median must be <= s.
    // If a[i] > s for i < median_idx, we must decrease it to s.
    // If a[i] < s for i < median_idx, it's already fine.
    // The median itself must be s.
    // Elements to the right of median must be >= s.

    // First, handle the median element itself.
    // It must become s.
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually set it to s for subsequent checks

    // Handle elements to the left of the median (indices 0 to median_idx - 1)
    // These elements must be <= s.
    // If any a[i] (i < median_idx) is greater than s, we must decrease it to s.
    // If a[i] is already <= s, no operations are needed for it to satisfy the condition.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Handle elements to the right of the median (indices median_idx + 1 to n - 1)
    // These elements must be >= s.
    // If any a[i] (i > median_idx) is smaller than s, we must increase it to s.
    // If a[i] is already >= s, no operations are needed for it to satisfy the condition.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

