    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int p_ptr = 0; // Pointer for elements to be placed (permuted array)
    int a_ptr = 0; // Pointer for original array positions

    while (p_ptr < n && a_ptr < n) {
        // If the current element from the permuted set (a[p_ptr])
        // is strictly greater than the current element from the original set (a[a_ptr]),
        // we can make a match.
        if (a[p_ptr] > a[a_ptr]) {
            count++;
            p_ptr++; // Move to the next element to be placed
            a_ptr++; // Move to the next original position
        } else {
            // If a[p_ptr] is not greater than a[a_ptr],
            // we cannot use a[p_ptr] for a[a_ptr] to satisfy the condition.
            // We must try a larger element for a[a_ptr], so we advance p_ptr.
            // a[a_ptr] might be matched with a[p_ptr+1], a[p_ptr+2], etc.
            p_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

