char wins_against(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Determine the most frequent move.
        // If counts are equal, 'R' < 'P' < 'S' lexicographically.
        // The problem statement implies any optimal answer is fine.
        // So, we can pick any of the most frequent ones.
        // Let's prioritize R, then P, then S if counts are equal.
        // This is implicitly handled by iterating through R, P, S.

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (empty string, though n >= 1), or if there's only one type of char,
        // the above logic correctly picks that char.
        // If counts are equal, e.g., R=1, P=1, S=1, it will pick 'S' because it's checked last.
        // This is fine as any of them would yield the same max_count.

        char player_winning_move = wins_against(most_frequent_bot_move);

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << player_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <algorithm>
