struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareElements);
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (b_elements[i].value) should be paired with
        // the (m-1-i)-th smallest A value (a_elements[m-1-i].value)
        // to maximize F(A', B) = A' / (B+1)
        // This means the i-th smallest B value should be paired with the i-th largest A value.
        // a_elements is sorted ascending, so a_elements[m-1-i] is the i-th largest.
        // b_elements[i].original_index gives the original position of the i-th smallest B value.
