    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // This 'a' needs to pass all 'b's to its right.
            // Each 'b' it passes results in an 'ab' -> 'bba' operation.
            // The number of steps for this 'a' is equal to the current b_count.
            total_steps = (total_steps + b_count) % mod;

            // After this 'a' passes all 'b's, it effectively moves to the right
            // and becomes a new 'b' for the 'a's further to its left.
            // The number of 'b's to its right effectively doubles for the next 'a'.
            // This is because each 'ab' -> 'bba' operation creates a new 'b'
            // to the right of the original 'a' (which is now to the right of the new 'b').
            // So, the 'b_count' effectively doubles for the next 'a' to its left.
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

