// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to a fixed length (18 for numbers up to 10^18-1)
    // The problem states a_i < 10^18, so max 18 digits.
    // A pattern of length 18 is sufficient to uniquely identify the parity sequence.
    // We reverse it later to match the right-to-left comparison logic.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Reverse to get MSB first
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string.
    // The key is the 18-character parity pattern string, value is its count.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern 's' with leading zeros to length 18.
            // This ensures it matches the format of keys in pattern_counts map.
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }

            // Look up the count for the padded pattern.
            // If the pattern is not in the map, map::operator[] would insert it with 0,
            // which is the correct count for a non-existent pattern.
            std::cout << pattern_counts[padded_s] << "\n";
        }
    }

    return 0;
}

