// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest divisor of p
            // and it satisfies the condition x % q != 0.
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, then p is not a valid x.
        // We need to find the largest divisor of p that is not divisible by q.
        // This means we need to remove some prime factors from p such that
        // the resulting number is no longer divisible by q.

        // Get prime factors of q.
        // We only care about the distinct prime factors of q.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        // For each distinct prime factor 'f' of q:
        // We want to find the largest divisor of p that is not divisible by q.
        // Consider removing 'f' from p until p is no longer divisible by q.
        // Specifically, we want to find the largest divisor of p, say x_f,
        // such that x_f is not divisible by q.
        // To do this, we can take p, and divide it by 'f' repeatedly until
        // the resulting number is no longer divisible by q.
        // The largest such x will be the maximum over all choices of 'f'.
        for (long long f : q_prime_factors) {
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            // current_p is now a divisor of p that is not divisible by q.
            // It's formed by removing all factors of 'f' from p until p is no longer divisible by q.
            // This current_p is a candidate for max_x.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

