            if (f2 == 0) { // Cannot move up, so target Y must be <= current Y
                max_y = std::min(max_y, y);
            }
            if (f3 == 0) { // Cannot move right, so target X must be <= current X
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down, so target Y must be >= current Y
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 using modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1 + MOD) % MOD; // Ensure (b-1) is non-negative for modulo
    if (b == 1) { // If b=1, then b-1=0, sum_r_term should be 0.
        sum_r_term = 0;
    }
    sum_r_term = (sum_r_term * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k_term = b * (a * (a+1) / 2) + a
    long long sum_k_inner_sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_inner_sum_k = (sum_k_inner_sum_k * inv2) % MOD;

    long long sum_k_term_part1 = (b % MOD * sum_k_inner_sum_k) % MOD;
    long long sum_k_term_part2 = a % MOD;

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    // Total sum = sum_r_term * sum_k_term
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c1 = s[k_actual]; // t[0] = s[k_actual]

        // Possible k values given c1
        const std::vector<int>& possible_k_indices = char_indices[c1 - 'a'];

        if (possible_k_indices.size() == 1) {
            // If only one k matches c1, Vasya wins immediately.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose p to maximize win probability for this c1.
        // Iterate over all possible p values (1 to L-1)
        double max_win_prob_for_c1 = 0.0;

        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k's from possible_k_indices lead to a win.
            // A win means (s[k], s[(k+p)%L]) is unique among all possible_k_indices.

            // Map to store counts of (s[k], s[(k+p)%L]) pairs
            std::map<std::pair<char, char>, int> pair_counts;

            for (int k_cand : possible_k_indices) {
                char c2 = s[(k_cand + p) % L]; // t[p] = s[(k_cand + p) % L]
                pair_counts[{c1, c2}]++;
            }

            int wins_for_this_p = 0;
            for (const auto& entry : pair_counts) {
                if (entry.second == 1) {
                    wins_for_this_p++;
                }
            }

            max_win_prob_for_c1 = std::max(max_win_prob_for_c1, (double)wins_for_this_p / possible_k_indices.size());
        }
        total_win_prob += max_win_prob_for_c1;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

