                    // Opponent (N=1, odd): takes 1. Opponent=2+1=3. N=0.
                    // Result: Chanek=5, Opponent=3.
                    // My trace for N=8 above was C=7, O=1. This is different.
                    // The trace for N=8, C=7, O=1:
                    // Chanek (N=8): takes N/2=4. Chanek=4. N=4.
                    // Opponent (N=4): takes 1. Opponent=1. N=3.
                    // Chanek (N=3): takes 1. Chanek=4+1=5. N=2.
                    // Opponent (N=2): takes 1. Opponent=1+1=2. N=1.
                    // Chanek (N=1): takes 1. Chanek=5+1=6. N=0.
                    // Result: Chanek=6, Opponent=2.
                    // Still not 7.

                    // What if N is a power of 2? N=2^k.
                    // If Chanek takes N/2, N becomes 2^(k-1).
                    // If Chanek takes 1, N becomes 2^k - 1.
                    // The opponent will also play optimally.

                    // The problem is that the "greedy" strategy (take N/2 if even, 1 if odd) is not always optimal.
                    // For N=4, it gives Chanek 3.
                    // For N=8, it gives Chanek 5.
                    // But if Chanek takes 1 for N=8:
                    // Chanek (N=8): takes 1. Chanek=1. N=7.
                    // Opponent (N=7): takes 1. Opponent=1. N=6.
                    // Chanek (N=6): takes N/2=3. Chanek=1+3=4. N=3.
                    // Opponent (N=3): takes 1. Opponent=1+1=2. N=2.
                    // Chanek (N=2): takes N/2=1. Chanek=4+1=5. N=1.
                    // Opponent (N=1): takes 1. Opponent=2+1=3. N=0.
                    // Result: Chanek=5, Opponent=3.
                    // This is the same as taking N/2 for N=8.

                    // What if N is a power of 2, say N=2^k?
                    // If Chanek takes N/2: Chanek gets N/2. Remaining N/2.
                    // If Chanek takes 1: Chanek gets 1. Remaining N-1.
                    // The opponent will try to maximize their share from the remaining coins.

                    // Let's consider the total coins taken by Chanek.
                    // The game ends when N=0.
                    // The total coins are N.
                    // Chanek wants to maximize his coins. Opponent wants to maximize his coins.
                    // This is equivalent to Chanek maximizing (Chanek_coins - Opponent_coins).
                    // And Opponent maximizing (Opponent_coins - Chanek_coins).

                    // Let's analyze the structure of N.
                    // If N is odd: Chanek must take 1. N becomes N-1 (even).
                    // If N is even:
                    //   If N is a power of 2 (N = 2^k, k >= 1):
                    //     Chanek has two choices:
                    //     1. Take 1. N becomes N-1 (odd).
                    //     2. Take N/2. N becomes N/2 (power of 2, 2^(k-1)).
                    //     If Chanek takes N/2, the game continues with N/2 coins, and it's Opponent's turn.
                    //     Opponent will also face a power of 2.
                    //     This leads to a sequence: C takes N/2, O takes N/4, C takes N/8, O takes N/16, ...
                    //     The last coin (1) goes to the player whose turn it is when N=1.
                    //     If k is odd (N=2, 8, 32, ...):
                    //       C takes N/2, N/8, ..., 2. O takes N/4, N/16, ..., 1.
                    //       Chanek gets (N/2 + N/8 + ... + 2) = (N-1)/3 + 1.
                    //       Opponent gets (N/4 + N/16 + ... + 1) = (N-1)/3.
                    //       Total = (2N-2)/3 + 1.
                    //     If k is even (N=4, 16, 64, ...):
                    //       C takes N/2, N/8, ..., 1. O takes N/4, N/16, ..., 2.
                    //       Chanek gets (N/2 + N/8 + ... + 1) = (N+1)/3.
                    //       Opponent gets (N/4 + N/16 + ... + 2) = (N-1)/3.
                    //       Total = (2N)/3.
                    //     This is the result if players always take N/2 when N is a power of 2.

                    //     Let's check N=4 (k=2, even): Chanek gets (4+1)/3 = 5/3 (not integer). This formula is wrong.
                    //     The sum of geometric series 1 + r + r^2 + ... + r^(m-1) = (1-r^m)/(1-r).
                    //     For N=2^k:
                    //

#include <iostream>
#include <algorithm> // For std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for simpler logic, as the problem is symmetric
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: Not enough moves to reach the target even with all diagonal moves
        // The minimum number of moves to reach (n, m) is m (if n <= m),
        // by making n diagonal moves and m-n straight moves.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the maximum possible diagonal moves if we only consider reaching (n,m)
        // We make n diagonal moves to reach (n,n). This uses n moves.
        // Then we make m-n straight moves to reach (n,m). This uses m-n moves.
        // Total moves so far: n + (m-n) = m.
        // Number of diagonal moves so far: n.
        long long current_diagonal_moves = n;
        long long remaining_moves = k - m;

        // Now we have 'remaining_moves' to spend. Each pair of moves (e.g., (1,0) then (-1,0))
        // can be used to increase diagonal moves or just waste moves.
        // We want to maximize diagonal moves.
        // A pair of moves like (1,1) then (-1,-1) uses 2 moves and results in (0,0) displacement,
        // adding 2 diagonal moves.
        // A pair of moves like (1,0) then (-1,0) uses 2 moves and results in (0,0) displacement,
        // adding 0 diagonal moves.
        // A pair of moves like (1,1) then (1,0) is not useful for maximizing diagonal moves.

        // The parity of (n+m) must be the same as the parity of k.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // (x_new + y_new) - (x_old + y_old) = (dx + dy).
        // If dx, dy are both non-zero (diagonal), dx+dy can be -2, 0, 2.
        // If one of dx, dy is zero (straight), dx+dy can be -1, 0, 1.
        // This means (x+y) changes by an even amount if it's a diagonal move,
        // and by an odd amount if it's a straight move.
        // So, (x_final + y_final) - (x_initial + y_initial) has the same parity as (number of straight moves).
        // (n+m) - 0 has the same parity as (k - current_diagonal_moves).
        // (n+m) % 2 == (k - current_diagonal_moves) % 2
        // (n+m) % 2 == (k - n) % 2
        // This is equivalent to (n+m+k-n) % 2 == 0, or (m+k) % 2 == 0.
        // Or, more simply, (n+m) and k must have the same parity.
        // If (n+m) % 2 != k % 2, it's impossible.
        // However, this is not entirely true. Consider (0,0) to (1,0) in 2 moves.
        // (1,0) -> (1,0) (0,0) -> (1,0) -> (0,0) -> (1,0)
        // (1,0) in 2 moves: (0,0) -> (1,0) -> (1,0) (1 straight, 1 no-op)
        // (0,0) -> (0,1) -> (1,0) (1 straight, 1 diagonal)
        // The parity condition is (n+m) % 2 == k % 2.
        // Let's check this:
        // Each move changes x by dx, y by dy.
        // (x_final - x_initial) = sum(dx_i)
        // (y_final - y_initial) = sum(dy_i)
        // (x_final - x_initial) + (y_final - y_initial) = sum(dx_i + dy_i)
        // (n+m) = sum(dx_i + dy_i)
        // Each (dx_i + dy_i) can be -2, -1, 0, 1, 2.
        // The parity of (dx_i + dy_i) is the same as the parity of (dx_i + dy_i)^2.
        // (dx_i + dy_i) % 2 == (dx_i % 2 + dy_i % 2) % 2.
        // A diagonal move has dx_i != 0 and dy_i != 0. So dx_i, dy_i are both odd.
        // (odd + odd) % 2 == 0.
        // A straight move has one of dx_i, dy_i as 0, the other as non-zero. So one is even, one is odd.
        // (even + odd) % 2 == 1.
        // So, (n+m) % 2 == (number of straight moves) % 2.
        // We know k = (number of diagonal moves) + (number of straight moves).
        // So (number of straight moves) = k - (number of diagonal moves).
        // (n+m) % 2 == (k - current_diagonal_moves) % 2.
        // This is equivalent to (n+m) % 2 == (k - n) % 2, since n is the initial diagonal moves.
        // (n+m) % 2 == (k - n) % 2
        // (n+m) % 2 == (k + n) % 2 (since -n and +n have same parity)
        // (m+k) % 2 == 0.
        // If (m+k) is odd, it's impossible.
        if ((m + k) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If (m+k) is even, it means (k-m) is also even.
        // We have 'remaining_moves' = k - m. This must be an even number.
        // Each pair of these remaining moves can be used to increase diagonal moves by 2.
        // For example, if we are at (x,y), we can move to (x+1, y+1) (diagonal) and then to (x,y) (diagonal).
        // This uses 2 moves and adds 2 to the diagonal count, while returning to the same point.
        // So, we can add 2 diagonal moves for each 2 remaining moves.
        current_diagonal_moves += remaining_moves; // remaining_moves is even, so this is valid.

        std::cout << current_diagonal_moves << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting point for the layout: a character with only one neighbor
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char with 1 neighbor, pick any char from used_in_s (it must have 0 or 2 neighbors)
    if (start_char == '\0' && !used_in_s.empty()) {
        start_char = *used_in_s.begin();
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // To keep track of the previous character in the path

        while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    if (layout_str.length() != used_in_s.size()) {
        // This means there's a cycle or disconnected components within used_in_s
        // that couldn't be fully traversed from a single start_char.
        // For example, if s="ab", then s="cd", these are two separate components.
        // Or if s="abc", then s="def", these are two separate components.
        // The current logic only builds one path.
        // If layout_str.length() != used_in_s.size(), it means there are multiple components
        // or a cycle that wasn't fully covered.
        // A cycle would mean a char has 2 neighbors, and we'd eventually return to start_char.
        // If all chars in used_in_s have 2 neighbors, and form a single cycle,
        // then layout_str.length() would be used_in_s.size().
        // The only way layout_str.length() != used_in_s.size() is if there are multiple components
        // or if a component is a cycle and we started from a char with 2 neighbors,
        // and the path didn't cover all used_in_s.
        // However, the problem implies a single linear arrangement.
        // If there are multiple components, they cannot be arranged linearly without breaking adjacency.
        // E.g., "ab" and "cd" means a-b and c-d. These cannot be adjacent on a single line.
        // So, if layout_str.length() != used_in_s.size(), it's impossible.
        // The only exception is if used_in_s is empty (s is empty, but |s| >= 1).
        // Or if used_in_s has only one character, layout_str will have length 1.
        // The logic for start_char and traversal correctly handles single paths/cycles.
        // If there are multiple components, this check will catch it.
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

