#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (count of 1s) - (count of 2s) for jars 1 to i
    // (0-indexed: a[0] to a[i-1])
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[i] = (count of 1s) - (count of 2s) for jars 2n-i+1 to 2n
    // (0-indexed: a[2n-i] to a[2n-1])
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain difference.
    // key: diff_L[k_L] (difference after removing k_L jars from left)
    // value: k_L (number of jars removed)
    std::map<int, int> left_diff_to_removed_count;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = diff_L[n] - diff_L[k_L]; // diff of remaining left jars
        if (left_diff_to_removed_count.find(current_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_diff] = k_L;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through possible removals from the right side
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_R = diff_R[n] - diff_R[k_R]; // diff of remaining right jars
        int target_diff_L = -current_diff_R; // We need total_diff = 0, so diff_L + diff_R = 0

        if (left_diff_to_removed_count.count(target_diff_L)) {
            int k_L = left_diff_to_removed_count[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track what happens if the input bit is 0, and what happens if it's 1.
    // `bit_state[j][0]` is the result for bit `j` if input bit `j` is 0.
    // `bit_state[j][1]` is the result for bit `j` if input bit `j` is 1.
    // Initially, if input bit is 0, output is 0. If input bit is 1, output is 1.
    std::vector<std::vector<int>> bit_state(10, std::vector<int>(2));
    for (int j = 0; j < 10; ++j) {
        bit_state[j][0] = 0; // If input bit j is 0, it remains 0
        bit_state[j][1] = 1; // If input bit j is 1, it remains 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int x_bit = (x >> j) & 1; // j-th bit of x

            if (op_char == '&') {
                bit_state[j][0] &= x_bit;
                bit_state[j][1] &= x_bit;
            } else if (op_char == '|') {
                bit_state[j][0] |= x_bit;
                bit_state[j][1] |= x_bit;
            } else { // op_char == '^'
                bit_state[j][0] ^= x_bit;
                bit_state[j][1] ^= x_bit;
            }
        }
    }

    // Now, `bit_state[j][0]` and `bit_state[j][1]` represent the final transformation for bit `j`.
    // We need to find constants for AND, OR, XOR operations that achieve this.

    // Let's define the target values for the constants.
    // `final_and_const`: If a bit `j` is 0 in this constant, it means `v_out[j]` must be 0 regardless of `v_in[j]`.
    // `final_or_const`: If a bit `j` is 1 in this constant, it means `v_out[j]` must be 1 regardless of `v_in[j]`.
    // `final_xor_const`: If a bit `j` is 1 in this constant, it means `v_out[j]` must be `1 - v_in[j]`.

    int final_and_const = 1023; // All bits initially 1
    int final_or_const = 0;     // All bits initially 0
    int final_xor_const = 0;    // All bits initially 0

    for (int j = 0; j < 10; ++j) {
        int res_0 = bit_state[j][0]; // Result if input bit j is 0
        int res_1 = bit_state[j][1]; // Result if input bit j is 1

        if (res_0 == 0 && res_1 == 0) {
            // Both 0 and 1 map to 0. This means the j-th bit of the output is always 0.
            // To achieve this, we must AND with 0 at bit j.
            final_and_const &= ~(1 << j); // Set j-th bit of final_and_const to 0
        } else if (res_0 == 1 && res_1 == 1) {
            // Both 0 and 1 map to 1. This means the j-th bit of the output is always 1.
            // To achieve this, we must OR with 1 at bit j.
            final_or_const |= (1 << j); // Set j-th bit of final_or_const to 1
        } else if (res_0 == 0 && res_1 == 1) {
            // 0 maps to 0, 1 maps to 1. This means the j-th bit of the output is the same as input.
            // No change needed for this bit by OR or XOR.
        } else { // res_0 == 1 && res_1 == 0
            // 0 maps to 1, 1 maps to 0. This means the j-th bit of the output is inverted.
            // To achieve this, we must XOR with 1 at bit j.
            final_xor_const |= (1 << j); // Set j-th bit of final_xor_const to 1
        }
    }

    std::vector<std::pair<char, int>> optimized_ops;
    if (final_and_const != 1023) { // If any bit was forced to 0
        optimized_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit was forced to 1
        optimized_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit was inverted
        optimized_ops.push_back({'^', final_xor_const});
    }

    std::cout << optimized_ops.size() << "\n";
    for (const auto& op : optimized_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
