// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n < 3) return false; // Should not happen based on constraints (n >= 3)

    std::vector<int> b = a;
    bool changed = false;

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        int median_val;
        if (sum >= 2) { // Two or three 1s
            median_val = 1;
        } else { // Zero or one 1 (two or three 0s)
            median_val = 0;
        }

        if (b[i] != median_val) {
            b[i] = median_val;
            changed = true;
        }
    }

    a = b;
    return changed;
}

int main() {
