    for (size_t i = 0; i < zero_one_zero_indices.size(); ++i) {
        int current_idx = zero_one_zero_indices[i];
        int prev_one_idx = (i == 0) ? first_one : zero_one_zero_indices[i - 1];

        // If current_idx is the first 010, prev_one_idx is the first 1 in the whole sequence.
        // If current_idx is not the first 010, prev_one_idx is the previous 010's index.
        // In both cases, the segment is from prev_one_idx to current_idx.
        // The distance is current_idx - prev_one_idx.
        // The number of steps for this segment is ceil((current_idx - prev_one_idx) / 2.0)
        // which is (current_idx - prev_one_idx + 1) / 2 for integer division.
        max_dist = std::max(max_dist, (current_idx - prev_one_idx + 1) / 2);
    }

    // Handle the segment from the last 010 to the last 1 in the whole sequence
    int last_zero_one_zero_idx = zero_one_zero_indices.back();
    max_dist = std::max(max_dist, (last_one - last_zero_one_zero_idx + 1) / 2);

    // Apply smoothing max_dist times
    for (int k = 0; k < max_dist; ++k) {
        apply_median_smoothing(a);
    }

    std::cout << max_dist << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Step 1: Initialize a_prime array with a very small value
    // a_prime[j] represents the maximum possible initial value for a[j]
    // based on type 2 operations.
    std::vector<long long> a_prime(n, LLONG_MAX);

    // Step 2: Process operations in reverse to determine upper bounds for a_prime
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (add d), then to find the initial value,
            // we need to subtract d from the current value.
            // So, if a_prime[j] was an upper bound for a[j] *after* this operation,
            // then a_prime[j] - d is an upper bound for a[j] *before* this operation.
            // We propagate this upper bound backwards.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (a_prime[j] != LLONG_MAX) { // Only propagate if an upper bound was set
                    a_prime[j] -= ops[i].val;
                }
            }
        } else { // type 2 operation (max query)
            // For a type 2 operation (l, r, m), we know that max(a[l...r]) = m.
            // This implies that for all j in [l, r], a[j] <= m.
            // So, we update a_prime[j] = min(a_prime[j], m) for j in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a_prime[j] = std::min(a_prime[j], ops[i].val);
            }
        }
    }

    // Step 3: Construct the candidate initial array 'a'
    // If a_prime[j] is still LLONG_MAX, it means no type 2 operation
    // constrained its initial value. We can set it to 0.
    // Otherwise, a_prime[j] is the tightest upper bound for initial_a[j].
    // To satisfy max(a[l...r]) = m, we need at least one element in the range
    // to be exactly m. To minimize changes and satisfy all conditions,
    // we set initial_a[j] = a_prime[j].
    // If a_prime[j] was LLONG_MAX, we set it to 0.
    std::vector<long long> initial_a(n);
    for (int j = 0; j < n; ++j) {
        if (a_prime[j] == LLONG_MAX) {
            initial_a[j] = 0;
        } else {
            initial_a[j] = a_prime[j];
        }
    }

    // Step 4: Verify the constructed initial array
    // Simulate all operations with the constructed initial_a
    // and check if all type 2 conditions are met.
    std::vector<long long> current_a = initial_a;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type 2 operation
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_cry = children[i].v;
        long long cumulative_d_cry = 0; // Sum of d_j from children who left due to p < 0

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply confidence reduction from child i's crying
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--; // v_i, v_i-1, v_i-2, ...
            }

            // Apply cumulative confidence reduction from previous children who left
            children[j].p -= cumulative_d_cry;

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_cry += children[j].d; // Add d_j to cumulative cry for subsequent children
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

