    long long low = 0, high = m - 1;
    long long ans = m - 1; // Max possible operations is m-1 (e.g., change 0 to m-1)

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

