    // and all other elements are in the other subsequence (e.g., 2).
    //
    // Pairs within subsequence 1: None (if n=1, but n>=2) or just elements[0] if n=1.
    // Pairs within subsequence 2: (elements[1], elements[2]), ..., (elements[n-2], elements[n-1])
    //   min_same = elements[1].value + elements[2].value
    //   max_same = elements[n-2].value + elements[n-1].value
    // Pairs across subsequences: (elements[0], elements[1]), ..., (elements[0], elements[n-1])
    //   min_diff = elements[0].value + elements[1].value + h
    //   max_diff = elements[0].value + elements[n-1].value + h
    //
    // Overall min_f = min(min_same, min_diff)
    // Overall max_f = max(max_same, max_diff)
    //
    // This strategy is good when h is large, making cross-subsequence pairs very large.
    // By isolating the smallest element, we try to make min_diff as small as possible
    // while keeping max_diff from being too large.
    //
    // Let's calculate min_f and max_f for this partition.
    //
    // Values of f:
    // 1. For (elements[i], elements[j]) where i,j >= 1: elements[i].value + elements[j].value
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-2].value + elements[n-1].value
    // 2. For (elements[0], elements[j]) where j >= 1: elements[0].value + elements[j].value + h
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h

    long long min_f_case2;
    long long max_f_case2;

    if (n == 2) {
        // Only one pair (elements[0], elements[1]). They are in different subsequences.
        // f = elements[0].value + elements[1].value + h
        min_f_case2 = elements[0].value + elements[1].value + h;
        max_f_case2 = elements[0].value + elements[1].value + h;
    } else { // n > 2
        long long min_same_sub2 = elements[1].value + elements[2].value;
        long long max_same_sub2 = elements[n - 2].value + elements[n - 1].value;
        long long min_diff_sub2 = elements[0].value + elements[1].value + h;
        long long max_diff_sub2 = elements[0].value + elements[n - 1].value + h;

        min_f_case2 = std::min(min_same_sub2, min_diff_sub2);
        max_f_case2 = std::max(max_same_sub2, max_diff_sub2);
    }
    long long goodness2 = max_f_case2 - min_f_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

