#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to check if all tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0; // Current head being considered
    int track_idx = 0; // Current target track being considered

    while (track_idx < m) {
        if (head_idx >= n) {
            // No more heads available, but there are still tracks to cover
            return false;
        }

        // Find the first head that can reach the current target track p[track_idx]
        // A head h[head_idx] can reach p[track_idx] if h[head_idx] - T <= p[track_idx] <= h[head_idx] + T
        // This simplifies to p[track_idx] - T <= h[head_idx] <= p[track_idx] + T
        // Since h is sorted, we can advance head_idx until h[head_idx] is within range or past it.

        // Skip heads that are too far to the left to reach p[track_idx]
        while (head_idx < n && h[head_idx] + T < p[track_idx]) {
            head_idx++;
        }

        if (head_idx >= n) {
            // No head can reach p[track_idx]
            return false;
        }

        // At this point, h[head_idx] is the first head that *might* be able to reach p[track_idx].
        // Specifically, h[head_idx] + T >= p[track_idx].
        // We need to ensure h[head_idx] - T <= p[track_idx].
        // If h[head_idx] - T > p[track_idx], then this head is too far to the right.
        // In this case, no subsequent head can reach p[track_idx] either, because h is sorted.
        // So, if h[head_idx] - T > p[track_idx], it means p[track_idx] cannot be covered.
        if (h[head_idx] - T > p[track_idx]) {
            return false;
        }

        // This head h[head_idx] can cover p[track_idx].
        // It can cover tracks in the range [h[head_idx] - T, h[head_idx] + T].
        // We greedily use this head to cover p[track_idx] and as many subsequent tracks as possible.
        long long current_head_coverage_end = h[head_idx] + T;
        while (track_idx < m && p[track_idx] <= current_head_coverage_end) {
            track_idx++;
        }

        // Move to the next head for the remaining tracks
        head_idx++;
    }

    return true; // All tracks covered
}

