    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // The maximum possible time could be the distance between the furthest target track
    // and the furthest head, or the distance between the closest target track and the closest head.
    // A safe upper bound is the maximum possible coordinate value (10^10)
    // or the difference between max_p and min_h, which can be up to 10^10.
    long long high = 20000000000LL; // Max possible coordinate is 10^10, so max diff is 10^10.
                                    // A head might need to move from 1 to 10^10, so 10^10 is a safe upper bound.
                                    // 2 * 10^10 is also safe.

    long long ans = high; // Initialize with a value that is definitely too high

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1; // Try for a smaller time
        } else {
            low = mid + 1; // Need more time
        }
    }

    std::cout << ans << std::endl;

    return 0;
