                //     `memo[k] = {x_step2, y_step2, true}`
                //     `visited[k] = 2`
                //     return `memo[k]`

                //   `val_2 = a[x_step2]`
                //   `x_step3 = x_step2 - val_2`
                //   `y_step3 = y_step2 + val_2`
                //   If `x_step3 <= 0` or `x_step3 > n`:
                //     `memo[k] = {x_step3, y_step3, true}`
                //     `visited[k] = 2`
                //     return `memo[k]`

                //   // Recursive call for the next state
                //   `next_result = solve(x_step3)`
                //   If `next_result.terminates == false` (infinite loop):
                //     `memo[k] = {0, -1, false}`
                //   Else:
                //     `memo[k] = {next_result.final_x, y_step3 + next_result.total_y_added, true}`

                //   `visited[k] = 2`
                //   return `memo[k]`

    std::vector<JumpResult> memo_table(n + 1);
    std::vector<int> visited_state(n + 1, 0); // 0: unvisited, 1: visiting, 2: visited

    // Function to solve for a given starting x
    auto solve = [&](int start_x, auto& self) -> JumpResult {
        if (start_x <= 0 || start_x > n) {
            return { (long long)start_x, 0, true }; // Terminated, 0 additional y
        }

        if (visited_state[start_x] == 1) {
            // Cycle detected in current path, means infinite loop
            return { 0, -1, false }; // Special values for infinite loop
        }
        if (visited_state[start_x] == 2) {
            // Already computed
            return memo_table[start_x];
        }

        visited_state[start_x] = 1; // Mark as visiting

        long long val1 = a[start_x];
        long long x_after_step2 = (long long)start_x + val1;
        long long y_after_step2 = val1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            memo_table[start_x] = { x_after_step2, y_after_step2, true };
            visited_state[start_x] = 2;
            return memo_table[start_x];
        }

        long long val2 = a[x_after_step2];
        long long x_after_step3 = x_after_step2 - val2;
        long long y_after_step3 = y_after_step2 + val2;

        if (x_after_step3 <= 0 || x_after_step3 > n) {
            memo_table[start_x] = { x_after_step3, y_after_step3, true };
            visited_state[start_x] = 2;
            return memo_table[start_x];
        }

        // Recursive call for the next state
        JumpResult next_res = self(x_after_step3, self);

        if (!next_res.terminates) {
            // Infinite loop detected further down the path
            memo_table[start_x] = { 0, -1, false };
        } else {
            memo_table[start_x] = { next_res.final_x, y_after_step3 + next_res.total_y_added, true };
        }

        visited_state[start_x] = 2; // Mark as visited
        return memo_table[start_x];
    };

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run
        // Reset memoization and visited states for a_1.
        // For a_2 to a_n, the values are fixed.
        // The `solve` function will compute results for all reachable states from 1.
        // Since `a[1]` changes for each `i`, we effectively need to re-run the `solve` for `x=1` each time.
        // However, the `memo_table` and `visited_state` are global to the `solve` function.
        // This means if `solve(k)` is called for `k != 1`, it will use previously computed values.
        // This is correct because `a[k]` for `k >= 2` is fixed.
        // Only `a[1]` changes. So we only need to clear `memo_table[1]` and `visited_state[1]`
        // and recompute `solve(1)`.
        // But `solve(1)` might call `solve(k)` for `k >= 2`.
        // If `solve(k)` for `k >= 2` was computed with a previous `a[1]` value, it's still valid.
        // The `a` array is passed by reference to `solve` implicitly.
        // So, `a[1]` is the only thing that changes.
        // We need to clear `memo_table` and `visited_state` for `x=1` only.
        // But `solve(1)` might lead to `x_step3` being `1` again, or some other `k`.
        // The `solve` function is designed to compute for a fixed `a` array.
        // Since `a[1]` changes, the entire `memo_table` and `visited_state` need to be cleared for each `i`.
        // This makes it O(N^2) in worst case.
        // N=2*10^5, N^2 = 4*10^10, too slow.

        // The problem is that `a[1]` changes.
        // The graph structure changes for each `i`.
        // The only node whose outgoing edge changes is node 1.
        // All other nodes `k` (from 2 to n) have fixed outgoing edges and costs.
        // This means `memo_table[k]` for `k >= 2` is always the same.
        // We only need to compute `memo_table[1]` for each `i`.
        // When `solve(1)` is called, it might call `solve(k)` for `k >= 2`.
        // These `solve(k)` calls should use the precomputed values.
        // So, we can precompute `memo_table[k]` for `k=2..n` once.
        // Then for each `i`, we compute `memo_table[1]` using the precomputed values for `k >= 2`.

        // Precompute for k = 2 to n
        // This part should be outside the loop for `i`.
        // Initialize memo_table and visited_state for k=2..n.
        // For k=2..n, a[k] is fixed.
        // We can run DFS for each k from 2 to n that hasn't been visited.
    }

    // Precompute memo_table for x from 2 to n
    // This part is executed only once.
    for (int k = 2; k <= n; ++k) {
        if (visited_state[k] == 0) { // If not visited, compute it
            solve(k, solve);
        }
    }

    // Now, for each i (1 to n-1), we set a[1] and compute solve(1).
    // We need to reset visited_state[1] and memo_table[1] for each iteration.
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        // Reset state for node 1 only
        visited_state[1] = 0;
        memo_table[1] = {}; // Clear previous result for node 1

        JumpResult res = solve(1, solve);

        if (!res.terminates) {
            std::cout << -1 << "\n";
        } else {
            std::cout << res.total_y_added << "\n";
        }
    }

    return 0;
}

