// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1 (2 parts)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_new = s2 + s1;

        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2 (3 parts)
    // The problem statement implies that if k=1 doesn't work, we try k=2.
    // For k=2, we need to make two cuts.
    // This means we split s into s_prefix, s_middle, s_suffix.
    // The only way to form a new palindrome with 2 cuts that is not s
    // is if s_prefix + s_suffix is a palindrome and s_middle is a palindrome,
    // and s_prefix != s_suffix.
